(68, 82, 'Restaurante Kenti', 'Restaurante Kenti, con menú especializado en parrillas además ofrece un menú variado con comida nacional e internacional.', 'service', NULL, '4', 'uploads/location-items/article_20251106_164528_4ada67f5d29d.webp'),
