(107, 100, 'Bombón Belén', 'Domo de Mus de chocolate amargo relleno de chocolate blanco, base de brownie, cubierto con chocolate.', 'dish', 30.00, '4', 'https://static.wixstatic.com/media/77bec3_5e9987bdffc0451ab404c95a49435e23~mv2.jpg/v1/fill/w_939,h_438,al_c,q_85,usm_0.66_1.00_0.01,enc_avif,quality_auto/77bec3_5e9987bdffc0451ab404c95a49435e23~mv2.jpg'),
(108, 100, 'Tarta Dulce del día', 'El sabor varía según disponibilidad', 'dish', 28.00, '4', 'https://static.wixstatic.com/media/77bec3_3b9ef87d3acb469b8b9871195f310da1~mv2.jpg/v1/fill/w_939,h_438,al_c,q_85,usm_0.66_1.00_0.01,enc_avif,quality_auto/77bec3_3b9ef87d3acb469b8b9871195f310da1~mv2.jpg'),
(109, 100, 'Cheesecake', 'Estilo New York con salsa casera de frutos rojos', 'dish', 32.00, '4', 'https://static.wixstatic.com/media/77bec3_5feb653b70e548c29eb8ddbade5bc2dc~mv2.jpg/v1/fill/w_1878,h_438,al_c,q_85,usm_0.66_1.00_0.01,enc_avif,quality_auto/77bec3_5feb653b70e548c29eb8ddbade5bc2dc~mv2.jpg'),
