INSERT INTO `articles` (`id`, `parent_id`, `id_category`, `title`, `subtitle`, `description`, `content`, `type`, `author`, `media_url`, `template_id`, `page_section`, `link`, `created_at`, `updated_at`) VALUES
(1, NULL, 2, 'En el corazón de los Andes', NULL, 'El altiplano ocupa cerca del 28% del territorio boliviano abarcando los departamentos de La Paz, Oruro y Potosí, forma un mosaico de pampas, pastizales y desiertos donde la cultura late con fuerza.Sus comunidades, herederas de antiguas civilizaciones, conservan costumbres, tejidos, lenguas y rituales que han sobrevivido al paso del tiempo. En sus fiestas, en sus cantos y en su relación con la Pachamama (madre tierra), se percibe una espiritualidad un diálogo entre lo humano y natural.Aquí, la naturaleza se contempla y se siente. Cada amanecer sobre el Lago Titicaca, cada reflejo en los infinitos espejos de Uyuni y Coipasa, cada ráfaga del viento helado cuenta la historia de una tierra sagrada que sigue viva.\r\nEl altiplano ocupa cerca del 28% del territorio boliviano abarcando los departamentos de \r\nLa Paz, Oruro y Potosí, forma un mosaico de pampas, pastizales y desiertos donde la cultura late con fuerza.\r\nSus comunidades, herederas de antiguas civilizaciones, conservan costumbres, tejidos, lenguas y rituales que han sobrevivido al paso del tiempo. En sus fiestas, en sus cantos y en su relación con la Pachamama (madre tierra), se percibe una espiritualidad un diálogo entre lo humano y natural.\r\nAquí, la naturaleza se contempla y se siente. Cada amanecer sobre el Lago Titicaca, cada reflejo en los infinitos espejos de Uyuni y Coipasa, cada ráfaga del viento helado cuenta la historia de una tierra sagrada que sigue viva.', NULL, 'custom', NULL, 'uploads/articles/article_20251104_024157_2f44602ffd07.webp', 1, 'home', NULL, '2025-10-14 18:09:38', '2025-11-04 07:41:59'),
(2, NULL, 2, 'Biodiversidad andina', NULL, NULL, 'En apariencia desolado, el altiplano esconde una biodiversidad extraordinaria que ha aprendido a florecer entre el frío y la aridez.\r\nLos camélidos andinos, la llama, la alpaca, el huanaco y la vicuña dominan el paisaje, en los cielos, el cóndor andino y el flamenco rosado sobrevuelan lagunas de colores demostrando que en los entornos más hostiles, la vida se abre paso.', 'custom', NULL, 'uploads/articles/article_20251104_024337_5e1e0283c574.webp', 1, 'home', NULL, '2025-10-14 18:11:05', '2025-12-01 14:03:37'),
(3, NULL, NULL, 'Refugio de vida', NULL, NULL, 'La zona subandina es uno de los grandes refugios de vida de Bolivia.\r\nEn sus bosques nubosos habitan aves como el tucán, el gallito de las rocas, el lorito andino y variedad de loros junto a mamíferos como el oso de anteojos y el puma y diversas especies de monos.\r\nEn cada rincón, la naturaleza parece reinventarse: una hoja, una flor o un vuelo bastan para entender por qué esta región es una de las más biodiversas de Sudamérica.', 'custom', NULL, 'uploads/articles/article_20251104_024434_66b51b02510e.webp', 1, 'home', NULL, '2025-10-14 18:11:53', '2025-11-04 07:44:36'),
(4, NULL, NULL, 'Climas de transición', NULL, NULL, 'El clima subandino varía con la altitud: en los valles predomina un ambiente templado que favorecen la agricultura y las caminatas al aire libre; mientras que, en los yungas, el aire es cálido, húmedo y fragante, con lluvias que alimentan los bosques y las cascadas.\r\nEstos contrastes hacen que se pueda practicar senderismo, ciclismo, observación de aves, turismo rural y exploración natural, donde cada kilómetro ofrece un cambio de paisaje y de energía.', 'custom', NULL, 'uploads/articles/article_20251104_024553_549a946cde93.webp', 1, 'home', NULL, '2025-10-14 18:12:34', '2025-11-04 07:45:58'),
(5, NULL, NULL, '¡Explora Bolivia sin prisas!', 'Descubre lo auténtico y déjate cautivar por la esencia de nuestro país', 'Descubre lo auténtico y déjate cautivar por la esencia de nuestro país', NULL, 'custom', 'RRSS', 'uploads/articles/article_20251103_122957_1102bc2ca782.webp', 22, 'home', '/que-hacer', '2025-10-11 07:21:44', '2025-11-03 17:29:57'),
(6, NULL, NULL, '¿Cuáles son tus intereses?', '¡Toda gran aventura comienza con un primer paso! ¡Escoge una categoría y déjate llevar por los colores, los sabores y los secretos que hacen única a Bolivia!', '¡Toda gran aventura comienza con un primer paso! ¡Escoge una categoría y déjate llevar por los colores, los sabores y los secretos que hacen única a Bolivia!', NULL, 'custom', NULL, 'uploads/articles/article_20251104_015440_5ae22b54e412.webp', 21, 'home', NULL, '2025-10-11 07:14:53', '2025-11-04 06:54:45'),
(7, NULL, NULL, 'Bolivia te espera', 'Un viaje al corazón de Sudamérica donde la naturaleza, aventura y cultura se entrelazan', 'Un viaje al corazón de Sudamérica donde la naturaleza, aventura y cultura se entrelazan', NULL, 'custom', NULL, 'https://apiconoce.unigcorp.com/uploads/articles/article_20251105_175720_bd368b8edea0.webp', 20, 'home', '/mapa', '2025-10-11 06:40:32', '2025-11-20 13:27:40'),
(8, NULL, NULL, 'Descubre el lugar donde nació Bolivia', 'La Casa de la Libertad en Sucre: cuna de la República', 'Más que un museo: es el escenario de la firma del Acta de Independencia en 1825.', 'En la Plaza 25 de Mayo de Sucre, la Casa de la Libertad guarda el alma de la nación. Sus salas —Virreinal, de la Independencia, de Guerrilleros— narran la transición de la colonia a la libertad. Pero su valor va más allá: alberga la Biblioteca Joaquín Ganteir, el Archivo Histórico y la Mapoteca, espacios abiertos a investigadores y curiosos. Visitarla es caminar por los mismos pasillos donde se forjó la historia de Bolivia.', 'custom', 'Equipo Conoce Bolivia', 'uploads/articles/article_20251104_024013_cf8f627ad446.webp', 1, 'home_inspiration', NULL, '2025-10-13 23:19:26', '2025-11-04 07:40:17'),
(9, NULL, NULL, 'El espejo del cielo: Salar de Uyuni', 'El desierto de sal más grande del mundo te espera', 'Un paisaje surrealista que desafía la imaginación y redefine la belleza natural.', 'En el corazón del altiplano boliviano, el Salar de Uyuni se transforma en un espejo infinito durante la temporada de lluvias. Con más de 10,000 km² de sal pura, es el remanente de un antiguo lago prehistórico. Aquí, el cielo y la tierra se funden en un solo plano, creando fotos imposibles y momentos inolvidables. No es solo un destino: es una experiencia sensorial que conecta con lo sublime.', 'custom', 'Equipo Conoce Bolivia', 'uploads/articles/article_20251104_132413_af80c21b6a74.webp', 4, 'home_inspiration', NULL, '2025-10-13 23:19:26', '2025-11-25 13:45:49'),
(10, NULL, NULL, 'Madidi: el pulmón más diverso del planeta', 'Donde la selva amazónica se encuentra con los Andes', 'El Parque Nacional Madidi alberga más biodiversidad que toda Europa.', 'En el norte de La Paz, el Parque Nacional Madidi es un santuario de vida. Con más de 6,000 especies de plantas, 1,200 de mariposas, 1,000 de aves y 200 de mamíferos —incluyendo jaguares, delfines rosados y monos—, es considerado uno de los lugares con mayor biodiversidad del mundo. Recorrerlo es adentrarse en un mundo intacto, guiado por comunidades indígenas que protegen este tesoro desde hace siglos.', 'custom', 'Equipo Conoce Bolivia', 'uploads/articles/article_20251104_014756_8cb65254723e.webp', 5, 'home_inspiration', NULL, '2025-10-13 23:19:26', '2025-11-04 06:48:01'),
(11, NULL, NULL, 'El Carnaval de Oruro: fe, danza y devoción', 'Patrimonio Inmaterial de la Humanidad por la UNESCO', 'Más de 20,000 bailarines en una procesión que fusiona lo andino y lo católico.', 'Cada año, Oruro se convierte en el epicentro de la identidad boliviana. La Entrada Folklórica del Carnaval reúne a fraternidades de todo el país en un despliegue de color, música y devoción. La Diablada, la Morenada, los Caporales… cada danza cuenta una historia de resistencia, sincretismo y fe. No es un espectáculo: es un ritual vivo que ha sobrevivido siglos y sigue latiendo con fuerza.', 'custom', 'Equipo Conoce Bolivia', 'https://cdn.bolivia.com/sdi/2022/02/26/carnaval-oruro-inicio-entrada-folklorica-1002348.jpg', 2, 'home_inspiration', NULL, '2025-10-13 23:19:26', '2025-10-13 23:19:26'),
(24, NULL, NULL, 'Hazz rapel en el Jardín de las Delicias', 'Descenso de 90 metros por una cascada en la selva', 'Una experiencia de adrenalina en el Parque Nacional Amboró, Santa Cruz.', 'En el Parque Nacional Amboró, a pocas horas de Santa Cruz, el Jardín de las Delicias ofrece un descenso en rapel de 90 metros por una cascada rodeada de selva. La actividad incluye caminatas por senderos, tirolesas y vistas panorámicas. Es ideal para quienes buscan emociones fuertes en un entorno natural protegido. Se requiere reserva previa y condición física básica.', 'custom', 'Equipo Conoce Bolivia', 'uploads/articles/article_20251104_131449_61fbae9a7875.webp', 22, 'what_to_do', '/buscar', '2025-10-14 18:46:41', '2025-11-11 18:00:08'),
(25, NULL, NULL, 'Explora los museos de Sucre', 'La ciudad blanca alberga más de 10 museos históricos y culturales', 'Desde la Casa de la Libertad hasta el Museo del Tesoro, cada museo cuenta una historia.', 'Sucre, la capital constitucional, es un museo al aire libre. La Casa de la Libertad narra el nacimiento de Bolivia. El Museo del Tesoro exhibe técnicas tradicionales de orfebrería. El Museo ASUR celebra la cultura textil de los pueblos indígenas. Y el Museo Universitario Colonial resguarda arte sacro y objetos de la época virreinal. Todos están en el centro histórico, a pocos pasos unos de otros. Ideal para un día de cultura y reflexión.', 'custom', 'Equipo Conoce Bolivia', 'https://images.mnstatic.com/2d/7d/2d7d27c08442a7388612b945f4b28e8e.jpg', 22, 'what_to_do', NULL, '2025-10-14 18:46:41', '2025-10-21 11:38:16'),
(26, NULL, NULL, '¡Bolivia te invita a vivir…!', NULL, NULL, 'Sumérgete en la riqueza de sus paisajes y sabores para experimentar lo que despierta todos tus sentidos y convierte cada viaje en un recuerdo inolvidable.', 'custom', 'Rocky', '/videos/conocebolivia1080X192.mp4', 20, 'what_to_do', NULL, '2025-10-14 18:50:37', '2025-11-11 15:41:05'),
(27, NULL, NULL, 'Comida y Bebida', NULL, NULL, 'Restaurantes, bares, comida típica y experiencias culinarias.', 'custom', NULL, 'uploads/articles/article_20251104_023849_a92cad10d182.webp', 22, 'home', '/comida', '2025-10-14 19:10:01', '2025-11-19 18:37:52'),
(29, NULL, 3, 'Sabores que permanecen', NULL, NULL, 'Hoy, la gastronomía del país se reinventa sin olvidar su esencia. Chefs, comunidades y productores reinterpretan recetas ancestrales, incorporando prácticas sostenibles y técnicas contemporáneas que valorizan el producto local. En los mercados, en los hogares o en restaurantes de alta cocina, Bolivia se saborea con orgullo y autenticidad.', 'custom', 'Samuel Choque', 'https://upload.wikimedia.org/wikipedia/commons/thumb/e/ec/Sopa_de_mani.jpg/1200px-Sopa_de_mani.jpg', 1, 'what_to_do', NULL, '2025-10-14 23:51:10', '2025-10-30 13:47:39'),
(31, NULL, NULL, 'Un legado que se saborea', NULL, NULL, 'El cacao y el café boliviano son una invitación a descubrir un país que se expresa en aromas, texturas y tradiciones. Desde una taza de café recién tostado en los Yungas hasta el chocolate artesanal de la Amazonía.', 'custom', NULL, 'https://abi.bo/images/2025/Marzo/14/CACAOO.jpg', 4, NULL, NULL, '2025-10-15 00:49:35', '2025-10-15 22:41:57'),
(32, NULL, 2, 'La esencia de un país vivo', NULL, NULL, 'La biodiversidad en Bolivia no se observa desde lejos, se vive de cerca. Es caminar por un sendero húmedo y escuchar el sonido del agua que cae entre hojas; es ver una vicuña en el horizonte altiplánico o un tucán que rompe el silencio del bosque.\r\nEs comprender que el país no solo guarda vida, sino que está hecho de ella.\r\n', 'custom', 'RRSS', 'https://img.europapress.es/fotoweb/fotonoticia_20121016100018_1200.jpg', 4, NULL, NULL, '2025-10-15 22:49:59', '2025-10-15 22:49:59'),
(33, NULL, 2, 'Diversidad en cada región', NULL, NULL, 'El país ocupa el quinto lugar en Sudamérica y el décimo en el mundo por la cantidad de especies de plantas que alberga, muchas de ellas endémicas.\r\nEn el altiplano, la vida se adapta al frío y al viento, donde llamas, vicuñas y zorros andinos conviven con flamencos y cóndores sobre paisajes de sal. Al descender hacia los valles interandinos y los Yungas, la vegetación se transforma con cada nivel de altura. Finalmente, los llanos orientales y la Amazonía alberga jaguares, delfines rosados, monos y miles de aves tropicales.\r\n', 'custom', 'RRSS', 'https://passagenspromo.com.br/blog/wp-content/uploads/2019/11/o-que-fazer-na-bolivia-740x415.jpg', 4, NULL, NULL, '2025-10-15 22:51:12', '2025-10-15 22:52:52'),
(34, NULL, NULL, 'El café, sabor de altura. ', NULL, NULL, 'Cultivado en los Yungas y Caranavi, el café boliviano alcanzó reconocimiento mundial por su perfil aromático y su producción sostenible. Con un sabor dulce y limpio y acidez equilibrada, se ha posicionado como un referente del café gourmet andino.\r\nPequeños productores, desde parcelas que oscilan entre 1 y 8 hectáreas, aplican técnicas artesanales en conjunto con modernas plantas de tostado, permitiendo mostrar el café al mundo. \r\nGracias a su calidad excepcional, Bolivia es hoy sede del Cup of Excellence, una competencia internacional que premia los mejores granos de café y visibiliza la labor de los caficultores locales.\r\n-\r\n', 'custom', NULL, 'https://eju.tv/wp-content/uploads/2022/10/img_633ad68d25f63-1000x666.jpg', 5, NULL, NULL, '2025-10-15 22:52:04', '2025-10-16 00:40:43'),
(35, NULL, 2, 'Áreas protegidas y sitios de vida', NULL, NULL, 'El territorio boliviano está resguardado por una red de Áreas Protegidas Nacionales y Sitios RAMSAR, donde se conservan ecosistemas únicos.\r\nCada parque, reserva o humedal es un refugio que resguarda especies, culturas, modos de vida y tradiciones que comprenden la naturaleza no como recurso, sino como hogar.\r\nNo solo se observa, sino que se aprende a escuchar la selva, a sentir el ambiente y a comprender el silencio como parte del paisaje.\r\n', 'custom', 'RRSS', 'https://wwflac.awsassets.panda.org/img/ramsar_8_661189.png', 4, NULL, NULL, '2025-10-15 22:54:58', '2025-10-15 22:55:30'),
(36, NULL, 2, 'País que late al ritmo de su biodiversidad', NULL, NULL, 'Bolivia es uno de los 15 países megadiversos del planeta, un título que refleja la inmensa variedad de flora y fauna que se esconde en sus paisajes. Desde las cumbres andinas cubiertas de hielo hasta las selvas amazónicas que respiran humedad y vida. \r\nCada paisaje parece guardar su propio latido: el silbido del viento en el altiplano, el canto de las aves en los Yungas, el rugido de los ríos amazónicos. Explorar Bolivia es descubrir un universo natural donde la vida se manifiesta con fuerza, color y movimiento.\r\n', 'custom', 'RRSS', 'https://madidiid.org/wp-content/uploads/2021/03/Heath-Rio-Botes-id_madidi_Omar-Torrico-WCS.jpg', 4, NULL, NULL, '2025-10-15 22:58:00', '2025-10-15 22:58:00'),
(37, NULL, NULL, 'Biodiversidad andina', NULL, NULL, 'En apariencia desolado, el altiplano esconde una biodiversidad extraordinaria que ha aprendido a florecer entre el frío y la aridez.\r\nLos camélidos andinos, la llama, la alpaca, el huanaco y la vicuña dominan el paisaje, en los cielos, el cóndor andino y el flamenco rosado sobrevuelan lagunas de colores demostrando que en los entornos más hostiles, la vida se abre paso.\r\n', 'custom', 'RRSS', 'https://media.istockphoto.com/id/1676366735/es/foto/llama-contra-el-volc%C3%A1n-parinacota-en-el-altiplano-boliviano.jpg?s=612x612&w=0&k=20&c=e7pxbriVjUP9EkZliytB3KzM6oVUpzmc-tBNPwWaqcg=', 4, NULL, NULL, '2025-10-15 23:01:42', '2025-12-01 14:02:01'),
(38, NULL, NULL, 'El cacao, aroma fino de la Amazonía', NULL, NULL, 'Desde la selva amazónica hasta los Yungas paceños, el cacao boliviano crece entre ríos y bosques, conservando su aroma floral y frutal, es considerado uno de los más finos del planeta.\r\nSu recolección y fermentación artesanal, realizada por familias que trabajan bajo prácticas sostenibles, permite conservar su esencia original. En ciudades como Sucre y La Paz, su transformación da vida a chocolates finos, bombonería y licores de cacao que reflejan innovación con identidad.\r\nHoy, el cacao boliviano ha conquistado mercados en Europa, Norteamérica y Asia, destacando por su calidad premium y certificaciones orgánicas.\r\n', 'custom', NULL, 'https://www.urgente.bo/sites/default/files/29bb0201-8310-425b-bd4a-b32e59d2419e_0.jpg', 4, NULL, NULL, '2025-10-15 23:02:43', '2025-10-16 00:40:34'),
(39, NULL, NULL, 'Clima de altura', NULL, NULL, 'El clima andino es una prueba de fuerza y adaptación. Entre los vientos fríos y las heladas, las personas del altiplano forjaron su carácter. \r\nEn el sur y el oriente, de la región andina, predominan los paisajes áridos y desérticos, modelados por la sequía y el sol. En contraste, el norte ofrece un mosaico de lagos, montañas y humedales que dan vida a la región.', 'custom', 'RRSS', 'uploads/articles/article_20251104_125348_7d22e086431b.webp', 4, 'home', NULL, '2025-10-15 23:12:18', '2025-11-04 17:53:50'),
(40, NULL, NULL, 'En el corazón de los Andes', NULL, NULL, 'El altiplano ocupa cerca del 28% del territorio boliviano abarcando los departamentos de La Paz, Oruro y Potosí; entre pampas, pastizales y desiertos donde la cultura late con fuerza.\r\nSus comunidades, aún conservan costumbres, tejidos, idiomas y tradiciones que han sobrevivido al paso del tiempo, demostrando la relación estrecha con la Pachamama (madre tierra). \r\nAquí, la naturaleza se contempla y se siente. Cada amanecer sobre el Lago Titicaca, cada reflejo en los infinitos espejos de Uyuni y Coipasa, cada ráfaga del viento helado cuenta la historia de una tierra sagrada que sigue viva.', 'custom', 'RRSS', 'uploads/articles/article_20251104_131713_072e876e1c27.webp', 4, 'home', NULL, '2025-10-15 23:15:04', '2025-11-04 18:17:14'),
(41, NULL, NULL, 'Refugio de vida', NULL, NULL, 'La zona subandina es uno de los grandes refugios de vida de Bolivia.\r\nEn sus bosques nubosos habitan aves como el tucán, el gallito de las rocas, el lorito andino y variedad de loros junto a mamíferos como el oso de anteojos y el puma y diversas especies de monos.\r\nEn cada rincón, la naturaleza parece reinventarse: una hoja, una flor o un vuelo bastan para entender por qué esta región es una de las más biodiversas de Sudamérica.', 'custom', 'RRSS', 'uploads/articles/article_20251104_123919_48a3aca7d785.webp', 4, 'home', NULL, '2025-10-15 23:24:27', '2025-11-04 17:39:25'),
(42, NULL, NULL, 'Climas de transición', NULL, NULL, 'El clima subandino varía con la altitud: en los valles predomina un ambiente templado que favorecen la agricultura y las caminatas al aire libre; mientras que, en los yungas, el aire es cálido, húmedo y fragante, con lluvias que alimentan los bosques y las cascadas.\r\nEstos contrastes hacen que se pueda practicar senderismo, ciclismo, observación de aves, turismo rural y exploración natural, donde cada kilómetro ofrece un cambio de paisaje y de energía.\r\n', 'custom', 'RRSS', 'https://upload.wikimedia.org/wikipedia/commons/thumb/9/98/Los_Yungas_La_Paz_-_Bolivia.jpg/1100px-Los_Yungas_La_Paz_-_Bolivia.jpg', 4, NULL, NULL, '2025-10-15 23:27:26', '2025-10-15 23:27:26'),
(43, NULL, NULL, 'El corazón fértil de Bolivia', NULL, NULL, 'Los valles y yungas subandinos cuentan con suelos fértiles, sus laderas cubiertas de vegetación y sus climas templados dan origen a una de las regiones más productivas del país. Aquí se cultiva la vid, el maíz, la fruta tropical, el café, y la hoja de coca, pilares de la economía y la cultura local.\r\nEn cada valle, el visitante puede conocer comunidades rurales, degustar vinos artesanales o participar de actividades de turismo comunitario, donde la tierra y el ser humano comparten el mismo ritmo.\r\n', 'custom', 'RRSS', 'https://www.eldiario.net/noticias/2017/2017_05/nt170504/f_2017-05-04_8.jpg', 4, NULL, NULL, '2025-10-15 23:29:23', '2025-10-15 23:29:23'),
(44, NULL, NULL, 'Donde los Andes se abren paso hacia la selva', NULL, NULL, 'Esta región, que abarca cerca del 17% del territorio nacional, se extiende por los departamentos de Cochabamba, Chuquisaca y Tarija, formando un corredor natural en donde los valles interandinos descienden hacia los yungas amazónicos, creando paisajes donde la frescura de los ríos se mezcla con el perfume de los bosques y el canto de las aves.', 'custom', 'RRSS', 'https://www.trazandoruta.com/wp-content/uploads/2019/05/jungle_tour_madidi.jpg', 4, NULL, NULL, '2025-10-15 23:47:19', '2025-10-15 23:48:40'),
(45, NULL, NULL, 'Vida Salvaje', NULL, NULL, 'En esta región habitan jaguares, delfines rosados y una gran variedad de aves tropicales. Sus bosques, ricos en plantas medicinales y especies endémicas, albergan parques como Madidi, Noel Kempff Mercado y Manuripi, verdaderos santuarios naturales donde el visitante puede vivir la experiencia de adentrarse en una selva que parece eterna.\r\nLa Amazonía y el oriente boliviano son mucho más que un destino: son un refugio de vida, un pulmón del planeta y un espejo de la diversidad que define al país.\r\n', 'custom', 'RRSS', 'https://antipode-bolivia.com/Que-Voir/amazonie-bolivienne-v1-1200-800.jpeg', 4, NULL, NULL, '2025-10-15 23:53:09', '2025-10-15 23:53:09'),
(46, NULL, NULL, 'El clima que da vida al oriente', NULL, NULL, 'El oriente y la Amazonía boliviana son regiones de clima cálido y húmedo, donde las lluvias marcan el pulso del paisaje.\r\nDurante la temporada húmeda, los ríos crecen y los bosques se tornan aún más verdes, ofreciendo un espectáculo natural en constante transformación. En los meses secos, la calma vuelve, los caminos se abren y las condiciones son ideales para la navegación fluvial y la observación de fauna.\r\nAquí, cada amanecer trae una nueva sinfonía de sonidos: aves, insectos y el rumor de los ríos que nunca duermen.\r\n', 'custom', 'RRSS', 'https://infoamazonia.org/wp-content/uploads/2016/04/scientists-to-explore-amazon-rainforests-link-with-climate-136405160548403901-160413001011.jpg', 4, NULL, NULL, '2025-10-15 23:55:57', '2025-10-16 00:00:15'),
(47, NULL, NULL, 'Ríos caudalosos ', NULL, NULL, 'Los llanos forman parte de las grandes cuencas del río Amazonas, una red hídrica que conecta al país con Sudamérica entera. El Mamoré y el Beni son arterias de agua que sostienen la vida y la comunicación en estas tierras bajas.\r\nA su alrededor se extienden selvas densas, llanuras fértiles y planicies inundables, escenarios que albergan comunidades ribereñas, haciendas ganaderas y reservas naturales.\r\n', 'custom', 'RRSS', 'https://embajadadebolivia.eu/beni/DCIM101MEDIADJI_0012.JPG', 4, NULL, NULL, '2025-10-15 23:58:35', '2025-10-16 00:00:18'),
(48, NULL, NULL, 'El esplendor del oriente y la Amazonía boliviana', NULL, NULL, 'Explorar la zona de los llanos bolivianos es adentrarse en la región más vasta y diversa del país: un territorio que representa el 59% de la superficie nacional, ocupa los departamentos de Beni y Pando en su totalidad, y partes de Santa Cruz, Cochabamba, La Paz, Chuquisaca y Tarija.\r\nAquí, la naturaleza se muestra sin límites: sabanas infinitas, selvas tropicales, ríos que serpentean entre la niebla y horizontes donde el cielo se funde con la tierra.\r\n', 'custom', 'RRSS', 'https://media.istockphoto.com/id/1314259446/es/foto/crep%C3%BAsculo-en-la-selva-amaz%C3%B3nica.jpg?s=612x612&w=0&k=20&c=xODbrLhMSnYmRepmGrU-ngoh2FS4tI_3hsqAhn8MspM=', 4, NULL, NULL, '2025-10-15 23:59:56', '2025-10-16 00:01:04'),
(49, NULL, 3, 'El sabor de una nación diversa', NULL, NULL, 'Desde los Andes hasta la Amazonía, desde los valles templados hasta el Chaco, cada región aporta su propio lenguaje de sabores, ingredientes y costumbres que hacen de Bolivia un territorio gastronómico irrepetible.', 'custom', 'RRSS', 'https://unifranz.edu.bo/wp-content/uploads/2024/08/PLATOS-TIPICOS2-BLOG.jpg', 4, 'what_to_do', NULL, '2025-10-16 00:09:56', '2025-10-30 13:46:45'),
(50, NULL, NULL, 'Mocochinchi, el sabor del durazno', NULL, NULL, 'El mocochinchi es una de las bebidas más queridas y representativas de Bolivia, un clásico que acompaña la vida. Elaborado a partir de duraznos deshidratados, que se hierven lentamente con canela, clavo de olor y azúcar hasta lograr un almíbar dorado y perfumado, su sabor dulce y refrescante guarda el espíritu hogareño del país.\r\nEl mocochinchi es una herencia familiar. En muchos hogares, su preparación marca los fines de semana o las festividades. En cada sorbo hay un recuerdo, el sabor de la infancia, la paciencia del hervor y el gesto cariñoso de quien lo prepara.\r\n', 'custom', 'RRSS', 'https://www.bolivianita.de/cdn/shop/products/mocochinchi_006.jpg?v=1752004715&width=1445', 4, NULL, NULL, '2025-10-16 00:26:50', '2025-10-17 18:19:29'),
(51, NULL, NULL, 'Tradición que evoluciona', NULL, NULL, 'En las comunidades del altiplano, la quinua sigue siendo cultivada con métodos ancestrales, se siembra y cosecha a mano, se trilla con cuidado y se limpia mediante técnicas tradicionales como el lavado en corrientes naturales de agua o el uso de cenizas para eliminar la saponina.\r\nEn contraste, modernas plantas en Oruro y Potosí incorporan procesos industriales de clasificación, desaponificado y envasado, cumpliendo estándares internacionales de inocuidad y calidad. \r\n', 'custom', NULL, 'https://www.aygun.com.bo/wp-content/uploads/2024/03/quinua_aygun.jpeg', 5, NULL, NULL, '2025-10-16 00:27:02', '2025-10-16 00:40:05'),
(52, NULL, NULL, 'El valor de un grano con historia', NULL, NULL, 'La Quinua Real se distingue por el tamaño de su grano, su textura ligera y su alto valor nutritivo, contiene todos los aminoácidos esenciales, proteínas de alta calidad, minerales y vitaminas. Por ello, el mundo la reconoce como un superalimento y para Bolivia sigue siendo un legado vivo que forma parte de su identidad cultural alimentaria.', 'custom', NULL, 'https://abi.bo/images/historico_1/quinua.jfif', 4, NULL, NULL, '2025-10-16 00:30:15', '2025-10-16 00:40:02'),
(53, NULL, NULL, 'Chicha, el sabor del maíz', NULL, NULL, 'Entre todas las bebidas tradicionales, la chicha ocupa un lugar especial. Esta bebida fermentada de maíz ha acompañado a las comunidades desde tiempos precolombinos. Su sabor y aroma varían según la región y la variedad del grano.\r\nEn los valles y altiplanos de Cochabamba, Chuquisaca, La Paz y Oruro, el maíz ha sido fermentado desde tiempos remotos. Antes se masticaba para liberar su almidón, y hoy los métodos se modernizan sin perder la esencia artesanal ni el sabor de la fermentación natural.\r\n', 'custom', 'RRSS', 'https://cdn.bolivia.com/gastronomia/2011/08/03/chicha-1604.gif', 4, NULL, NULL, '2025-10-16 00:30:16', '2025-10-16 00:30:16'),
(54, NULL, NULL, 'Sabores que cuentan historias', NULL, NULL, 'Las bebidas bolivianas son un reflejo de la riqueza natural y agrícola del país, un viaje sensorial que recorre desde las tierras tropicales hasta los valles y el altiplano. En cada sorbo se descubre una historia distinta: la dulzura de las frutas amazónicas, la frescura de los valles interandinos y la fuerza de las hierbas andinas.\r\nDegustarlas es conectarse con la tierra y su gente, con los mercados donde las frutas perfuman el aire. Estas bebidas naturales no solo acompañan la gastronomía, sino que invitan al viajero a descubrir los sabores que nacen del suelo boliviano.\r\n', 'custom', 'RRSS', 'https://cdn.bolivia.com/sdi/2018/08/22/5-bebidas-tipicas-bolivianas-que-debes-probar-665429.jpg', 4, NULL, NULL, '2025-10-16 00:32:07', '2025-10-16 00:32:07'),
(55, NULL, NULL, 'Charquekan', NULL, NULL, 'El charquekan, cuya preparación tiene como protagonista al charque, sigue fielmente los pasos que practicaban los pueblos originarios hace siglos.\r\nSu origen se asocia a las comunidades urus y se consolidó en Oruro, donde los mineros lo adoptaron como fuente de sustento y fortaleza durante las arduas jornadas de trabajo.\r\nHoy, el charque mantiene su lugar en la mesa boliviana como un símbolo de identidad regional. Su textura y sabor característico lo convierten en protagonista de platos típicos como el charquekan, acompañado de mote, huevo, papa y queso frito.\r\nHoy en día, es una tradición que aprovecha los recursos naturales sin desperdicio.\r\n', 'custom', 'RRSS', 'https://cdn.bolivia.com/sdi/2024/09/28/en-oruro-prepararan-el-charquekan-mas-largo-del-mundo-1256829.jpg', 4, NULL, NULL, '2025-10-16 00:34:27', '2025-10-16 00:34:27'),
(56, NULL, NULL, 'El legado de la carne deshidratada', NULL, NULL, 'La carne deshidratada es uno de los tesoros más antiguos de la gastronomía boliviana y un ejemplo de la sabiduría de los pueblos andinos. Nacida de la necesidad de conservar los alimentos frente al clima extremo del altiplano, esta técnica, que consiste en salar la carne de res o de llama y dejarla secar al sol, ha perdurado por siglos, manteniendo su esencia intacta.\r\nEl resultado es una carne firme, de color oscuro y sabor intenso, capaz de resistir el paso del tiempo sin perder su valor nutritivo. Rica en proteínas y con larga durabilidad, representa una de las formas más sostenibles e ingeniosas de preservación natural.\r\n', 'custom', 'RRSS', 'https://semaya.mx/wp-content/uploads/2020/11/27.jpg', 4, NULL, NULL, '2025-10-16 00:36:09', '2025-10-16 00:36:09'),
(57, NULL, NULL, 'Quinua, grano milenario de los Andes', NULL, NULL, 'En el altiplano boliviano, donde los vientos soplan sobre tierras salinas y los cielos se confunden con los salares de Uyuni y Coipasa, nace la Quinua Real, un tesoro milenario que solo puede cultivarse en esta tierra única del mundo.\r\nA más de 3.600 metros de altura, este grano sagrado ha alimentado a generaciones desde hace más de cinco mil años. Para las civilizaciones andinas, la quinua no era solo alimento, era símbolo de vida, abundancia. Su nombre original, jupha, evocaba el origen, lo esencial, lo eterno.\r\n', 'custom', NULL, 'https://gestion.pe/resizer/v2/X53FHHCR2FBJFFDQYNYRHMMZTE.jpg?auth=0a348674cb7919efaa647184a4a44393c2322d472ad236f51466f613aeafc5dd&width=1203&height=800&quality=75&smart=true\r\n', 5, NULL, NULL, '2025-10-16 00:36:47', '2025-10-16 00:39:17'),
(61, NULL, NULL, 'El ají en la cocina boliviana', NULL, NULL, 'Su versatilidad lo convierte en el corazón de innumerables recetas:\r\nLa llajua, salsa emblemática elaborada con locoto, tomate y hierba de quirquiña, presente en todos los rincones del país. Un pequeño tazón de ají acompaña la mesa de cada familia boliviana.\r\nAjí de fideo, guiso popular en Cochabamba y La Paz, donde el ají amarillo aporta su color intenso y sabor inconfundible.\r\nMondongo chuquisaqueño, plato preparado con carne de cerdo y salsa espesa de ají rojo molido, acompañado de mote y papa.\r\n', 'custom', 'RRSS', 'https://thebolivianfoodie.com/wp-content/uploads/2025/05/Llajua-bolivia-gastronomia-the-bolivian-foodie3.jpg', 4, NULL, NULL, '2025-10-16 00:39:45', '2025-10-16 00:39:45'),
(62, NULL, NULL, 'Ulupica, locoto y ají amarillo: el fuego de los Andes', NULL, NULL, 'La ulupica, diminuta y poderosa, considerada la “madre de los ajíes”.\nEl locoto, robusto y de picor firme, protagonista de la llajua boliviana.\nEl ají amarillo, suave y fragante, base de muchas salsas y guisos tradicionales.\nEsta trilogía de sabores ha trascendido las fronteras culinarias llegando a ser un producto innovador con potencial internacional. ', 'custom', 'RRSS', 'https://pbs.twimg.com/media/EhLEjzCWAAAH4Dt.jpg:large', 4, NULL, NULL, '2025-10-16 00:41:00', '2025-10-16 00:46:09'),
(63, NULL, NULL, 'El corazón picante de la gastronomía boliviana', NULL, NULL, 'El ají es uno de los tesoros de la gastronomía boliviana, el alma que da color, aroma y carácter a cada plato. Presente en preparaciones como el fricasé, el ají de lengua, saice tarijeño, ranga ranga o el mondongo chuquisaqueño, este ingrediente va más allá del picante: encierra matices dulces, notas ahumadas y un perfume inconfundible que refleja la diversidad y la fuerza de la tierra que lo cultiva.\r\nPara el viajero, el ají boliviano es una puerta de entrada a la cultura local. Se descubre en todo el país. Degustar un plato con ají en Bolivia no es solo saborear la comida, es probar el alma del país.\r\n', 'custom', 'RRSS', 'https://ruta1825.com.bo/images/ruta1825/gastronomia/2025/20250608-gastronomia-sabores-aji.jpg', 4, NULL, NULL, '2025-10-16 00:42:35', '2025-10-16 00:43:03'),
(64, NULL, NULL, 'Más que una bebida, una identidad  ', NULL, NULL, 'En cada copa de vino o en cada sorbo de singani se puede sentir la historia de un pueblo que aprendió a transformar la altura en virtud. El vino de altura expresa la nobleza de los valles bolivianos; el singani, la alegría y elegancia del espíritu nacional. Juntos van conquistando el mundo, una botella a la vez.', 'custom', NULL, 'https://abi.bo/images/historico_1/vinhos-bolivia-0fb318a0.jpg', 5, NULL, NULL, '2025-10-16 00:47:16', '2025-10-16 00:47:16'),
(65, NULL, NULL, 'Tradición y modernidad', NULL, NULL, 'Las bodegas familiares mantienen la cosecha manual y la fermentación en tinajas. A su vez, modernas bodegas de Tarija y los Valles Cinteños incorporan procesos controlados en sistemas de prensado mecanizado y destilación de precisión, garantizando estándares internacionales sin perder la esencia local. \nEsta dualidad, entre lo ancestral y lo técnico, permite que Bolivia destaque en la escena vitivinícola mundial con vinos de alta calidad y un destilado de carácter incomparable.\nPor su parte el singani, cuenta con la denominación de origen boliviana y ha conquistado bares en ciudades como Nueva York, Londres y Tokio. \n', 'custom', NULL, 'https://activosbolivia.com/wp-content/uploads/2023/08/Proyecto-nuevo-singani-.jpg', 4, NULL, NULL, '2025-10-16 00:49:59', '2025-10-16 00:52:50'),
(66, NULL, 4, 'Cuando la fe se convierte en arte', NULL, NULL, 'Son encuentros donde la devoción religiosa se funde con la creatividad popular: los bordados brillan bajo el sol, las máscaras cobran vida, y los tambores marcan el pulso de un país que danza con el alma.\r\nLa herencia compartida entre lo sagrado y lo festivo, hace de cada celebración una manifestación capaz de emocionar y unir a todos quienes la viven. Por eso, cada año miles de visitantes llegan para sentir lo que no se puede explicar con palabras: la emoción de ver a un pueblo entero danzando su historia.\r\n', 'custom', 'RRSS', 'https://revistavamos.wordpress.com/wp-content/uploads/2008/05/_unt8718.jpg', 4, NULL, NULL, '2025-10-16 00:54:15', '2025-10-16 00:54:15'),
(67, NULL, NULL, 'Altura, tradición y sabor', NULL, NULL, 'Bolivia guarda uno de sus secretos mejor resguardados: los viñedos más altos del mundo, cultivados entre los 1.800 y 2.200 metros sobre el nivel del mar.\r\nLas primeras cepas fueron traídas desde España y se lograron adaptar en los valles de Tarija, Chuquisaca y la región de los Cintis. El esfuerzo de generaciones de viticultores logró domesticar la vid en un entorno desafiante. \r\nEn estas mismas alturas nació también el singani, un destilado elaborado exclusivamente con uva moscatel de Alejandría, cuya pureza y suavidad lo convirtieron en orgullo nacional.', 'custom', NULL, 'uploads/articles/article_20251104_131352_d51e2521f018.webp', 5, 'home', NULL, '2025-10-16 00:54:56', '2025-11-04 18:13:56'),
(68, NULL, 4, 'El alma festiva de un país diverso', NULL, NULL, 'Las festividades bolivianas reflejan la fuerza de su gente y la riqueza de su historia. Cada celebración es un lenguaje distinto: la Diablada cuenta la lucha entre el bien y el mal, la Morenada rinde homenaje a la fuerza y la resistencia ante la esclavitud, la Saya expresa la voz afroboliviana que canta libertad, y danzas como los Macheteros moxeños o los Caporales llevan el ritmo de la identidad nacional más allá de las fronteras.', 'custom', 'RRSS', 'https://upload.wikimedia.org/wikipedia/commons/thumb/b/ba/CORSO%2C_LA_PAZ_-_BOLIVIA%2C_SAYA_AFROBOLIVIANA_1.jpg/1200px-CORSO%2C_LA_PAZ_-_BOLIVIA%2C_SAYA_AFROBOLIVIANA_1.jpg', 4, NULL, NULL, '2025-10-16 00:55:18', '2025-10-16 00:55:37'),
(69, NULL, 4, 'Donde Bolivia baila al ritmo de su identidad', NULL, NULL, 'Cada danza, cada traje y cada melodía son una historia que cobra vida en las calles, donde la fe y la alegría se entrelazan en un solo corazón. El país entero se transforma en un escenario de ritmo, color y emoción. \r\nEl folklore boliviano es una expresión que une al pueblo y que invita al mundo a descubrir su cultura diversa. Desde las alturas del altiplano hasta las tierras cálidas del oriente, cada región baila su identidad. ', 'custom', 'RRSS', 'https://periodicolaesperanza.com/wp-content/uploads/2023/02/Danza-de-la-diablada-678x381.png', 4, NULL, NULL, '2025-10-16 00:57:56', '2025-10-16 01:33:43'),
(70, NULL, NULL, 'De la tierra al plato ', NULL, NULL, 'Los cereales y legumbres bolivianos desde los suelos fríos del altiplano hasta los fértiles valles interandinos y las cálidas tierras bajas, cada grano y semilla ha nutrido a generaciones, adaptándose a los distintos pisos ecológicos y conservando tradiciones que hoy sigue alimentando al pueblo boliviano.\r\nEntre los cereales más representativos se encuentran el maíz, la quinua y el amaranto y entre las legumbres el maní, el haba y el frijol; todos ellos con un papel esencial en la gastronomía y la cultura del país.\r\n', 'custom', NULL, 'https://cipca.org.bo/images/news/es/b_2302_implementar-bancos-de-semillas-para-afrontar-los-efectos-del-cambio-1.jpg', 4, NULL, NULL, '2025-10-16 01:10:32', '2025-10-16 01:10:32'),
(71, NULL, NULL, 'El maíz, símbolo de abundancia. ', NULL, NULL, 'El maíz es uno de los cultivos más antiguos de América y, en Bolivia, es un verdadero símbolo de vida y fertilidad. Desde tiempos prehispánicos, ha sido parte fundamental de la dieta y de las ceremonias agrícolas de los pueblos andinos. Su diversidad, amarillo, blanco, morado o reventón, permite una infinidad de preparaciones que llenan de sabor las mesas bolivianas.', 'custom', NULL, 'https://cdn.correodelsur.com/img/contents/images_980/2022/09/25/15763f92-0be5-4990-9fb4-0de86647ea7e.jpg', 4, NULL, NULL, '2025-10-16 01:14:31', '2025-10-16 01:15:13'),
(72, NULL, 3, 'Tradición en cada bocado', NULL, NULL, 'Humintas al horno, masa de maíz fresco mezclada con queso, envuelta en hojas de choclo y cocida al horno o al vapor. Plato típico de los valles y del altiplano, presente en celebraciones y ferias locales.\r\nLawas de maíz, sopas espesas elaboradas con maíz molido, papa, carne y hierbas aromáticas, un clásico de las comunidades rurales que representa el sabor reconfortante del hogar andino.\r\n', 'custom', NULL, 'https://cdn.bolivia.com/sdi/2024/03/26/cinco-platillos-bolivianos-que-puedes-preparar-en-semana-santa-1231814.jpg', 5, 'what_to_do', NULL, '2025-10-16 01:21:28', '2025-10-30 13:46:24'),
(77, NULL, NULL, '', NULL, NULL, 'El sábado de peregrinación, la ciudad entera se detiene para ver pasar a miles de danzantes. El sonido de las bandas, el brillo de los trajes y el cansancio en los rostros se mezclan con lágrimas de emoción cuando, ya frente a la Virgen, los bailarines se quitan la máscara y se arrodillan para pedir perdón. \r\nAl día siguiente, el domingo, la atmósfera cambia: la ciudad vibra con alegría, las calles se llenan de música, color y risas, y todos se unen en una celebración que parece no tener fin.\r\nEl lunes llega con el dramatismo de los “Relatos” de la Diablada, donde el Arcángel San Miguel y Lucifer reviven la eterna lucha entre el bien y el mal, una escena estremecedora. \r\nFinalmente, el martes de Ch’alla trae consigo un aire de calma y gratitud. Entre hojas de coca, serpentinas y globos, se agradece a la Pachamama por lo recibido, cerrando el carnaval. ', 'custom', 'RRSS', 'https://t4.ftcdn.net/jpg/01/96/67/37/360_F_196673765_Iz8smedi5tBmYJRkUdPaafHZVNW4FOmN.jpg', 4, NULL, NULL, '2025-10-16 02:09:16', '2025-10-16 16:43:27'),
(78, NULL, NULL, 'Cuatro días de fe, danza y devoción', 'Vivir el Carnaval de Oruro es dejarse llevar por una experiencia que mezcla fe, emoción y tradición en cada paso', 'Vivir el Carnaval de Oruro es dejarse llevar por una experiencia que mezcla fe, emoción y tradición en cada paso', NULL, 'custom', NULL, 'uploads/articles/article_20251104_023757_1fb6823b77dc.webp', 1, 'home', NULL, '2025-10-16 16:44:21', '2025-11-04 07:38:00'),
(79, NULL, NULL, 'La leyenda que dio vida al Carnaval de Oruro', NULL, NULL, 'El Carnaval de Oruro florece en la pampa orureña, con raíces que se remontan a tiempos prehispánicos y se entrelazan con influencias europeas. La leyenda cuenta que el dios Wari, enfadado porque el pueblo Uru adoraba al dios Inti, envió pestes y criaturas monstruosas, pero una Ñusta protectora apareció y las venció. En agradecimiento, los Urus comenzaron a vestirse de diablos, representando a Wari, y a rendir devoción a la Ñusta, hoy conocida como la Virgen del Socavón. Así nació una celebración única en el mundo, una danza entre la tierra y el cielo donde mito, historia y fe caminan al mismo paso.', 'custom', 'RRSS', 'https://lavozdetarija.com/wp-content/uploads/2024/05/monumento-a-la-virgen-candelaria.jpg', 4, NULL, NULL, '2025-10-16 16:46:22', '2025-10-16 16:46:22'),
(80, NULL, NULL, 'El latido del Folklore', NULL, NULL, 'Oruro, la capital del folclore boliviano, se transforma cada año en un escenario donde la fe y la tradición se funden en un solo espectáculo. El Carnaval de Oruro es una fiesta que vibra entre lo divino y lo humano, entre el sonido de los bronces y el silencio de la plegaria.\r\nVivir el Carnaval de Oruro es sumergirse en una explosión de colores, música y tradición que llena cada rincón de la ciudad. Las calles se transforman en un escenario vibrante donde el brillo de los trajes, la diversidad de danzas y las máscaras llenas de historia cuentan el alma de un pueblo devoto y festivo. Cada grupo que pasa contagia energía, invitando a locales y visitantes a unirse al ritmo de las bandas que no descansan ni de día ni de noche. \r\n', 'custom', 'RRSS', 'https://i.pinimg.com/originals/55/91/3d/55913ded538a2cb946bd7e99a932f8e1.jpg', 4, NULL, NULL, '2025-10-16 16:49:24', '2025-10-16 16:52:57'),
(81, NULL, NULL, 'Chunchos, promesa de fe', NULL, NULL, 'Los chunchos, protagonistas de la festividad que representan a los enfermos de lepra, bajaban desde los cerros en busca de alimento, cubriendo su rostro con velos y plumas como símbolo de humildad y anonimato. Hoy, ese gesto ancestral sigue vivo: una danza que no busca mostrar el rostro, sino el corazón que promete.', 'custom', 'RRSS', 'https://marielaaroundtheworld.com/san-roque-celebrations/img_6106/', 4, NULL, NULL, '2025-10-16 16:59:14', '2025-10-16 17:00:08'),
(82, NULL, NULL, 'La tradición que nació del antiguo Lazareto', NULL, NULL, 'Su origen se remonta al antiguo leprosario de Lazareto, donde, según la tradición, San Roque habría aparecido para aliviar el sufrimiento de los enfermos. Desde entonces, su figura se convirtió en el reflejo de la fe y la solidaridad tarijeña.', 'custom', 'RRSS', 'https://abi.bo/images/2024/Agosto/13/SRCHUNCHOS_1.jpg', 2, NULL, NULL, '2025-10-16 17:02:07', '2025-10-16 17:02:07'),
(83, NULL, NULL, 'La promesa que danza en Tarija', NULL, NULL, 'En el sur de Bolivia, Tarija se viste de fe, música y devoción para honrar a su patrono protector, San Roque, guardián de la salud y símbolo de esperanza para todo un pueblo. Cada septiembre, las calles tarijeñas laten al ritmo de tambores y violines, mientras miles de promesantes danzan con fervor.', 'custom', 'RRSS', 'https://elpais.bo/img/images_1200/contents/2023/09/10/8dfb5dff-8209-4025-b96a-edb25830c058.jpg', 4, NULL, NULL, '2025-10-16 22:20:13', '2025-10-16 22:21:46'),
(84, NULL, NULL, 'La fe que hace danzar a La Paz', NULL, NULL, 'La Fiesta Mayor del Gran Poder se celebra cada año en el mes de junio, generalmente el sábado siguiente a la solemnidad de la Santísima Trinidad, iniciando en la mañana y culmina en la noche.\r\nLa celebración tiene lugar en la ciudad de La Paz, sede de gobierno de Bolivia recorriendo las calles céntricas de la ciudad. Durante la festividad, la sede de gobierno se transforma en un gran escenario cultural, donde visitantes nacionales e internacionales disfrutan de una experiencia única que combina espiritualidad, tradición y fiesta.\r\n', 'custom', 'RRSS', 'https://cdn.bolivia.com/sdi/2025/06/03/anuncian-lanzamineto-oficial-del-gran-poder-2025-1287460.jpg', 4, NULL, NULL, '2025-10-16 22:55:48', '2025-10-16 22:55:48'),
(85, NULL, NULL, 'La evolución de una tradición viva', NULL, NULL, 'Su origen se remonta a los barrios populares del siglo XX, donde la imagen del Señor del Gran Poder era venerada en pequeños altares familiares. Con el tiempo, la fe de los devotos transformó esa sencillez en una gran entrada folclórica que hoy convoca a más de 85.000 bailarines y músicos que recorren las principales avenidas paceñas con trajes bordados, máscaras brillantes y coreografías que relatan la historia y la esencia de lo devoto.', 'custom', 'RRSS', 'https://blogger.googleusercontent.com/img/b/R29vZ2xl/AVvXsEglSZscE9gbaXMLVhzlyeoVGlIDBbFNDXbgX5hW736JM3i7lULT1UFV87GYEDHx9MTex2FGRklVIO1uBhrV4UzbgzulAHTfriqQ7kYUZIW-QEm4mw7-x7zpqFot6otF21Pq6ZcMxRleZ_c/s1600/rol_granpoder.jpg', 4, NULL, NULL, '2025-10-16 22:59:36', '2025-10-16 22:59:36'),
(86, NULL, NULL, 'La fiesta mayor de Los Andes', NULL, NULL, 'El Gran Poder es el latido espiritual de ciudad de La Paz. Cada año, la urbe se viste de fe, danza y color para rendir homenaje al Señor Jesús del Gran Poder. Cada fraternidad lleva en sus pasos una promesa, en sus bordados una historia y en su danza un sentimiento colectivo.', 'custom', 'RRSS', 'https://www.coolt.com/uploads/s1/88/62/1/bailarinas-interpretan-la-danza-waka-waka-en-la-fiesta-del-gran-poder-en-la-paz-bolivia-25-de-mayo-de-2024-efe-luis-gandarillas_4_795x421.jpeg', 4, NULL, NULL, '2025-10-16 23:02:14', '2025-10-16 23:02:14'),
(87, NULL, NULL, 'Cuando julio viste de fiesta', NULL, NULL, 'La Ichapekene Piesta se celebra cada año en el mes de julio, siendo el día central el 31, fecha dedicada a San Ignacio de Loyola. \r\nLa festividad tiene lugar en San Ignacio de Moxos, cercana a la ciudad de Trinidad, capital departamental de Beni.', 'custom', NULL, 'uploads/articles/article_20251104_125628_b4c4bf491d55.webp', 4, 'home', NULL, '2025-10-16 23:04:27', '2025-11-04 17:56:34'),
(88, NULL, NULL, 'Símbolos vivos', NULL, NULL, 'Más que una fiesta, es una representación del equilibrio entre lo sagrado y lo terrenal. Los Macheteros marcan el paso con su danza majestuosa, acompañados por los Achus, los Tigrecillos, los Toritos y la pareja del Sol y la Luna, personajes que simbolizan la unión del hombre con la naturaleza y la dualidad que gobierna el mundo. Los ritmos mestizos y barrocos, herencia de las misiones jesuíticas, se entrelazan con melodías nativas que evocan el canto de los ríos y el murmullo de la selva.\r\nA la medianoche, las bengalas que iluminan los sombreros de los danzarines simbolizan el don de la luz, la clarividencia para vivir en armonía con la tierra y sus espíritus. Cada gesto, cada máscara y cada melodía narran una historia que ha sobrevivido por siglos, manteniendo viva su memoria.', 'custom', 'RRSS', 'https://ich.unesco.org/img/photo/thumb/06087-BIG.jpg', 4, NULL, NULL, '2025-10-16 23:07:19', '2025-10-16 23:07:57'),
(89, NULL, NULL, 'La gran fiesta Mojeña', NULL, NULL, 'En la Amazonía boliviana, San Ignacio de Moxos se transforma cada julio en un escenario donde la fe, la naturaleza y la cultura bailan al mismo ritmo. La Ichapekene Piesta, es la celebración más grande del pueblo mojeño y una de las expresiones más auténticas de la identidad amazónica del país.', 'custom', 'RRSS', 'https://www.laregion.bo/wp-content/uploads/2024/08/Ichapekene-Piesta-Steffen-Reichle-3.jpg', 4, NULL, NULL, '2025-10-16 23:09:12', '2025-10-16 23:10:48'),
(90, NULL, NULL, '¡Descubre la esencia de Bolivia en cada experiencia!', 'Vive la diversidad de Bolivia a través de experiencias que despiertan tus sentidos y emociones', 'Vive la diversidad de Bolivia a través de experiencias que despiertan tus sentidos y emociones', NULL, 'custom', NULL, 'uploads/articles/article_20251104_014952_0f15023036c0.webp', 23, 'home', '/que-hacer', '2025-10-17 19:14:52', '2025-11-04 06:49:57'),
(1007, NULL, NULL, 'Jalq’as', 'La Cultura Jalq’a través de sus Textiles', 'La Cultura Jalq’a través de sus Textiles', 'La cultura Jalq’a, que habita Sucre y Potosí, cobra vida en sus textiles, obras que combinan creatividad, símbolos de animales y figuras mitológicas del inframundo reflejando su profunda conexión. Nacieron como necesidad y expresión: para pagar tributos, resistir el frío del altiplano y dar vuelo a la imaginación de sus artesanos.\r\nTejer es para los Jalq’a un acto de memoria y orgullo. Cada pieza inicia con la lana de oveja o llama, teñida con pigmentos naturales, hilada y llevada al telar, donde cada hebra adquiere movimiento y significado. Cada hilo rojo y negro narra historias heredadas de sus tatarabuelos, mostrando un arte que nace de la mente, de la tradición y de la inspiración espontánea que habita en cada artesano.', 'custom', 'RRSS', 'uploads/articles/article_20251105_180711_b055e10155be.webp', 4, 'home', NULL, '2025-10-17 20:07:23', '2025-11-05 23:07:13'),
(1008, NULL, NULL, 'Yampara', 'La grandeza de la Cultura Yampara', NULL, 'Los Yampara de Chuquisaca llevan en la sangre un espíritu aguerrido y en las manos la delicadeza del arte ancestral. Su presencia se hizo imposible de ignorar durante la resistencia a la conquista española, cuando sus guerreros enfrentaron al ejército invasor, y la leyenda recuerda su valentía hasta en los gestos más extremos, por ello se les conoce como “sunqu mikhus” (come corazón).\r\nEntre sus tradiciones vivas, el Pujllay celebra la cosecha y susurra gratitud a la Pachamama que nutre y protege, mientras que el Ayarichi danza contando historias de antiguas resistencias, recordando que el espíritu Yampara nunca se doblegó y sigue latiendo en cada generación.\r\n', 'custom', 'RRSS', 'https://live.staticflickr.com/5564/31513573205_60fc0a7a35_b.jpg', 4, NULL, NULL, '2025-10-17 20:09:31', '2025-10-22 13:59:24');
INSERT INTO `articles` (`id`, `parent_id`, `id_category`, `title`, `subtitle`, `description`, `content`, `type`, `author`, `media_url`, `template_id`, `page_section`, `link`, `created_at`, `updated_at`) VALUES
(1009, NULL, NULL, 'Guaraní', 'Guaraníes del Oriente Boliviano', NULL, 'Los guaraníes, guardianes del oriente y del Chaco boliviano, viven guiados por la “tierra sin mal” (Yvy marã ey), un ideal de armonía entre la tierra, los espíritus y la comunidad.\r\nSu vestimenta, ligera y adornada con plumas y semillas, refleja la profunda conexión con la naturaleza que los rodea. La lengua guaraní, viva y hablada con orgullo, transmite su visión única del mundo, donde cada ser posee un espíritu y un propósito, y todo se entrelaza en el equilibrio de la vida.\r\n', 'custom', 'RRSS', 'https://es.wfp.org/sites/default/files/2022-02/Foto%201%20Historia.jpg', 4, NULL, NULL, '2025-10-17 20:11:59', '2025-10-17 20:11:59'),
(1010, NULL, NULL, 'Quechua', 'Memoria Viva de los Quechuas', NULL, 'Los quechuas, uno de los pueblos más antiguos de Bolivia, habitan el Altiplano y los valles interandinos, llevando consigo la memoria de siglos que preceden al Imperio Inca. Su lengua, el quechua, vive como un hilo que se transmite de padres a hijos como un hilo que une generaciones, transmitiendo historias que mantienen latente su identidad.\r\nA través de la música, las fiestas y sus tradiciones, la tierra, el agua y el cielo dialogan con la vida cotidiana, revelando un mundo donde la lengua y la tradición se entrelazan en armonía con la naturaleza.\r\n', 'custom', 'RRSS', 'https://www.laregion.bo/wp-content/uploads/2019/09/AIQUILE-DL-11.jpg', 4, NULL, NULL, '2025-10-17 20:14:03', '2025-10-17 20:15:09'),
(1011, NULL, NULL, 'Aimaras', 'Legado Vivo del Altiplano', 'Legado Vivo del Altiplano', 'Los aimaras habitan el altiplano andino, junto a las aguas del lago Titicaca, guardando la memoria de sus ancestros en cada palabra y leyenda. De padres a hijos, de abuelos a nietos, sus historias fluyen como ríos entre la vida cotidiana y lo sagrado, revelando la dualidad, la complementariedad y la reciprocidad que sostienen su cosmos.\r\nEn el corazón de su mundo late la Pachamama, Madre Tierra, fuente de vida y equilibrio, a quien ofrendan sus rituales, conectando cielo, tierra y espíritu en un eterno diálogo con la naturaleza.', 'custom', 'RRSS', 'uploads/articles/article_20251104_125832_437b1aaa92a5.webp', 4, 'home', NULL, '2025-10-17 20:16:23', '2025-11-04 17:58:37'),
(1012, NULL, NULL, 'Chiquitanía', 'Pueblos vivos de las Misiones Jesuíticas', NULL, 'Las Misiones Jesuíticas son un encuentro de mundos, lo indígena y lo europeo. Nacieron con la llegada de los sacerdotes de la Compañía de Jesús, quienes fundaron reducciones para evangelizar a los pueblos originarios, combinando la fe cristiana con las tradiciones locales.\r\nDe esta fusión surgió un estilo único: templos de madera tallada y barroco mestizo, música misional que aún resuena entre sus paredes, y máscaras que hablan de identidad y resistencia. Su color claro, lejos de ser casual, burla a los colonos españoles, recordando que el arte guarda vivo el espíritu y la memoria de los pueblos del oriente boliviano.\r\n', 'custom', 'RRSS', 'https://wwflac.awsassets.panda.org/img/ormich10_801769.webp', 4, NULL, NULL, '2025-10-17 20:18:35', '2025-10-22 13:56:53'),
(1014, NULL, NULL, 'Uru Chipaya', 'Civilización milenaria de los Andes', NULL, 'Reconocidos como uno de los pueblos más antiguos de América, los Uru Chipayas son considerados verdaderos hijos del agua, pues surgieron cuando los pequeños lagos y terrenos habitables empezaron a formarse. \r\nDestacan sus viviendas circulares, construidas con adobe y diseñadas de manera que sus puertas siempre se orientan hacia el este, dejando entrar el sol y protegiéndolos del intenso frío del altiplano, una clara muestra de su ingenio milenario. La tradición se viste de lana y se enreda en el cabello. Sombreros tejidos acarician la cabeza, mientras las trenzas cuentan historias: finas y numerosas para las jóvenes solteras, gruesas y firmes para las casadas y las autoridades, símbolos vivos de estatus. \r\n', 'custom', 'RRSS', 'https://www.laregion.bo/wp-content/uploads/2025/04/nacion-Uru-Chipaya-Bolivia-2.jpeg', 4, NULL, NULL, '2025-10-17 20:23:09', '2025-10-17 20:24:42'),
(1015, NULL, NULL, 'Manos que Moldean Sal', NULL, NULL, 'Una de las artesanías más conocidas y procuradas en la región es la artesanía con sal. En las manos de los artistas locales, los bloques de este mineral se transforman en obras de arte, dando forma a animales, figuras humanas y monumentos que parecen cobrar vida, desde tamaños reales hasta miniaturas delicadas. Cada escultura es cuidadosamente tallada y pulida, hasta alcanzar una superficie lisa y brillante que refleja la luz y la creatividad de quien la creó.\r\nLa sal, símbolo de la riqueza natural del altiplano, se convierte un medio de expresión artística y cultural. ', 'custom', 'RRSS', 'https://us.123rf.com/450wm/anibaltrejo/anibaltrejo1401/anibaltrejo140101335/25393799-crafts-in-salinas-grandes-salt-flats-in-jujuy-province-northern-argentina.jpg', 4, NULL, NULL, '2025-10-17 20:29:38', '2025-10-17 20:29:38'),
(1016, NULL, NULL, 'Arte en Arcilla', NULL, NULL, 'En la mágica comunidad de Berque, la alfarería no es solo un oficio; es el latido que une a su gente. Cada vasija, cada cántaro, jarrón o florero es mucho más que barro moldeado, es un legado que perdura en cada cerámica.\r\nLas manos de los artesanos trabajan con destreza y delicadeza, transformando la arcilla en cada pieza que refleja la identidad de Berque, un patrimonio que se transmite de padres a hijos y que convierte la alfarería en símbolo de orgullo y expresión cultural.', 'custom', 'RRSS', 'uploads/articles/article_20251104_131156_830bfef405ab.webp', 4, 'home', NULL, '2025-10-17 20:31:37', '2025-11-04 18:11:57'),
(1017, NULL, NULL, 'Tejedoras de Palmeras', NULL, NULL, 'El tejido del sombrero de Saó es un arte que florece en la vida del oriente boliviano, nacido de palmeras y transformada por manos de mujeres artesanas y guardianas de su territorio. \r\nEn cada hogar se teje, sin importar la edad, y pocas veces de manera solitaria: las artesanas trabajan juntas, lado a lado, entrelazando hilos y palabras. Los sombreros de Saó, coronan la danza folclórica del oriente, como el taquirari y la chovena, llevando sobre sus alas la historia, la tradición y la identidad de su gente. \r\n', 'custom', 'RRSS', 'https://www.laregion.bo/wp-content/uploads/2015/11/DSC_0053-1024x685.jpg', 4, NULL, NULL, '2025-10-17 20:33:24', '2025-10-17 20:33:24'),
(1018, NULL, NULL, 'El Arte de la Totora ', NULL, NULL, 'En el lago Titicaca, la totora se convierte en hilo de tradición y creatividad. Las comunidades que habitan sus orillas tejen balsas que flotan sobre el agua, navegando entre islas del lago más profundo del planeta, pescando y llevando consigo la herencia de siglos. De la totora nacen también pequeñas balsas y figuras de animales, delicadas y minúsculas, que se transforman en llaveros o adornos de decoración. \r\nLos hombres reman hacia los totorales, recogiendo los tallos más largos y firmes, aprovechando cada hebra, cada fibra, como si cada corte tejiera también un pedazo de historia y cultura que permanece viva en cada embarcación.\r\n', 'custom', 'RRSS', 'https://www.laregion.bo/wp-content/uploads/2019/07/huatajata-RLL-8.jpg', 4, NULL, NULL, '2025-10-17 20:34:46', '2025-10-17 20:34:46'),
(1019, NULL, NULL, 'Tiwanaku', 'Donde las piedras hablan', NULL, 'A orillas del Lago Titicaca, se levanta Tiwanaku como testimonio eterno de una civilización que marcó el origen del altiplano andino. Declarado Patrimonio Cultural de la Humanidad por la UNESCO, este sitio arqueológico relata su grandeza arquitectónica, espiritual y humana en sus piedras. \r\nSe alzan estructuras que desafían al tiempo y espacio, la imponente Puerta del Sol, el templo de Kalasasaya y la pirámide de Akapana, son reflejo de una precisión que asombra incluso a la ingeniería moderna. Entre sus piedras vive el eco de Wiracocha y la conexión sagrada entre el hombre y el cosmos, recordando que Tiwanaku no desapareció: sigue respirando en la memoria del tiempo.\r\n', 'custom', 'RRSS', 'https://media2.holiplus.com/3840x2880/uploads/excursion/68575/tiwanaku-tour-464.jpeg', 4, NULL, NULL, '2025-10-17 22:27:30', '2025-10-17 22:27:30'),
(1020, NULL, NULL, 'Ruta Prehispánica', 'El camino donde nació la historia', 'El camino donde nació la historia', 'Antes de que existieran fronteras, hubo senderos que unieron pueblos, montañas y sueños. La Ruta Prehispánica de Bolivia es uno de esos caminos milenarios, conectando sitios como Tiwanaku, Inkallajta, Samaipata y los antiguos caminos del Qhapaq Ñan. \r\n Cada tramo narra la historia de un pueblo que entendió la montaña como guía, el sol como protector y el camino como símbolo de unión. Descubrir un país donde la historia no se estudia… se camina.', 'custom', 'RRSS', 'uploads/articles/article_20251104_124609_dd9135cffcd5.webp', 4, 'home', NULL, '2025-10-17 22:29:33', '2025-11-04 17:46:12'),
(1021, NULL, NULL, 'Samaipata', 'Descanso en las alturas', NULL, 'En las estribaciones de los Andes, donde la montaña abraza el verde de los valles cruceños, se alza Samaipata. Su nombre, “descanso en las alturas”, refleja el encanto de un lugar donde el tiempo se detiene para contemplar el pasado.\r\nEn lo alto se alza El Fuerte de Samaipata, tallado en piedra y declarado Patrimonio Cultural de la Humanidad por la UNESCO, revela la fusión de influencias incaicas, amazónicas y precolombinas, testimonio de la convivencia de culturas que entendían la tierra como un templo. A los pies del sitio arqueológico, el pueblo conserva su espíritu acogedor, con calles empedradas, casas coloniales, clima templado y su gente amable que invitan a recorrer su valle en calma.\r\n', 'custom', 'RRSS', 'https://media.istockphoto.com/id/1189489640/es/foto/restos-del-sitio-arqueol%C3%B3gico-pre-inca-cerca-de-samaipata-en-bolivia.jpg?s=612x612&w=0&k=20&c=i7a-PWwAzVYY4_XW43tIUloUpvtB6soWenBtsEWiQmk=', 4, NULL, NULL, '2025-10-17 22:32:08', '2025-10-17 22:40:52'),
(1022, NULL, NULL, 'Morenada', 'El compás solemne de la memoria y el orgullo', 'El compás solemne de la memoria y el orgullo', 'Su andar pausado evoca el paso firme de los esclavos africanos que, entre cadenas y cansancio, transformaron su dolor en danza. Nació como una sutil burla a los bailes de los señores blancos, pero con el tiempo se convirtió en un canto de libertad, acompañado por bombos que estremecen la tierra y matracas que imitan el sonido de las cadenas.\r\nLos trajes, bordados con hilos de oro y plata, relucen bajo el sol como símbolo de poder y resistencia. Las máscaras de ojos saltones guardan la fuerza del esfuerzo humano, mientras las cholitas morenas danzan con elegancia, moviendo sus polleras coloridas al compás de la música. Hoy, la Morenada es mucho más que una danza: es un orgullo nacional.', 'custom', 'RRSS', 'uploads/articles/article_20251104_131902_8b2e2c01baee.webp', 4, 'home', NULL, '2025-10-17 22:54:36', '2025-11-04 18:19:04'),
(1023, NULL, NULL, 'Diablada', 'El fuego del Carnaval de Oruro', NULL, 'La Diablada es la danza emblemática del Carnaval de Oruro en donde los bailarines interpretan a los diablos avanzando entre saltos, giros y reverencias. \r\nLa Diablada representa la eterna lucha entre el bien y el mal, entre los ángeles liderados por San Miguel y las huestes infernales comandadas por Lucifer. Cada personaje cobra vida en una puesta en escena majestuosa: máscaras que brillan con cuernos dorados, trajes pesados cubiertos de bordados minuciosos y coreografías que fusionan lo teatral con lo espiritual.\r\nBailar la Diablada es un acto de fe y devoción que transforma la espiritualidad en arte.\r\n\r\n', 'custom', 'RRSS', 'https://abi.bo/images/historico_1/diablos_de_Oruro.jpg', 4, NULL, NULL, '2025-10-17 22:59:11', '2025-10-17 23:01:57'),
(1024, NULL, NULL, 'Caporales', 'El ritmo del vigor y la libertad', NULL, 'El Caporal es una danza que refleja el orgullo mestizo, la herencia afroboliviana y la energía del Bolivia actual. Nacida de la figura del capataz que vigilaba a los esclavos en tiempos coloniales, el pueblo convirtió ese símbolo de poder en una danza de libertad. \r\nCon pasos firmes y saltos vigorosos, los danzarines muestran su valentía y vitalidad. Sus botas adornadas con cascabeles, chaquetas bordadas y sombreros de ala corta, junto a los látigos que marcan el compás, completan la vestimenta. Las mujeres se suman con gracia, luciendo polleras coloridas y gestos de elegancia y energía.\r\n', 'custom', 'RRSS', 'https://st2.depositphotos.com/1320014/9842/i/450/depositphotos_98423130-stock-photo-caporales-dance-group.jpg', 4, NULL, NULL, '2025-10-17 23:35:59', '2025-10-17 23:36:45'),
(1027, NULL, 1, 'Patrimonio Boliviano, Sinónimo de Identidad', NULL, NULL, 'El patrimonio material está reconocido en sus templos coloniales, ciudades históricas, caminos ancestrales y obras arquitectónicas que narran el paso del tiempo. Cada estructura, piedra o mural es testigo silencioso de la identidad revelada entre montañas, valles y llanuras.\r\nMientras tanto, el patrimonio inmaterial respira en sus fiestas, en la música que acompaña los rituales, en los tejidos que guardan símbolos milenarios y en la sabiduría de las comunidades que dan sentido a la vida colectiva. En cada canto, danza o costumbre se revela la memoria viva de una nación que se reconoce en su diversidad.', 'custom', NULL, 'uploads/articles/article_20251104_124250_4369d1282edb.webp', 4, 'home', NULL, '2025-10-17 23:52:03', '2025-11-04 17:42:55'),
(1028, NULL, 1, 'Descubrir el patrimonio boliviano es descubrir el alma de su gente', NULL, NULL, 'Un legado que no solo pertenece al pasado, sino que sigue latiendo en el presente, inspirando a las nuevas generaciones a proteger lo que somos.', 'custom', NULL, 'https://upload.wikimedia.org/wikipedia/commons/3/3e/Chunchos_%28206708213%29.jpeg', 2, NULL, NULL, '2025-10-17 23:54:17', '2025-10-22 13:42:52'),
(1029, NULL, 1, 'Nuestra Cultura, Tesoros de Autenticidad', NULL, NULL, 'Bolivia resguarda, de oriente a occidente, tesoros de autenticidad que nacen en épocas milenarias y perduran hasta la actualidad. Culturas que se transformaron con el tiempo sin perder su raíz, dejando su huella en textiles convertidos en símbolos de identidad, músicas que dialogan con la tierra, sitios emblemáticos que evocan su pasado y artesanías moldeadas con manos de oro a partir de la riqueza que brinda la Madre Tierra.', 'custom', NULL, 'uploads/articles/article_20251104_015213_9d1e1e77fafb.webp', 4, 'home', NULL, '2025-10-17 23:55:05', '2025-11-04 06:52:19'),
(1030, NULL, NULL, 'Tejidos Jalq’as', 'El universo del ukhu pacha tejido en identidad', NULL, 'Los tejidos Jalq’a son mucho más que hilos entrelazados: son un reflejo del ukhu pacha, el mundo interior y fecundo donde habitan los khurus, criaturas indomables que emergen de las profundidades donde la luz no existe. En cada Pallay, este universo se despliega en formas que parecen moverse por sí solas: serpientes de dos cabezas, aves con dientes, mamíferos alados y espíritus sin forma, todos entrelazados en un flujo perpetuo que captura la vitalidad del caos primordial.\r\nLos tonos negros evocan la oscuridad y el misterio del mundo subterráneo, mientras que el rojo simboliza la energía vital, la sangre que palpita en las entrañas de la tierra. Para las mujeres Jalq’a, tejer es un acto sagrado: un diálogo con el misterio, un puente entre lo humano y lo espiritual, convirtiendo cada tejido en un testimonio vivo de su cosmovisión.\r\n', 'custom', 'RRSS', 'https://www.ailamhub.org/wp-content/uploads/elementor/thumbs/inmark-2-qysle76gsps7a8we9swfjwhukb5m4n9iebdsiwp2ok.jpeg', 4, NULL, NULL, '2025-10-18 00:22:00', '2025-10-18 00:22:00'),
(1031, NULL, NULL, 'Tejido Kallawaya', 'Hilos que curan y cuentan la vida', NULL, 'En el universo Kallawaya, el textil trasciende la función de vestimenta: un lenguaje que encarna identidad, saberes y espiritualidad. Cada prenda, ya sea un aqsu, lliclla o wincha, guarda símbolos de la montaña, del sol y del agua, reflejando la relación sagrada entre el ser humano y la naturaleza que lo rodea.\r\nLas tejedoras Kallawaya transforman la lana de alpaca y oveja en auténticos mapas culturales: los colores señalan los pisos ecológicos, los diseños narran historias de su territorio, y los hilos enlazan generaciones. En sus manos, el tejido se vuelve un acto de sanación, un puente entre lo visible y lo espiritual. Así, el arte textil Kallawaya sigue siendo una medicina visual, un testimonio vivo del equilibrio entre humanidad y naturaleza.\r\n', 'custom', 'RRSS', 'https://i.pinimg.com/736x/c7/a6/d1/c7a6d10756c3dcc8848d680de43e43c1.jpg', 4, NULL, NULL, '2025-10-18 00:23:35', '2025-10-18 00:23:35'),
(1032, NULL, NULL, 'Tejido Uru Chipaya', 'El alma del agua hecha hilo', NULL, 'Los Uru Chipayas, primeros habitantes del mundo andino, tejen desde la memoria del agua. En cada prenda de lana de oveja y llama se refleja la vida del lago, los ríos y el cielo que se mira en su espejo. Los tonos negros, grises, blancos y cafés evocan la sombra y la luz, el día y la noche, la tierra y el agua que los nutre.\r\nCada poncho, faja, manta o sombrero es un símbolo de identidad. Sus líneas representan el movimiento del viento sobre el lago, mientras que sus formas funcionan como camuflaje natural, recordando la unión de los urus con las aves y los peces. Tejer no es solo crear una prenda, sino reafirmar quiénes son: qhas qot zoñi, hombres y mujeres del agua.\r\n', 'custom', NULL, 'https://lh3.googleusercontent.com/proxy/opDW9PEDKU0Yxi_AWQs40ylVIGSRAQoBB_YbaKhzCQMfJKZyE8EdVfU8n6lumH2bJCaR20isXH9FbIuk_9i71Pj8wQeOXv0P_blnqOk686TGxOso_QrjBaknAJTOkwU8L_FL', 4, NULL, NULL, '2025-10-18 00:25:21', '2025-10-18 00:25:21'),
(1036, NULL, NULL, 'Sucre: la ciudad blanca que guarda la historia de Bolivia', 'Capital constitucional, Patrimonio de la Humanidad y cuna de la República', 'Callejones coloniales, fachadas blancas y una atmósfera de eterna primavera te esperan en Sucre.', 'Sucre no es solo la capital constitucional de Bolivia: es un museo vivo. Sus calles empedradas, balcones coloniales y plazas arboladas están declaradas Patrimonio de la Humanidad por la UNESCO. Aquí nació la República, en la Casa de la Libertad, y cada edificio cuenta una historia. Pero Sucre también es moderna: universidades, cafés bohemios y una vibrante escena cultural. Ideal para caminar sin prisa, descubrir museos como el MUSEF o el Museo del Tesoro, y disfrutar de la gastronomía chuquisaqueña. Una ciudad que invita a quedarse más de lo planeado.', 'custom', 'Equipo Conoce Bolivia', 'uploads/articles/article_20251104_023111_0a7fb2fe5b53.webp', 24, 'where_to_go', '/ruta', '2025-10-17 23:26:59', '2025-11-04 07:31:15'),
(1037, NULL, NULL, 'Uyuni: puerta de entrada al espejo del cielo', 'El desierto de sal más grande del mundo y sus paisajes surreales', 'Un viaje al altiplano sur para vivir la magia del Salar de Uyuni y el Parque Nacional Sajama.', 'Uyuni es mucho más que el Salar. Es un pueblo tranquilo que sirve de base para explorar uno de los paisajes más extremos y bellos del planeta. El Salar de Uyuni, con sus 10,000 km² de sal, se transforma en un espejo infinito en temporada de lluvias. Pero también puedes visitar el Cementerio de Trenes, las islas de pescadores como Incahuasi, las lagunas de colores (Colorada, Verde, Hedionda) y el volcán Sajama, el más alto de Bolivia. Todo en un entorno de silencio, cielo despejado y aire puro. Una experiencia que redefine lo que es posible ver en la Tierra.', 'custom', 'Equipo Conoce Bolivia', 'uploads/articles/article_20251104_125303_22f743a2a5d3.webp', 4, 'where_to_go', NULL, '2025-10-17 23:26:59', '2025-11-04 17:53:05'),
(1038, NULL, NULL, 'Rurrenabaque: la puerta a la Amazonía boliviana', 'Selva, ríos, vida silvestre y comunidades indígenas en el norte del país', 'Descubre el Parque Madidi, uno de los lugares con mayor biodiversidad del planeta.', 'Rurrenabaque, en el departamento del Beni, es el punto de partida para adentrarse en la Amazonía boliviana. Desde aquí, tours guiados te llevan al Parque Nacional Madidi, donde podrás navegar por el río Tuichi, avistar delfines rosados, monos, jaguares (si tienes suerte) y cientos de aves. Los campamentos ecológicos, construidos por comunidades indígenas, ofrecen una experiencia auténtica y sostenible. De día, caminatas por la selva; de noche, el sonido de la naturaleza más intacta. Para quienes buscan desconectar del mundo moderno y conectar con la vida en estado puro.', 'custom', 'Equipo Conoce Bolivia', 'uploads/articles/article_20251104_023514_696666936150.webp', 5, 'where_to_go', NULL, '2025-10-17 23:26:59', '2025-11-04 07:35:18'),
(1039, NULL, NULL, '¡Consejos para planificar tu viaje a Bolivia!', 'Una buena planificación te permitirá disfrutar plenamente de cada experiencia que el país tiene para ofrecer.', 'Una buena planificación te permitirá disfrutar plenamente de cada experiencia que el país tiene para ofrecer.', NULL, 'custom', 'Equipo Conoce Bolivia', '/videos/conocebolivia1080X192.mp4', 20, 'planning', NULL, '2025-10-18 00:00:32', '2025-11-05 18:53:33'),
(1040, NULL, NULL, '¿Cómo moverse por Bolivia?', 'Toma el control de tu viaje y explora cada esquina de Bolivia, llegando hasta los rincones más escondidos del país.', 'Aproveche las rutas terrestres y aéreas para explorar cada rincón del país.', 'Bolivia tiene una red de buses interurbanos económicos y frecuentes (ej: La Paz - Santa Cruz en 18h). Para distancias largas, use vuelos domésticos (BoA, Amaszonas). En ciudades, el transporte público incluye micros y taxis. En zonas rurales, use \"flotas\" (minibuses compartidos). Si alquila auto, tenga en cuenta que algunas carreteras son de tierra y requieren 4x4.', 'custom', 'Equipo Conoce Bolivia', 'https://www.laregion.bo/wp-content/uploads/2022/10/RAFTING-BOLIVIA-2.jpg', 21, 'planning', NULL, '2025-10-18 00:00:32', '2025-10-21 19:15:29'),
(1047, NULL, NULL, 'Visas y requisitos de entrada a Bolivia', '¿Necesita visa? ¿Qué documentos llevar?', 'Información actualizada para ciudadanos de todo el mundo.', 'Ciudadanos de la UE, EE.UU., Canadá, Australia y muchos países de América Latina **no necesitan visa** para estancias turísticas de hasta 90 días. Solo requieren pasaporte válido (mínimo 6 meses). Algunos países (China, India, Nigeria) sí requieren visa. Verifique en el sitio del Ministerio de Relaciones Exteriores de Bolivia. Al ingresar, puede pedirle el pasaje de salida y reservas de hotel. No se requiere vacuna contra la fiebre amarilla si no viene de un país endémico.', 'custom', 'Equipo Conoce Bolivia', 'https://casadelalibertad.org.bo/wp-content/uploads/2024/11/Frag_1200x1200-copia.jpg', 2, 'planning', NULL, '2025-10-18 00:00:32', '2025-10-18 00:23:56'),
(1048, NULL, NULL, 'Bueno saber: datos prácticos para su viaje', 'Idioma, propinas, electricidad, mascotas y más', 'Pequeños detalles que marcan la diferencia.', 'Idioma: español (oficial), pero se hablan quechua, aymara y guaraní. Propinas: 10% en restaurantes si el servicio no está incluido. Electricidad: 220V, enchufe tipo C (redondo, dos patas). Mascotas: requieren certificado sanitario y vacuna antirrábica. Emergencias: llame al 110 (policía) o 116 (ambulancia). Horario: UTC-4 todo el año (no hay horario de verano).', 'custom', 'Equipo Conoce Bolivia', 'uploads/articles/article_20251104_023414_bc5cdf9982c2.webp', 29, 'planning', NULL, '2025-10-18 00:00:32', '2025-11-04 07:34:15'),
(1050, NULL, NULL, 'Más Lugares para Planificar', 'Descubre otros destinos increíbles para incluir en tu itinerario de viaje por Bolivia', 'Descubre otros destinos increíbles para incluir en tu itinerario de viaje por Bolivia', NULL, 'custom', 'Samuel', 'uploads/articles/article_20251104_025007_37ea536c2153.webp', 24, 'planning', NULL, '2025-10-20 23:12:12', '2025-11-04 07:50:09'),
(1052, NULL, NULL, '   ', NULL, NULL, 'Y en la vida moderna, la música popular del oriente sigue latiendo con fuerza. La tamborita, la flauta de tacuara y la guitarra acompañan los taquiraris y chovenas, ritmos que contagian alegría en cada fiesta. Son melodías que celebran la vida, la amistad y el amor, donde la gente baila con el corazón ligero, al compás del llano', 'custom', 'RRSS', 'https://repuestosmusicales.com.ar/wp-content/uploads/2020/12/FLAUTA-TRAVERSA-DE-ESTUDIO.jpg', 4, NULL, NULL, '2025-10-21 16:24:19', '2025-10-21 16:24:19'),
(1053, NULL, NULL, '   ', NULL, NULL, 'En las antiguas misiones jesuíticas de Moxos y Chiquitos, la herencia se transformó en armonía: los ensambles barrocos misionales conservan partituras de siglos pasados que hoy vuelven a cobrar vida, interpretadas por jóvenes músicos que combinan fe, técnica y orgullo cultural. En cada concierto, el pasado colonial se entrelaza con el alma indígena, creando un sonido que es, al mismo tiempo, europeo y profundamente amazónico', 'custom', NULL, 'https://lavozdetarija.com/wp-content/uploads/2022/05/Sinfonica-ensamble-de-Moxos.jpg', 4, NULL, NULL, '2025-10-21 16:26:22', '2025-10-22 13:46:54'),
(1054, NULL, NULL, 'Instrumentos', NULL, NULL, 'Instrumentos como el bajón mojeño y el yoresomanca resuenan en las ceremonias sagradas de los pueblos moxeños, marcando el ritmo de los rituales y el diálogo con la naturaleza. Cada soplo, grave y profundo, evoca el respeto por la tierra y la conexión con los espíritus del bosque.', 'custom', 'RRSS', 'uploads/articles/article_20251104_124502_99642a3de1bc.webp', 4, 'home', NULL, '2025-10-21 16:27:34', '2025-11-04 17:45:04'),
(1055, NULL, NULL, 'El alma sonora del oriente boliviano', NULL, NULL, 'La música del oriente boliviano es un puente entre la espiritualidad ancestral y la alegría cotidiana. En medio de selvas, ríos y llanuras infinitas, su sonido florece como una herencia viva que acompaña los rituales, las fiestas y los días tranquilos de la Amazonía.', 'custom', NULL, 'uploads/articles/article_20251104_020135_bfa83ca13ee5.webp', 1, 'home', NULL, '2025-10-21 16:28:51', '2025-11-04 07:01:40'),
(1056, NULL, NULL, '   ', NULL, NULL, 'En tiempos de carnaval, las coplas llenan el aire con versos picarescos y mensajes de amor, donde la risa y la nostalgia se entrelazan al compás del zapateo y los kaluyos. Cada voz femenina aporta dulzura, cada canto popular conserva una historia, y cada nota expresa un sentimiento: el amor, la añoranza o la alegría de vivir', 'custom', NULL, 'https://express.adobe.com/page/C1rrgFx79WWTy/images/d7ef71a9-9b74-4bc9-8ec3-0f4cce9b62ed.jpg?asset_id=66789b3f-165a-4034-a9b9-962e3b208e0e&img_etag=f04481223d09a00c9c700b621a24838d&size=1024', 4, NULL, NULL, '2025-10-21 16:30:15', '2025-10-21 16:30:15'),
(1057, NULL, NULL, '   ', NULL, NULL, 'El sonido del charango, con sus repunteos y quimbas, traduce en cuerdas la chispa y la ternura de su gente. Junto a los sikus, que danzan con el viento, y las quenas, que dejan escapar melodías suaves, la música de los valles combina emoción y movimiento en una armonía única', 'custom', NULL, 'https://abyayala.tv.bo/wp-content/uploads/2023/11/WhatsApp-Image-2023-11-04-at-16.55.01.jpeg', 4, NULL, NULL, '2025-10-21 16:34:16', '2025-10-21 21:03:05'),
(1058, NULL, NULL, 'La alegría hecha música en los valles bolivianos', NULL, NULL, 'Escuchar la música de los valles bolivianos es sentir cómo la alegría se convierte en melodía y la picardía en verso. Entre montañas templadas y cielos claros, nace un ritmo que refleja la esencia del pueblo valluno: alegre, sentimental y profundamente humano.', 'custom', NULL, 'uploads/articles/article_20251103_122812_aa7a4791ab15.webp', 1, 'home', NULL, '2025-10-21 16:35:30', '2025-11-03 17:28:12'),
(1059, NULL, NULL, '   ', NULL, NULL, 'Cada instrumento es una voz que conecta a los pueblos con su entorno, una forma de comunicación espiritual donde la naturaleza y la humanidad se funden en un mismo canto.', 'custom', NULL, 'https://apcbolivia.org/wp-content/uploads/2024/06/WhatsApp-Image-2024-06-04-at-17.06.41-6.jpeg', 2, NULL, NULL, '2025-10-21 16:40:22', '2025-10-21 20:34:29'),
(1060, NULL, NULL, '   ', NULL, NULL, 'El poder de los Andes se siente en su música, en ese eco que nace del gélido frio y se transforma en melodía al rozar las cumbres y nevados. Los sikus soplan armonías que dialogan en las alturas del cielo; las quenas, con su timbre melancólico, relatan la vida cotidiana de las comunidades originarias; mientras que las tarkas y pinkillos anuncian la siembra, el trabajo y la celebración', 'custom', 'RRSS', 'https://pbs.twimg.com/media/D0CCU_3X4AACvFk?format=jpg&name=large', 4, NULL, NULL, '2025-10-21 16:41:14', '2025-10-21 20:22:36'),
(1061, NULL, NULL, 'El poder de los andes', 'Escuchar los ecos del viento hecho música es escuchar el alma de sus pueblos', 'Escuchar los ecos del viento hecho música es escuchar el alma de sus pueblos', 'sonidos que cruzan montañas, pampas y en cada nota la historia de quienes aprendieron a cantar con el viento.', 'custom', NULL, 'uploads/articles/article_20251104_021528_4d70e85f2af2.webp', 1, 'home', NULL, '2025-10-21 16:42:09', '2025-11-04 07:15:32'),
(1062, NULL, NULL, 'Visas', NULL, NULL, 'Bolivia tiene sus propios requisitos de entrada y visado, que dependen de tu país de procedencia. Para información actualizada sobre visas y trámites migratorios, consulta con el consulado o la embajada de Bolivia más cercana o ingresa a la página web: www.migracion.gob.bo', 'custom', NULL, 'https://www.bolivianfullexplorer.com/wp-content/uploads/2023/12/VISA-BOLIVIA-ABI.jpg', 22, 'planning', 'https://www.migracion.gob.bo', '2025-10-21 16:50:45', '2025-10-21 19:58:44'),
(1063, NULL, NULL, 'Información Médica', NULL, NULL, 'En las principales ciudades encontrarás hospitales y clínicas privadas con buena atención médica, mientras que en zonas rurales es limitada, por lo que se recomienda contar con seguro de viaje.\r\nSi planeas visitar zonas como la Amazonía boliviana, donde el clima es cálido y existe mayor contacto con la fauna, la vacuna contra la fiebre amarilla es obligatoria. También se recomiendan vacunas como tétanos-difteria, triple vírica y hepatitis A, y para quienes permanecerán por tiempo prolongado o tendrán contacto con animales, se aconsejan vacunas contra hepatitis B, rabia o fiebre tifoidea. \r\nSe recomienda consultar con anticipación para definir las vacunas necesarias según el país de origen y las regiones que se visitarán dentro de Bolivia.', 'custom', NULL, 'uploads/articles/article_20251111_190311_c250ccadb361.webp', 23, 'planning', NULL, '2025-10-21 18:03:24', '2025-11-12 00:03:11'),
(1064, NULL, NULL, 'Seguridad y Bienestar', NULL, NULL, 'Bolivia es un país seguro para los turistas, ofreciendo zonas turísticas tranquilas y asistencia de la policía turística para garantizar su bienestar, evitar caminar solo de noche en áreas poco iluminadas y mantener los objetos de valor seguros. Es recomendable informarse sobre posibles manifestaciones o bloqueos, aprovechar la asistencia de la policía turística y llevar siempre documentos de identificación y contactos de emergencia.', 'custom', NULL, 'uploads/articles/article_20251111_190455_cf5cfa62053f.webp', 22, 'planning', NULL, '2025-10-21 18:10:05', '2025-11-12 00:04:55'),
(1065, NULL, NULL, 'Días Festivos', NULL, NULL, '1 de enero - Año Nuevo: El año comienza con celebraciones que marcan nuevos comienzos. \r\n12 de enero - Día Nacional del Turismo: Bolivia celebra su diversidad en destinos, riqueza cultural, natural y gastronómica. \r\n14, 15, 16 y 17 de febrero (Fecha Movible) - Carnaval: Una de las fiestas más vibrantes del país, donde música, danza y tradición convergen. \r\n21 de mayo - Año Nuevo Andino Amazónico y del Chaco: Celebración del retorno del sol dando la bienvenida a un nuevo ciclo solar.\r\n6 de agosto - Independencia de Bolivia: Día cívico nacional con desfiles, actos protocolares y homenajes a los héroes de la independencia. \r\n27 de septiembre - Día Mundial del Turismo: Fecha dedicada a valorar la actividad turística como motor de desarrollo sostenible y cultural. \r\n1 y 2 de noviembre - Todos Santos: Día para honrar a los fallecidos con ofrendas y sabores tradicionales en recuerdo de los seres queridos.\r\n25 de diciembre - Navidad: Celebración del nacimiento de Jesús.', 'custom', NULL, 'uploads/articles/article_20251104_022151_16db790ec912.webp', 23, 'planning', NULL, '2025-10-21 18:39:34', '2025-11-04 07:21:57'),
(1066, NULL, NULL, 'Clima y estaciones', NULL, NULL, 'Bolivia es un país de contrastes, donde el clima moldea paisajes que cambian con la altitud. En el Altiplano, los días se iluminan con un sol intenso y las noches se visten de frío; en los valles interandinos, disfrutan de un clima templado; y en los llanos y la Amazonía, el calor y la humedad dan vida a una naturaleza exuberante. \r\nDos estaciones marcan el año: la seca, de mayo a octubre, ideal para explorar bajo cielos despejados, y la lluviosa, de noviembre a marzo, cuando la naturaleza se viste de verde y vitalidad.', 'custom', NULL, 'uploads/articles/article_20251104_021804_03520a5a94da.webp', 22, 'planning', NULL, '2025-10-21 18:46:55', '2025-11-04 07:18:09'),
(1067, NULL, NULL, '¿Dónde Alojarse?', NULL, NULL, 'Viajar por Bolivia es también descubrir su hospitalidad. Desde los hoteles de las grandes ciudades hasta los ecolodges ocultos entre la selva o el altiplano, el país ofrece opciones para cada tipo de viajero. Ya sea que explores la modernidad de Santa Cruz, las alturas de La Paz o los paisajes infinitos del Salar de Uyuni, siempre encontrarás un espacio donde el descanso tiene alma boliviana: cálido, sencillo y auténtico.', 'custom', NULL, 'https://cf.bstatic.com/xdata/images/hotel/max1024x768/331148739.jpg?k=8f5fd6457f77ad8116ace7cc3ba5d1a0ffb4f0bba3e9abaabc0c7e81269c6b07&o=&hp=1', 23, 'planning', '/buscar?tab=alojamiento', '2025-10-21 18:48:10', '2025-10-21 19:19:10'),
(1068, NULL, NULL, 'Accesibilidad', NULL, NULL, 'Bolivia recibe a los viajeros a través de tres aeropuertos internacionales principales: El Alto en La Paz, que abre la puerta al altiplano y a las majestuosas montañas andinas; Viru Viru en Santa Cruz de la Sierra, ideal para descubrir el oriente y la exuberante Amazonía; y Jorge Wilstermann en Cochabamba, un punto estratégico que conecta el valle con las tierras altas y bajas. También es posible ingresar por tierra desde países vecinos como Perú, Chile, Argentina, Brasil o Paraguay. Una vez dentro del país, los visitantes pueden desplazarse en vuelos nacionales, buses interdepartamentales, vehículos privados o tours organizados. En zonas rurales o de alta montaña, algunos caminos pueden verse afectados por lluvias o nevadas, por lo que se recomienda planificar con anticipación y verificar siempre el estado de las rutas para disfrutar del viaje con seguridad.', 'custom', NULL, 'uploads/articles/article_20251104_014627_87aa5c4b5d0f.webp', 22, 'planning', NULL, '2025-10-21 19:00:22', '2025-11-04 06:46:30'),
(1069, NULL, NULL, 'Es hora de empezar a explorar...', NULL, NULL, NULL, 'custom', NULL, 'uploads/articles/article_20251105_175148_5db5a9a90eaf.webp', 20, 'where_to_go', NULL, '2025-10-22 16:55:18', '2025-11-05 22:51:49'),
(1070, NULL, NULL, 'Estos lugares para hospedarte en Bolivia ofrecen mucho más que solo un lugar para dormir', NULL, NULL, '¿Sueñas con escapar a una cabaña en los Andes o disfrutar de un retiro lujoso? Intenta planificar tu viaje alrededor de una de estas experiencias únicas de alojamiento.', 'custom', 'samuel', 'uploads/articles/article_20251104_021257_c7313f917157.webp', 21, 'where_to_go', NULL, '2025-10-22 17:15:29', '2025-11-04 07:12:59'),
(1071, NULL, NULL, 'Despierta tu curiosidad en un viaje por las ciudades de Bolivia', NULL, NULL, 'Experimenta la historia y cultura local más allá de las páginas de un libro, y descubre que las ciudades de cuento de hadas no son solo ficción.', 'custom', 'samiuel', 'uploads/articles/article_20251104_015820_7f9592cb3bc0.webp', 22, 'where_to_go', NULL, '2025-10-22 17:19:52', '2025-11-04 06:58:24'),
(1072, NULL, NULL, 'Buscas mas inpiracion?', 'Sigue recorriendo los diferentes lugares de Bolivia.', 'Sigue recorriendo los diferentes lugares de Bolivia.', '', 'custom', 'samuel', 'uploads/articles/article_20251104_021125_699005fe224f.webp', 23, 'where_to_go', NULL, '2025-10-22 17:27:30', '2025-11-04 07:11:28'),
(1073, NULL, NULL, 'Empieza a planificar', 'Usa nuestro mapa interactivo para encontrar destinos, descubrir nuevas actividades y diseñar un plan de viaje.', 'Usa nuestro mapa interactivo para encontrar destinos, descubrir nuevas actividades y diseñar un plan de viaje.', NULL, 'custom', 'samuel', 'uploads/articles/article_20251105_174808_5a85c1f83e85.webp', 28, 'where_to_go', '/mapa', '2025-10-22 17:42:05', '2025-11-05 22:48:09'),
(1074, NULL, NULL, 'Empieza a planificar', 'Usa nuestro mapa interactivo para encontrar destinos, descubrir nuevas actividades y diseñar un plan de viaje.', 'Usa nuestro mapa interactivo para encontrar destinos, descubrir nuevas actividades y diseñar un plan de viaje.', NULL, 'custom', 'samul', 'uploads/articles/article_20251105_174720_7025c381028b.webp', 26, 'where_to_go', NULL, '2025-10-22 17:52:00', '2025-11-05 22:47:25'),
(1075, NULL, NULL, 'Rutas sobre Ruedas', NULL, NULL, '¡Cuando la rueda gira, el ciclista se encuentra a sí mismo y con la naturaleza!\r\nEs una experiencia que siempre se disfruta más en persona, sintiendo el viento, los descensos y los ascensos, que cualquier foto o relato pueda transmitir.', 'custom', NULL, 'uploads/articles/article_20251104_020708_009655e712a3.webp', 21, 'what_to_do', '/actividades-biking', '2025-10-22 19:58:34', '2025-11-04 07:07:12'),
(1076, NULL, NULL, 'Escapadas para sanar', NULL, NULL, 'Nada se compara con la sensación de un baño caliente que libera al cuerpo del estrés y renueva el espíritu.', 'custom', NULL, 'uploads/articles/article_20251104_014216_99ee3dad1684.webp', 24, 'what_to_do', '/actividades-salud', '2025-10-22 20:06:39', '2025-11-04 06:42:21'),
(1077, NULL, NULL, 'Avistamiento de flora y fauna', NULL, NULL, 'Recorrer Bolivia es adentrarse en un mundo donde la vida se manifiesta en cada forma y color.', 'custom', NULL, 'uploads/articles/article_20251104_013702_36be30edac1b.webp', 25, 'what_to_do', '/actividades-avistamiento', '2025-10-22 20:16:21', '2025-11-04 06:37:04'),
(1078, NULL, NULL, 'Rutas 4x4', NULL, NULL, 'Explorar Bolivia en una ruta 4x4 es adentrarse en un territorio donde la geografía desafía y asombra.', 'custom', NULL, 'uploads/articles/article_20251104_020435_3c00a67cb77d.webp', 21, 'what_to_do', '/actividades-rutas4x4', '2025-10-22 20:20:39', '2025-11-04 07:04:36'),
(1079, NULL, NULL, '¡Caminar por Bolivia es más que aventura!', NULL, NULL, 'Recorrer Bolivia es contemplar amaneceres sobre los Andes, escuchar el susurro de los vientos en los valles como la calidez de sus llanos es descubrir que cada sendero conduce a un encuentro con uno mismo y con la esencia viva de la naturaleza.', 'custom', NULL, 'uploads/articles/article_20251104_020626_30f38876bf31.webp', 23, 'what_to_do', '/actividades-trekking', '2025-10-22 20:22:34', '2025-11-04 07:06:28'),
(1080, NULL, NULL, '¿Conquista la altura!', NULL, NULL, 'Ascender las montañas en Bolivia es un logro que está a la altura de sus cumbres: cada paso desafía al cuerpo, eleva el espíritu y regala la sensación incomparable de tocar el cielo con las manos.', 'custom', NULL, 'uploads/articles/article_20251104_013821_1b4063c811cd.webp', 23, 'what_to_do', '/actividades-montañismo', '2025-10-22 20:28:29', '2025-11-04 06:38:27'),
(1081, NULL, NULL, '¿Buscando qué hacer en tu viaje por Bolivia?', 'Bolivia es un país auténtico, donde cada paisaje cuenta su propia historia y ofrece escenarios inigualables que despiertan todos tus sentidos y permiten descubrir la diversidad que lo define. Aprovecha al máximo tu viaje, con estas imperdibles experiencia', 'Bolivia es un país auténtico, donde cada paisaje cuenta su propia historia y ofrece escenarios inigualables que despiertan todos tus sentidos y permiten descubrir la diversidad que lo define. Aprovecha al máximo tu viaje, con estas imperdibles experiencia', NULL, 'custom', NULL, 'uploads/articles/article_20251104_020555_e0d8268ec584.webp', 21, 'what_to_do', NULL, '2025-10-22 20:36:56', '2025-11-04 07:05:56'),
(1082, NULL, NULL, 'Aventura sobre dos ruedas', NULL, NULL, 'En Bolivia, cuando la rueda gira, uno se encuentra a sí mismo con la naturaleza, viviendo una experiencia que ningún relato o fotografía puede transmitir por completo. El viento en el rostro, los descensos vertiginosos y los ascensos desafiantes hacen que cada instante sea único. El biking ofrece múltiples posibilidades; puedes recorrer nuevos lugares a tu propio ritmo, disfrutando del paisaje y la conexión con la naturaleza, o participar en competencias intensas que llevan esta experiencia al máximo nivel.', 'custom', NULL, 'uploads/articles/article_20251104_020457_f49c812fb635.webp', 1, '/actividades-biking', NULL, '2025-10-22 20:44:36', '2025-11-04 07:04:57'),
(1083, NULL, NULL, 'Ciclismo entre abismos y espejos de sal', NULL, NULL, 'Bolivia es un paraíso para los aficionados al ciclismo, con una geografía que abarca regiones diversas y ofrece recorridos incomparables. Desde descensos extremos hasta la serenidad de paisajes infinitos, cada ruta convierte el ciclismo en una experiencia llena de emoción y aventura.', 'custom', NULL, 'uploads/articles/article_20251104_020527_aa9c4b6b3c22.webp', 1, 'home', NULL, '2025-10-22 20:48:58', '2025-11-04 07:05:30');
