INSERT INTO `categories` (`id`, `name`, `description`, `image_url`) VALUES
(1, 'Cultura y Patrimonio', 'Culturas que, a pesar del paso del tiempo, conservan la fuerza de sus raíces; sitios emblemáticos que susurran historias y evocan un pasado que sigue vivo en cada piedra y en cada memoria.', 'uploads/categories/article_20251103_122221_c83c52f9e01f.webp'),
(2, 'Naturaleza', 'Viajar por Bolivia es descubrir un destino donde la naturaleza no es solo un escenario, sino la verdadera protagonista.', 'uploads/categories/article_20251104_160840_beacc4e7d8ea.webp'),
(3, 'Gastronomía', 'La gastronomía boliviana es un viaje por los sentidos y por la memoria, una experiencia que une montañas, valles, selvas y llanuras en un solo plato. ', 'uploads/categories/article_20251104_160949_52ac541d0b02.webp'),
(4, 'Festividades', 'Vive el folklore de Bolivia y deja que cada danza te cuente su historia.', 'https://eeao2nst5vu.exactdn.com/wp-content/uploads/2010/10/Carnaval-de-Oruro-en-Bolivia.jpg');
INSERT INTO `departments` (`id`, `name`, `description`, `image_url`, `created_at`) VALUES
(1, 'Chuquisaca', 'Capital: Sucre. Conocida como la \"Cuna de la Libertad\", sede de la primera declaración de independencia de Bolivia. Ideal para turismo histórico y cultural.', 'https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcT5V67oCfiR8FLCNC_Z9J9F9kTs-fc5s9j2_w&s', '2025-09-09 03:34:55'),
(2, 'La Paz', 'Capital administrativa del país. Destaca por su geografía vertical, teleféricos, y acceso a los Yungas y el Altiplano. Centro político y cultural.', 'https://upload.wikimedia.org/wikipedia/commons/c/c7/Basilica_de_San_Francisco_La_Paz.jpg', '2025-09-09 03:34:55'),
(3, 'Cochabamba', 'Corazón de Bolivia. Famosa por su gastronomía, clima templado y valles fértiles. Puerta de entrada al trópico y a las montañas de los valles.', 'https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcS3USGiGtT9_rncf013dyw9c6MWL3p3pYD84g&s', '2025-09-09 03:34:55'),
(4, 'Oruro', 'Tierra del Carnaval más grande de Bolivia, patrimonio de la UNESCO. Zona minera y con fuerte identidad andina y religiosa.', 'https://upload.wikimedia.org/wikipedia/commons/7/7b/Oruro..jpg', '2025-09-09 03:34:55'),
(5, 'Potosí', 'Hogar del Cerro Rico, una de las mayores reservas de plata de la historia. Ciudad colonial impresionante y Patrimonio de la Humanidad.', 'https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcQKjv2pGfjuE0RTseCQZ9AJyivmOaY3XQ1wLA&s', '2025-09-09 03:34:55'),
(6, 'Santa Cruz', 'Motor económico del país. Clima tropical, selva, llanuras y una gastronomía vibrante. Puerta de entrada al Oriente boliviano.', 'https://upload.wikimedia.org/wikipedia/commons/thumb/a/a5/Barrio_de_Equipetrol.jpg/1200px-Barrio_de_Equipetrol.jpg', '2025-09-09 03:34:55'),
(7, 'Beni', 'Región amazónica con ríos, sabanas y vida silvestre. Ideal para ecoturismo, avistamiento de delfines rosados y comunidades indígenas.', 'https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcT-Pj-zbUS6V2hBSxnGQ0oRB2VWs93jT1HkYqwrH8O4JjynDwO8S9ESNMxPAXF38KjjLrk&usqp=CAU', '2025-09-09 03:34:55'),
(8, 'Pando', 'El departamento más norteño y selvático. Conocido por su producción de castaña y comunidades remotas. Acceso a la Amazonía profunda.', 'https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcTqtGrS30m5eo0AhqJ0Vzknx4zIyhPFqgs2SQ&s', '2025-09-09 03:34:55'),
(9, 'Tarija', 'Región del vino y el singani. Clima agradable, arquitectura colonial y fiestas tradicionales. Ideal para turismo enológico y cultural.', 'https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcQhN9rv8yTe4OJIsi8vtozHj8PdmxkCQcoJ9g&s', '2025-09-09 03:34:55');
INSERT INTO `locations` (`id`, `user_id`, `name`, `description`, `latitude`, `longitude`, `address`, `opening_hours`, `contact_info`, `type`, `department_id`, `badge`, `room_type`, `price_per_night`, `start_date`, `end_date`, `event_type`, `capacity`, `is_recurring`, `facebook`, `instagram`, `whatsapp`, `link`, `created_at`, `updated_at`) VALUES
(1, 1, 'Salar de Uyuni', 'El Salar de Uyuni es el lugar donde la naturaleza se expresa con una grandeza que sobrepasa la imaginación. Con más de 10.000 km² de extensión, este inmenso desierto blanco es considerado el mayor espejo natural de la Tierra, un escenario que transforma el horizonte en un lienzo infinito donde el cielo y la tierra se funden en un mismo reflejo. \n Las figuras poligonales que se dibujan sobre su superficie parecen trazos de un artista. En época de lluvias, una delgada capa de agua convierte al salar en el gigantesco espejo. Pero más allá de su belleza, el Salar guarda historias y leyendas. La más conocida, es la de la diosa Tunupa, cuenta que su llanto dio origen a este mar de sal, convirtiéndolo no solo en un lugar de paisajes sobrecogedores, sino también en un territorio lleno de memoria. \n Visitar el Salar de Uyuni es contemplar la inmensidad del planeta y al mismo tiempo conectarse con la esencia de Bolivia.', -20.133333330000000, -67.500000000000000, '', '', '', 'attraction', 5, '', NULL, NULL, NULL, NULL, 'other', NULL, 0, NULL, NULL, NULL, NULL, '2025-10-06 19:28:24', '2025-11-25 20:49:50'),
(2, 1, 'Laguna Colorada', 'Parte de la Reserva Nacional de Fauna Andina Eduardo Avaroa, las Lagunas de Colores despliegan un espectáculo natural de tonalidades únicas. Cada una ofrece una combinación distinta de matices: rojos, verdes, turquesas y blancos que contrastan con el silencio del paisaje andino.\nLa Laguna Colorada sorprende con sus aguas rojizas pobladas de flamencos, mientras la Laguna Verde refleja los tonos minerales del entorno y los microorganismos que habitan en ellas.\nUn recorrido por estas lagunas es contemplar la fuerza de la naturaleza \n\nVisitar este destino es contemplar la fuerza de la naturaleza y descubrir la magia que habita en los colores del altiplano.', -22.416666670000000, -67.666666670000000, '', '', '', 'attraction', 5, '', NULL, NULL, NULL, NULL, 'other', NULL, 0, NULL, NULL, NULL, NULL, '2025-10-06 19:28:24', '2025-11-06 00:26:16'),
(3, 1, 'La Paz', 'La Paz, es el corazón político y administrativo del país. Desde su altitud imponente, resguarda los principales órganos del poder estatal, convirtiéndose en el centro donde se toman las decisiones que marcan el rumbo de la nación. \n En sus calles conviven la historia y la modernidad. El Palacio Quemado y la Casa Grande del Pueblo se convierten en símbolo del poder ejecutivo del ayer y hoy. \n Más allá de lo político, La Paz representa un punto de encuentro para las distintas culturas y pensamientos de Bolivia, reflejando en su dinámica y cotidianeidad urbana la diversidad del país, y en ese equilibrio late el motor institucional del Estado boliviano.', -16.495732000000000, -68.133567000000000, '', '', '', 'city', 2, '', NULL, NULL, NULL, NULL, 'other', NULL, 0, 'https://www.facebook.com/MunicipioLaPaz', NULL, NULL, 'https://lapaz.bo/?s=TURISMO', '2025-10-06 19:28:24', '2025-11-25 20:52:58'),
(4, 1, 'Santa Cruz de la Sierra', 'Santa Cruz de la Sierra se levanta como el corazón moderno del oriente boliviano. Ciudad de ritmo vibrante, en sus calles se respira optimismo y hospitalidad, rasgos que hacen de Santa Cruz un lugar donde cada encuentro se convierte en una celebración de vida. En cada rincón, la ciudad se saborea: su gastronomía camba, con platos emblemáticos como el majadito, el locro y la yuca con queso, refleja la calidez y el sabor auténtico de su gente. \n Santa Cruz de la Sierra es, ante todo, una ciudad que inspira; moderna, alegre y acogedora, donde el progreso convive con la naturaleza y la alegría se convierte en su mejor bienvenida.', -17.786289000000000, -63.177856000000000, '', '', '', 'city', 6, '', NULL, NULL, NULL, NULL, 'other', NULL, 0, NULL, NULL, NULL, NULL, '2025-10-06 19:28:24', '2025-11-25 20:48:36'),
(5, 1, 'Lago Titicaca', 'El Lago Titicaca, elevado a 3.812 metros sobre el nivel del mar, es el lago navegable más alto del mundo, un espejo sagrado. En sus aguas reposan la Isla del Sol y la Isla de la Luna, lugares míticos donde, según la tradición, emergieron el Sol y la Luna para dar vida al mundo. Entre templos antiguos, terrazas agrícolas y miradores naturales, el lago invita a contemplar el origen mismo de los Andes, en un escenario donde el cielo parece tocar la tierra.', -16.000000000000000, -69.000000000000000, '', '', '', 'attraction', 2, '', NULL, NULL, NULL, NULL, 'other', NULL, 0, NULL, NULL, NULL, NULL, '2025-10-06 19:28:24', '2025-11-25 20:49:17'),
(6, 1, 'Samaipata', 'Samaipata, en el corazón de Santa Cruz, ha ganado renombre mundial gracias al Fuerte de Samaipata, declarado Patrimonio de la Humanidad por la UNESCO en 1998. Este sitio preincaico, con grabados en roca, construcciones ceremoniales y vestigios de antiguas culturas, refleja los conocimientos astronómicos, religiosos y culturales de las sociedades precolombinas, convirtiéndolo en un legado de la historia boliviana. \n El entorno natural de Samaipata es igualmente excepcional. Sus valles, bosques y cascadas, junto con la cercanía al Parque Nacional Amboró, ofrecen un escenario para el ecoturismo y las actividades al aire libre, donde la biodiversidad y la naturaleza se muestran en todo su esplendor. \n El pueblo, con su ambiente tranquilo y acogedor, conserva un encanto colonial que se percibe en sus calles empedradas y su arquitectura tradicional, invitando a los visitantes a recorrerlo despacio y disfrutar de la armonía entre historia, cultura y naturaleza.', -18.166666670000000, -63.833333330000000, '', '', '', 'attraction', 6, '', NULL, NULL, NULL, NULL, 'other', NULL, 0, 'https://www.facebook.com/elfuertedesamaipata', NULL, NULL, NULL, '2025-10-06 19:28:24', '2025-11-25 20:51:11'),
(7, 1, 'Sucre', 'Sucre, ciudad que encarna libertad y memoria. Escenario de los acontecimientos históricos, fue protagonista esencial en el proceso que condujo a la independencia. Un 25 de mayo de 1809 sus campañas marcaron el inicio del primer grito revolucionario en el continente, un eco que trascendió fronteras y encendió la chispa de la independencia en toda América. \n En la Universidad Mayor Real y Pontificia de San Francisco Xavier de Chuquisaca germinaron las ideas de libertad, que más tarde cambiarían el destino de un país entero. Desde la Real Audiencia de Charcas, Sucre alzó su voz jurídica y política, forjando los cimientos de la República y su destino de libertad. \n Así, Sucre no solo fue escenario de los hechos, sino protagonista indiscutible en el camino hacia la independencia. Por todo ello, Sucre fue reconocida como la Capital de Bolivia. Título, respaldado por su historia y por los lauros de libertad. \n Recorrer sus calles, plazas y edificaciones coloniales es revivir el origen de la nación. En Sucre nació Bolivia, y en su espíritu perdura la esencia de la patria.', -19.033333330000000, -65.266666670000000, 'Sucre, Bolivia', '', '800-13-2505', 'city', 1, '', NULL, NULL, NULL, NULL, 'other', NULL, 0, 'https://www.facebook.com/MunicipiodeSucreBolivia/', NULL, NULL, 'https://sucre.bo/?fbclid=IwY2xjawN2GmJleHRuA2FlbQIxMABicmlkETFFSkxVRE55QzIxUUJ3QnFIAR4O_Mt6xX5Ahy4OmW6QY_AoEGFhov2OWoYcHAfKPqpjJNsEy61-fbly9dAyzw_aem_hvRNMk5wQMajxV4J2BBc_A', '2025-10-06 19:28:24', '2025-11-25 20:50:55'),
(8, 1, 'Torotoro', 'Torotoro, esculpido por el tiempo en el norte potosino, es el lugar donde la tierra parece haber nacido. Entre cañones, cavernas profundas y formaciones pétreas que desafían los siglos, el paisaje revela la memoria geológica del mundo. \n En sus suelos quedaron grabadas las huellas de dinosaurios que alguna vez caminaron bajo el mismo cielo. \n Una verdadera aventura de espeleología espera en la caverna más profunda de Bolivia, Umajalanta, en su interior se forman estalactitas y estalagmitas milenarias. Es una experiencia emocionante que explora un mundo perdido en las profundidades.\n La piedra se transforma en arte en la Ciudad de Itas, y el agua renace en El Vergel, donde cascadas y vegetación irrumpen entre la aridez del cañón. \n Torotoro es un santuario del tiempo, donde la historia moldeó la piedra y hoy sus formas nos invitan a contemplar el pasado.', -18.133897613237000, -65.763095413298000, '', '', '', 'attraction', 5, '', NULL, NULL, NULL, NULL, 'other', NULL, 0, 'https://www.facebook.com/torotoropark', NULL, NULL, NULL, '2025-10-06 19:28:24', '2025-11-25 20:51:45'),
(9, 1, 'Parque Nacional Sajama – Curahuara de  Carangas', 'En el altiplano de Oruro se levanta el Parque Nacional Sajama, la primera área protegida de Bolivia, creada para resguardar los bosques de queñua más altos del mundo y la vida que habita entre las cumbres. Entre géiseres humeantes, lagunas de altura y el majestuoso Nevado Sajama, que con sus 6.542 metros toca el cielo, el paisaje revela la fuerza del altiplano andino. \n El Sajama también es territorio de memoria y cultura en donde sus pueblos mantienen un vínculo profundo con la montaña, el pastoreo y los rituales El Sajama es un encuentro entre montaña, cielo y cultura.', -17.983333330000000, -67.150000000000000, '', '', '', 'attraction', 4, '', NULL, NULL, NULL, NULL, 'other', NULL, 0, NULL, NULL, NULL, NULL, '2025-10-06 19:28:24', '2025-11-25 20:52:16'),
(10, 1, 'Rurrenabaque', 'Rurrenabaque, puerta de entrada al Parque Nacional Madidi y a las Pampas del Yacuma, es el punto donde la Amazonía boliviana revela toda su magia. Desde sus ríos y bosques, este destino ofrece una conexión íntima con la naturaleza. Los jaguares, guacamayos, delfines rosados y monos capuchinos habitan entre los reflejos del agua y la espesura verde. \n Navegar por el Madidi es vivir la selva en su estado más puro, donde cada amanecer trae el canto de las aves y cada atardecer se funde con los tonos dorados del día que termina. \n ¡Una puerta abierta al corazón verde de Bolivia!', -14.433333330000000, -67.566666670000000, '', '', '', 'city', 7, '', NULL, NULL, NULL, NULL, 'other', NULL, 0, NULL, NULL, NULL, NULL, '2025-10-06 19:28:24', '2025-11-25 20:51:26'),
(12, 1, 'Misiones Jesuíticas de la Chiquitania', 'Las Misiones Jesuíticas, declaradas Patrimonio Cultural de la Humanidad por la UNESCO, son vestigios vivos de un pasado compartido por los Jesuitas en los territorios de Bolivia, Paraguay y Argentina. Estos asentamientos transformaron la vida de los pueblos indígenas, guiándolos en la doctrina cristiana y creando espacios donde la educación, el arte y la música florecieron como testigos del ingenio. \n Sus iglesias y plazas, de estilo barroco con detalles locales, conservan la armonía entre arte y arquitectura, mientras coros y orquestas siguen resonando en la memoria de sus calles, y sus fachadas narran la fusión de influencias europeas e indígenas. \n Recorrerlas es viajar en el tiempo, adentrarse en un lugar donde cada piedra, cada altar y cada sonido aún vibran con la historia y la vida de quienes las habitaron.', -16.000000000000000, -62.500000000000000, '', '', '', 'attraction', 6, '', NULL, NULL, NULL, NULL, 'other', NULL, 0, NULL, NULL, NULL, 'https://misionesjesuiticas.com/concepcion/bienvenidos/', '2025-10-06 19:28:24', '2025-11-25 20:48:14'),
(13, 1, 'Yungas – Camino de la Muerte', 'El Camino de la Muerte, uno de los más desafiantes y emblemáticos del mundo, se adentra en los Yungas entre abismos cubiertos de neblina, cascadas que tocan la carretera y montañas vestidas de verde. \n Hoy, este antiguo paso que unía las tierras altas con las regiones tropicales se ha transformado en una ruta de aventura donde viajeros de todo el mundo descienden en bicicleta, desafiando sus curvas vertiginosas y el vértigo del precipicio. Solo los más valientes se atreven a recorrerlo… para al final poder decir con orgullo: “Yo sobreviví al Camino de la Muerte.”', -16.250000000000000, -67.833333330000000, '', '', '', 'attraction', 2, '', NULL, NULL, NULL, NULL, 'other', NULL, 0, NULL, NULL, NULL, NULL, '2025-10-06 19:28:24', '2025-11-25 20:50:05'),
(14, 1, 'Gran Chaco Boliviano', 'El Gran Chaco boliviano se encuentra al Sur del país, y entre sus llanuras se erigen los municipios de Yacuiba, Villamontes y Caraparí, guardianes de la vida y la cultura de los Guaraníes y Ayoreos, pueblos que sostienen tradiciones que atraviesan generaciones como hilos invisibles del tiempo. \n Este territorio conserva también la memoria de épocas de tensión y fronteras disputadas, cuando las sombras de los conflictos entre Bolivia y Paraguay marcaron el siglo XX. \n Hoy el Gran Chaco es un lugar donde la inmensidad de la llanura y la fuerza de su gente se funden en un paisaje que habla de historia, resistencia y vida.', -21.260188671141000, -63.475431675489000, '', '', '', 'attraction', 9, '', NULL, NULL, NULL, NULL, 'other', NULL, 0, NULL, NULL, NULL, NULL, '2025-10-06 19:28:24', '2025-12-02 22:52:25'),
(15, 1, 'Ruta del Vino y el Singani de altura', 'La Ruta del Vino y del Singani de Altura se despliega entre los valles del sur de Bolivia, donde los viñedos se elevan entre 1.800 y 2.300 metros sobre el nivel del mar, tocando el cielo con sus hojas y racimos bañados por el sol. \n Bajo el sol intenso de los valles altos, cada uva madura con fuerza, guardando en su esencia sabores y fragancias, y el clima seco y soleado intensifica la fragancia pura del singani, destilado emblemático de Bolivia. Entre bodegas y destilerías artesanales, cada visita guiada y degustación desvela el arte de transformar la uva en vino y en singani, invitando a contemplar, saborear y celebrar la riqueza del sur boliviano.', -21.500000000000000, -64.750000000000000, '', '', '', 'attraction', 9, '', NULL, NULL, NULL, NULL, 'other', NULL, 0, 'https://www.facebook.com/SDEPTarija', 'https://www.instagram.com/desarrolloproductivo_gamt', NULL, 'https://tarijaturismo.com/', '2025-10-06 19:28:24', '2025-11-25 20:49:35'),
(16, 1, 'Potosí', 'Potosí, elevada a más de 4.000 metros sobre el nivel del mar, fue en tiempos coloniales una de las ciudades más prósperas y admiradas del mundo. Su nombre resonó en todos los continentes gracias al Sumaj Orcko, el majestuoso Cerro Rico, montaña que durante siglos proveyó la plata que alimentó al mundo y marcó la historia económica de la humanidad. \n En el corazón de la ciudad, la imponente Casa de la Moneda se erige como testimonio de aquella grandeza. Entre sus muros se acuñó la riqueza que dio fama universal a Potosí y que aún hoy evoca el esplendor de una época irrepetible. \n Declarada Patrimonio Cultural de la Humanidad por la UNESCO, Potosí conserva su espíritu histórico en cada calle empedrada, en sus templos barrocos y en sus casonas coloniales. Sobre todo, el Cerro Rico aún recuerda al mundo que en esta tierra se forjó parte de la historia de la humanidad.', -19.583333330000000, -65.750000000000000, '', '', '', 'city', 5, '', NULL, NULL, NULL, NULL, 'other', NULL, 0, NULL, NULL, NULL, NULL, '2025-10-06 19:28:24', '2025-11-25 20:47:55'),
(17, 1, 'Cochabamba', 'Cochabamba, ubicada en el corazón de Bolivia, se extiende en un valle fértil rodeado de montañas y por un clima templado que acompaña casi todo el año. Su entorno hospitalario la convierte en un destino que invita a quedarse, a disfrutar de su ritmo sereno y de su calidez humana. \nReconocida como la capital gastronómica de Bolivia, Cochabamba celebra su identidad a través de los sabores. Cada plato cuenta una historia del valle, la abundancia de sus productos se combina con la creatividad de su gente y la herencia culinaria. \nComer en Cochabamba es descubrir un universo de sabores reflejados en cada sazón.', -17.383333330000000, -66.150000000000000, '', '', '', 'city', 3, '', NULL, NULL, NULL, NULL, 'other', NULL, 0, 'https://www.facebook.com/gamcochabamba', NULL, NULL, 'https://www.cochabamba.bo/?fbclid=IwY2xjawN2HgZleHRuA2FlbQIxMABicmlkETFwZGs4VURMRjN6a0piOEl3AR5YUXXotEoMie_VR9s3KFeTMqDzTPDwXUGTukwgBVB6DN3tvh4JoMtrjSXRRg_aem_C5qoqThw5PY2m6dRD7rXGQ', '2025-10-06 19:28:24', '2025-11-25 20:46:52'),
(18, 1, 'Triángulo Amazónico', 'La fauna y flora únicas del Beni se convierten en protagonistas: aves de colores intensos surcan los cielos, mientras peces y mamíferos habitan sus aguas y selvas, dando vida a cada paisaje.\n\nVisitar el Triángulo Amazónico es adentrarse en un mundo donde la naturaleza marca el ritmo de la vida y cada instante revela la riqueza y la magia de la Amazonía boliviana.', -11.000000000000000, -69.000000000000000, '', '', '', 'attraction', 7, '', NULL, NULL, NULL, NULL, 'other', NULL, 0, NULL, NULL, NULL, NULL, '2025-10-06 19:28:24', '2025-11-04 05:07:26'),
(19, 1, 'Norte Amazónico', 'Pando, puerta amazónica de Bolivia, es un territorio joven donde la selva, los ríos y la hospitalidad de su gente se entrelazan en armonía. Creado en 1938, es el departamento más joven del país, y en su geografía fronteriza con Brasil y Perú la convierte en un punto de encuentro comercial y cultural Su capital, Cobija, se alza a orillas del río Acre, envuelta en el verdor de la selva tropical. Ciudad cálida y acogedora, conserva la memoria del auge gomero, visible en sus antiguas casonas y en la historia de su gente, mientras avanza hacia un futuro moderno y sostenible. Es una invitación a sentir la Amazonía boliviana en toda su plenitud. Quien lo visita descubre un territorio donde la biodiversidad, los ríos infinitos y la calidez humana reflejan la esencia verde y vital de Bolivia.', -13.000000000000000, -66.000000000000000, '', '', '', 'attraction', 8, '', NULL, NULL, NULL, NULL, 'other', NULL, 0, NULL, NULL, NULL, NULL, '2025-10-06 19:28:24', '2025-11-25 20:47:36'),
(20, 1, 'Pantanal Boliviano', 'El Pantanal boliviano, el humedal de agua dulce más grande del mundo, se extiende en el sureste del departamento de Santa Cruz como un refugio de vida y biodiversidad. Cada rincón de sus aguas y llanuras es hogar de especies que sorprenden por su abundancia y variedad. \n \n El ingreso al Pantanal se realiza principalmente desde Puerto Suárez, punto de partida para explorar sus ríos y lagunas, donde los recorridos ofrecen encuentros cercanos con la fauna local. La observación de aves, por su parte, se convierte en un espectáculo que cambia con las estaciones. Así, cada paseo se transforma en un viaje de contemplación y conexión con uno de los ecosistemas más extraordinarios de Bolivia.', -19.004527543837000, -57.715547116030000, '', '', '', 'attraction', 6, '', NULL, NULL, NULL, NULL, 'other', NULL, 0, NULL, NULL, NULL, NULL, '2025-10-06 19:28:24', '2025-12-02 22:38:04'),
(21, 1, 'Casa de la Libertad', 'Museo Histórico Nacional y escenario de la firma del Acta de Independencia de Bolivia (1825). La visita recorre salas emblemáticas - Sala Virreinal, Sala de la Independencia, Sala de Guerrilleros, Sala de Deliberantes y la Galería de presidentes - donde se conservan documentos, retratos y objetos que narran el tránsito de la colonia a la República. El museo cuenta además con Biblioteca y Archivo para consulta especializada. Un lugar imprescindible para comprender el origen de la nación y el papel de la ciudad de Sucre en la historia boliviana.', -19.047437819540360, -65.260186560240940, 'Plaza 25 de mayo #1', 'LUNES A VIERNES: 8:30-16:30; SABADO DOMINGO: 9:00-13:00', NULL, 'museum', 1, NULL, NULL, NULL, NULL, NULL, 'other', NULL, 0, 'https://www.facebook.com/museocasadelalibertad/?locale=es_LA', NULL, NULL, 'https://casadelalibertad.org.bo/', '2025-10-06 23:13:36', '2025-10-06 23:13:36'),
(22, 1, 'Museo Nacional de Etnografía y Folklore (MUSEF)', 'El Museo Nacional de Etnografía y Folklore (MUSEF) - Sucre presenta la diversidad cultural de Bolivia mediante salas con piezas de pueblos originarios, fotografías, mapas y objetos en cuero, madera, cerámica y textiles; además cuenta con una videoteca que refleja los legados de danzas, etnias, historia, pintura y arquitectura de Bolivia', -16.494510323433000, -68.134987714162000, 'Calle IngavI N° 906', 'LUNES A VIERNES: 8:00-16:15; DOMINGOS: 9:00-16:15', '', 'museum', 2, '', NULL, NULL, NULL, NULL, 'other', NULL, 0, 'https://www.facebook.com/musef.lapaz.bolivia', NULL, NULL, 'http://musef.gob.bo/?fbclid=IwY2xjawN3COVleHRuA2FlbQIxMABicmlkETEzUEZjV1ZyNWRpNk9iVFREAR61ay_ke_SAyZHFD0oUzIAhXe_vbEXflv9SWA-iXS_4J6xQHqU85laHsPX69A_aem_qWOl4uF485a4704-SVAKDA', '2025-10-06 23:13:36', '2025-11-06 01:40:58'),
(23, 1, 'Museo Convento de la Recoleta', 'Fundado en 1600 por Fray Francisco de Morales como Convento de Nuestra Señora de Santa Ana del Monte Sión, la Recolección de Chuquisaca fue uno de los principales conjuntos conventuales de la Provincia de los Charcas. La iglesia -reconstruida en el siglo XIX- presenta una sola nave con capilla lateral y una fachada de pórtico con pilastras coronadas por frontón triangular, flanqueada por dos torres. En el interior destacan cuatro altares menores de estilo gótico de ese siglo. El altar mayor conserva su espacio sin retablo, lo que realza la singular sillería del coro, tallada en cedro en el siglo XVII y atribuida a la escuela alto-peruana; esta pieza fue trasladada en 1875 desde la iglesia de San Francisco. El museo funciona en ambientes del tercer claustro -de los cuatro que conforman el conjunto- e incluye el \"Patio de los Naranjos\". Sus salas exhiben pinturas, esculturas, obras religiosas y una valiosa colección numismática de la Colonia y la República. El patrimonio bibliográfico se resguarda en una suntuosa biblioteca con alrededor de 20.000 títulos de temática diversa. En la antigua huerta aún permanece un cedro milenario, testigo vivo de la historia del convento.', -19.054704598356466, -65.253709010601640, 'Calle Polanco #162', 'LUNES A VIERNES: 9:00-11:30 y 14:30-16:00; SABADOS: 9:00-11:30', NULL, 'museum', 1, NULL, NULL, NULL, NULL, NULL, 'other', NULL, 0, NULL, NULL, NULL, NULL, '2025-10-06 23:13:36', '2025-10-06 23:13:36'),
(24, 1, 'Museo del Convento de Santa Clara', 'Fundado el 16 de enero de 1636, este monasterio de clausura de las Hermanas Clarisas nació gracias a la iniciativa de doña María de Zeballos y Vera, viuda de Jerónimo Maldonado de Buendía, con apoyo de doña María Mogollón de Ribera. Su creación marcó un hito espiritual y cultural en la entonces ciudad de La Plata (hoy Sucre). El conjunto conserva el carácter sereno de sus claustros y patios, con arquerías sobre columnas de piedra trabajada, y continúa albergando la comunidad religiosa de las hermanas Clarisas. Parte de sus ambientes funcionan como museo, donde se exhiben arte sacro colonial, muebles, platería, joyas, objetos litúrgicos e instrumentos musicales. Destacan pinturas atribuidas a maestros del periodo virreinal y un órgano del siglo XVII restaurado, empleado en conciertos de música barroca.', -19.049660773110507, -65.256423812992130, 'Calle Calvo #138', 'LUNES A VIERNES: 8:00-12:00 y 14:30-17:00', NULL, 'museum', 1, NULL, NULL, NULL, NULL, NULL, 'other', NULL, 0, NULL, NULL, NULL, NULL, '2025-10-06 23:13:36', '2025-10-06 23:13:36'),
(25, 1, 'Museo de la Catedral', 'El Museo de la Catedral de Sucre, es uno de los museos de arte sacro más importantes de Bolivia. Alberga una valiosa colección de objetos litúrgicos, pinturas, esculturas, orfebrería y textiles que datan desde el siglo XVI hasta el XIX, reflejando el legado histórico religioso de la antigua Villa de la Plata.', -19.049003327267080, -65.259866673132380, 'Calle Nicolas Ortiz #61', 'LUNES A VIERNES: 9:00-12:00 y 15:30-18:30; SABADOS: 15:00-18:30', NULL, 'museum', 1, NULL, NULL, NULL, NULL, NULL, 'other', NULL, 0, 'https://www.facebook.com/p/Museo-de-la-Catedral-de-Sucre-100093684937702/', NULL, NULL, NULL, '2025-10-06 23:13:36', '2025-10-06 23:13:36'),
(26, 1, 'Museo - Monasterio y Templo de Santa Teresa', 'El Museo Monasterio y Templo de Santa Teresa de Sucre es un conjunto patrimonial fundado en 1665 por el arzobispo Gaspar de Villarroel para la orden de las Carmelitas Descalzas. El recorrido invita a conocer ambientes que revelan la vida austera, espiritual y de trabajo de las religiosas, junto con una valiosa colección de pintura colonial, objetos de devoción y elementos de tradición. El convento sigue habitado: las monjas elaboran hostias, repostería, vinos y mermeladas, preservando oficios y sabores que mantienen viva la herencia colonial.', -19.048429733835775, -65.254509085896770, 'Calle Final Potosí #199', 'LUNES A VIERNES: 9:00-12:00 y 14:30-18:00; SABADOS: 14:30-18:00', NULL, 'museum', 1, NULL, NULL, NULL, NULL, NULL, 'other', NULL, 0, 'https://www.facebook.com/p/Museo-Convento-de-Santa-Teresa-de-Sucre-100063668376017/', NULL, NULL, NULL, '2025-10-06 23:13:36', '2025-10-06 23:13:36'),
(27, 1, 'Museo Universitario Colonial Charcas', 'El Museo Universitario Colonial \"Charcas\" resguarda un notable patrimonio de estilos de pintura (manierismo y barroco), pintura mestiza de escuelas virreinales, orfebrería en plata, escultura y mobiliario de los siglos XVII-XIX; además exhibe arte del siglo XX de maestros bolivianos y extranjeros. Su sede fue adquirida el 27 de mayo de 1939 por el Ateneo de Bellas Artes y, desde 1957, pertenece a la Universidad San Francisco Xavier; Su edificación es considerado monumento arquitectónico de gran importancia en la ciudad de Sucre', -19.050208621807315, -65.259146834724490, 'Calle Bolívar #698', 'LUNES A VIERNES: 9:00-12:30 y 14:30-18:15; SABADOS: 9:00-12:45', NULL, 'museum', 1, NULL, NULL, NULL, NULL, NULL, 'other', NULL, 0, 'https://www.facebook.com/museocolonialcharcas', NULL, NULL, 'https://culturaydeporte.usfx.bo/project/museo-colonial-charcas/', '2025-10-06 23:13:36', '2025-10-06 23:13:36'),
(28, 1, 'Museo Antropológico', 'El Museo Antropológico centra su exhibición en un acopio de restos antropológicos y arqueológicos del departamento de Chuquisaca; presenta una colección que abarca desde hace 3.600 años organizados cronológicamente y tipológicamente para enseñar y entender sobre el pasado prehispánico del territorio.', -19.050208621807315, -65.259146834724490, 'Calle Bolívar #698', 'LUNES A VIERNES: 9:00-12:30 y 14:30-18:15; SABADOS: 9:00-12:45', NULL, 'museum', 1, NULL, NULL, NULL, NULL, NULL, 'other', NULL, 0, NULL, NULL, NULL, 'https://culturaydeporte.usfx.bo/antropologico/', '2025-10-06 23:13:36', '2025-10-06 23:13:36'),
(29, 1, 'Museo de Historia Natural', 'El Museo Universitario de Historia Natural de Sucre es un espacio dedicado a la exhibición de colecciones taxidermizadas de aves y mamíferos, además de muestras paleontológicas, botánicas y de biodiversidad regional.', -19.159647611576577, -65.266129787608210, 'Villa de Yotala', 'LUNES A VIERNES: 8:00-15:00', NULL, 'museum', 1, NULL, NULL, NULL, NULL, NULL, 'other', NULL, 0, 'https://www.facebook.com/p/Museo-Universitario-de-Historia-Natural-Sucre-Bolivia-100063053299078/', NULL, NULL, NULL, '2025-10-06 23:13:36', '2025-10-06 23:13:36'),
(30, 1, 'Museo de Arte Indígena Asur', 'El museo Asur es imprescindible para quienes aman las culturas ancestrales de los alrededores de Sucre revela el arte textil vivo de las regiones Jalq\'a y Tarabuco. Reúne un amplio repertorio de tejidos: composiciones densas y simbología del \"más allá\" de la cultura jalq\'a; como también escenas de vida comunitaria y diseño figurativas representados en la cultura yamparas', -19.053795902978305, -65.253886675344100, 'Calle Iturricha #34', 'LUNES A VIERNES: 9:00-12:15 y 14:30-18:00; SABADO: 9:00-12:00 y 14:30-18:00', NULL, 'museum', 1, NULL, NULL, NULL, NULL, NULL, 'other', NULL, 0, 'https://www.facebook.com/museo.asur/?locale=es_LA', NULL, NULL, NULL, '2025-10-06 23:13:36', '2025-10-06 23:13:36'),
(31, 1, 'Museo del Chocolate', 'El Museo del Chocolate de Sucre expone un recorrido didáctico desde la obtención del cacao como materia prima hasta el producto final, permitiendo apreciar cada etapa y el oficio chocolatero que distingue a la ciudad dentro su tradición gastronómica que posee.', -19.053795902978305, -65.253886675344100, 'Calle Inca Garcilazo de la Vega #34', 'LUNES A SABADO: visitas a las 8:30, 9:15, 10:00, 10:45, 11:30 y 12:15', NULL, 'museum', 1, NULL, NULL, NULL, NULL, NULL, 'other', NULL, 0, 'https://www.facebook.com/museo.asur/?locale=es_LA', NULL, NULL, NULL, '2025-10-06 23:13:36', '2025-10-06 23:13:36'),
(32, 1, 'Museo del Tesoro', 'El Museo del Tesoro de Sucre exhibe técnicas tradicionales de orfebrería y joyas elaboradas con metales y piedras preciosas de Bolivia. El museo hace gala de los secretos primarios, las técnicas magistrales y la brillantez artística de estos materiales, entender el oficio joyero y llevarte una mirada distinta sobre la riqueza material del país.', -19.046921243357925, -65.259483048599210, 'Plaza 25 de mayo #59', 'LUNES A DOMINGO: 9:00-12:30 y 15:00-18:30', NULL, 'museum', 1, NULL, NULL, NULL, NULL, NULL, 'other', NULL, 0, 'https://www.facebook.com/Museo.del.Tesoro.Sucre', NULL, NULL, 'https://museotesoro.com/', '2025-10-06 23:13:36', '2025-10-06 23:13:36'),
(33, 1, 'Museo Histórico Militar del Estado', 'El Museo Histórico Militar Mariscal Antonio José de Sucre, es un espacio para comprender la valentía y la historia militar de Bolivia, desde la independencia hasta tiempos recientes. reúne espacios dedicados a las tres fuerzas de Bolivia -Ejército, Armada Boliviana y Fuerza Aérea- con colecciones que recorren la historia militar del país.', -19.045895147617763, -65.259114790020480, 'Calle Ravelo #1', 'LUNES A VIERNES: 8:00-12:00 y 14:00-16:00', NULL, 'museum', 1, NULL, NULL, NULL, NULL, NULL, 'other', NULL, 0, 'https://www.facebook.com/MuseoHistoricoMilitarSucre/', NULL, NULL, NULL, '2025-10-06 23:13:36', '2025-10-06 23:13:36'),
(34, 1, 'Museo de San Felipe Neri', 'El Museo y Templo de San Felipe Neri invita a subir a sus terrazas y azotea para disfrutar del centro histórico de Sucre vistas panorámicas; en el interior, sus claustros conservan piezas de arte sacro y el encanto de la arquitectura colonial.', -19.050325822641994, -65.261135852351670, 'Calle Nicolas Ortiz #165', 'LUNES A SABADO: 14:30-17:30', NULL, 'museum', 1, NULL, NULL, NULL, NULL, NULL, 'other', NULL, 0, NULL, NULL, NULL, NULL, '2025-10-06 23:13:36', '2025-10-06 23:13:36'),
(35, 1, 'Museo de San Francisco', 'El Templo-Museo de San Francisco de Asís es una de las iglesias más antiguas de Sucre. Destacan sus cubiertas con cinco tipos de artesonados -de estilos renacentista, mudéjar y barroco- y el altar mayor finamente tallado y dorado a la hoja, al igual que los retablos laterales. En la cripta reposan conquistadores y fundadores de la ciudad. Sus dos torres cuadrangulares se construyeron junto con el templo; una alberga la \"Campana de la Libertad\" (fundida en 1800), la misma que convocó al pueblo el 25 de mayo de 1809 durante el Primer Grito de Independencia.', -19.045932822541420, -65.258957250031910, 'Calle Aniceto Arce #106', 'LUNES A SABADOS: 10:00-12:00 y 15:00-17:00', NULL, 'museum', 1, NULL, NULL, NULL, NULL, NULL, 'other', NULL, 0, 'https://www.facebook.com/p/Templo-Museo-San-Francisco-100091972364946/?locale=es_LA', NULL, NULL, NULL, '2025-10-06 23:13:36', '2025-10-06 23:13:36'),
(36, 1, 'Museo Costumbrista \"Casa DR. Mariano Deheza\"', 'El Museo Costumbrista Casa Deheza resguarda piezas de gran valor histórico y recrea rincones urbanos y residenciales propios de la Sucre de antaño, abarcando finales del siglo XIX y principios del siglo XX. Sus salas evocan la vida cotidiana de la época mediante ambientes cuidadosamente ambientados, que permiten al visitante asomarse a la ciudad y al hogar tradicional de aquellos años. Una parada breve, clara y muy visual para conectar con la memoria costumbrista de Sucre.', -19.047375126269117, -65.257227941261820, 'Calle San Alberto #156', 'LUNES A VIERNES: 9:00-12:30 y 14:30-18:15; SABADOS: 9:00-12:45', NULL, 'museum', 1, NULL, NULL, NULL, NULL, NULL, 'other', NULL, 0, 'https://www.facebook.com/Museocostumbrista?locale=es_LA', NULL, NULL, 'https://culturaydeporte.usfx.bo/project/museo-costumbrista-casa-deheza/', '2025-10-06 23:13:36', '2025-10-06 23:13:36'),
(37, 1, 'Museo DR. Alfredo Gutiérrez Valenzuela', 'El Museo Dr. Alfredo Gutiérrez Valenzuela ofrece una colección de objetos decorativos de renombradas firmas europeas, que reflejan el gusto y el lujo de la sociedad sucrense de los siglos XIX y XX. Estas piezas fueron reunidas con pasión por el ilustre abogado Dr. Alfredo Gutiérrez Valenzuela, dando lugar a un recorrido breve y muy visual para comprender la estética doméstica de aquella época.', -19.048632196288615, -65.259352329320690, 'Calle Plaza 25 de mayo #22', 'LUNES A VIERNES: 9:00-12:30 y 14:30-18:30; SABADOS: 9:30-12:00', NULL, 'museum', 1, NULL, NULL, NULL, NULL, NULL, 'other', NULL, 0, 'https://www.facebook.com/profile.php?id=100092730219171&locale=es_LA', NULL, NULL, 'https://culturaydeporte.usfx.bo/project/museo-alfredo-gutierrez-valenzuela/', '2025-10-06 23:13:36', '2025-10-06 23:13:36'),
(38, 1, 'Museo de arte textil CETUR', 'El Museo de Arte Textil CETUR presenta, en sus salas de exposición, el patrimonio textil de Chuquisaca, con énfasis en las culturas jalq\'a, yamparas y en expresiones como el fandango de los Cintis. La muestra aborda técnicas, motivos y usos sociales del textil, situándolos en su contexto cultural y territorial. Además de exhibir piezas representativas, el museo funciona como centro didáctico: ofrece espacios de aprendizaje y demostración sobre técnicas de elaboración de los tejidos y sobre entre otros saberes tradicionales. Talleres, visitas guiadas y actividades de interacción que permiten al público comprender la riqueza cultural del departamento de Chuquisaca', -19.049327658387270, -65.255063474181530, 'Calle San Alberto #413', 'LUNES A VIERNES: 8:00-16:00', NULL, 'museum', 1, NULL, NULL, NULL, NULL, NULL, 'other', NULL, 0, 'https://www.facebook.com/CeturMuseo/?locale=es_LA', NULL, NULL, NULL, '2025-10-06 23:13:36', '2025-10-06 23:13:36'),
(39, 1, 'Parque Cretácico', '¡La era de los dinosaurios esta acá! Si eres fan de la paleontología, en el Parque Cretácico descubrirás el mayor yacimiento de huellas del mundo, el farallón de Cal Orck\'o. Conoce qué dinosaurios caminaron aquí, cómo se formaron sus pisadas y todo su legado que dejaron Recorre miradores, salas interactivas y réplicas a escala real; y, ve las huellas a pocos metros. Ven en familia, con tu curso o con amigos: aprender, asombrarte y tomarte la foto con gigantes del pasado nunca fue tan fácil.', -19.004759815278582, -65.236044397179900, 'Carretera a Cochabamba Km 5', 'MARTES A DOMINGO: 9:00-17:00', NULL, 'attraction', 1, 'Sitio Paleontológico', NULL, NULL, NULL, NULL, 'other', NULL, 0, 'https://www.facebook.com/ParqueCretacicoSucre?locale=es_LA', NULL, NULL, NULL, '2025-10-06 23:24:43', '2025-10-06 23:24:43'),
(40, 1, 'Castillo de la Glorieta', 'Residencia palaciega construida entre 1893 y 1897 para Francisco Argandoña y Clotilde Urioste -los llamados *Príncipes de La Glorieta*-, considerada uno de los ejemplos más representativos del eclecticismo en Bolivia. Su arquitectura reúne, en un mismo conjunto, elementos neogóticos, mudéjares, neorrenacentistas y neobarrocos, además de influencias venecianas y toscanas visibles en portadas, arquerías y volúmenes. Las torres y cúpulas combinan perfiles y ornamentos de distinta procedencia, recurso típico del eclecticismo de fines del siglo XIX, cuando los modelos europeos se reinterpretaron con libertad en América. El diseño se atribuye al arquitecto Antonio Campo novó. Aunque la obra empleó materia prima local, muchos acabados -fueron importados de Francia e Italia; artesanos y jardineros europeos participaron en la decoración de interiores y del jardín', -19.080802959663345, -65.270638023864690, 'Carretera a Potosí Km 5', 'MARTES A SABADO: 9:00-17:00; DOMINGOS Y FERIADOS: 9:00-16:00', NULL, 'attraction', 1, 'Edificio Histórico', NULL, NULL, NULL, NULL, 'other', NULL, 0, 'https://www.facebook.com/castillodelaglorieta', NULL, NULL, NULL, '2025-10-06 23:24:43', '2025-10-06 23:24:43'),
(41, 1, 'Palacio de la Florida', 'Edificación señorial de fines del siglo XIX, visible por su fachada ladrillo-azul y el alineamiento de palmeras. Fue la residencia del expresidente Aniceto Arce (1824-1906), apodado *el boliviano de hierro*, y está considerada una reliquia de la arquitectura republicana en Bolivia. En 2015 fue designada segunda residencia presidencial. La decoración mural es uno de sus mayores atractivos. Los salones fueron pintados al temple con recursos de trompe-l\'œil que imitan mármoles, maderas y relieves. En el comedor de lujo, la bóveda crea la ilusión de un cielo infinito, con golondrinas, nubes y ángeles Este programa artístico refleja el gusto cosmopolita de Arce y su interés por el arte europeo.', -19.075959950610414, -65.268715787887490, 'Carretera a Potosí Km 4', 'MARTES A SABADO: 9:00-17:00; DOMINGOS Y FERIADOS: 9:00-16:00', NULL, 'attraction', 1, 'Edificio Histórico', NULL, NULL, NULL, NULL, 'other', NULL, 0, 'https://www.facebook.com/castillodelaglorieta', NULL, NULL, NULL, '2025-10-06 23:24:43', '2025-10-06 23:24:43'),
(42, 1, 'Palacete del Guereo', 'Residencia señorial de fines del siglo XIX ubicada a los pies de los cerros Sica Sica y Churuquella, en la zona de Santa Ana. El predio, de más de 8.000 m², tiene ingreso principal por la avenida del Ejército -en desnivel- y jardines que descienden hasta el barrio de El Guereo. Su origen es una casa de hacienda denominada Huaya Paccha, edificada en 1875 por los esposos Juan de Mata Melgarejo Antezana y Manuela Arteche de Melgarejo. En 1897, tras una deuda y un prolongado juicio, la propiedad pasó a Mamerto Urriolagoitia y Ozamis y su esposa Amalia Tardío del Rivero de Urriolagoitia. Esta familia la rebautizó como \"Guereo\" en homenaje a Magdalena de Guereo y Ozamis, madre de Mamerto. Ya en manos de los Urriolagoitia, se encargó al arquitecto Antonio Camponovo la remodelación y ampliación que le dio su fisonomía actual de palacete. Posteriormente perteneció al Dr. Gustavo Urioste y, más tarde, a sus herederos. De estilo ecléctico, el conjunto recuerda la campiña francesa por su composición y tratamiento ornamental. Destacan la torre-mirador con vitrales policromados, la capilla de traza renacentista y los túneles del patio exterior que conducían aguas de vertiente desde el cerro hasta la propiedad. En los jardines subsisten pinos, sauces y cedros de gran porte.', -19.053857414783508, -65.251910898406860, 'Av. Del Guereo', 'MARTES A DOMINGO: 9:00-17:00', NULL, 'attraction', 1, 'Edificio Histórico', NULL, NULL, NULL, NULL, 'other', NULL, 0, NULL, NULL, NULL, NULL, '2025-10-06 23:24:43', '2025-10-06 23:24:43'),
(43, 1, 'HOTEL ROSARIO LAGO TITICACA', 'El Hotel Rosario Lago Titicaca ofrece una estadía confortable frente a las orillas del lago más alto del mundo. Sus habitaciones, decoradas con estilo tradicional andino, cuentan con wifi gratuito, calefacción y balcones con vistas panorámicas. El hotel dispone de restaurante con especialidades locales y cocina internacional, además de áreas comunes donde los huéspedes pueden disfrutar del paisaje y la tranquilidad de Copacabana.\n\nUbicado sobre la avenida Costanera, a pocos minutos del centro y del embarcadero, el Hotel Rosario Lago Titicaca combina comodidad y entorno natural. Es una opción ideal para quienes buscan descansar, disfrutar de la vista al lago y acceder fácilmente a los principales atractivos turísticos de la región.', -16.167901158870000, -69.089434254911000, 'Av Costanera esq.Calle Rigoberto Paredes', '', '+591 76254988', 'accommodation', 2, 'Hotel moderno con esencia andina', 'Habitaciones y suites', 90.00, NULL, NULL, 'other', NULL, 0, NULL, 'https://www.instagram.com/hotelrosariolagotiticaca/', '+591 76254988', NULL, '2025-10-06 23:35:59', '2025-11-04 05:45:42'),
(44, 1, 'Marriot Santa Cruz de la Sierra Hotel', 'El Marriott Hotel Santa Cruz combina lujo y confort para el huésped que busca una estadía de alta categoría. Ofrece habitaciones modernas con wifi gratuito, ropa de cama de calidad y servicios ejecutivos. Dispone de restaurante, bar, piscina al aire libre, gimnasio y spa, además de salas para reuniones y eventos.\n\nEl Marriott Hotel Santa Cruz se encuentra en la zona de Equipetrol, a pocos minutos de centros comerciales, oficinas y del Aeropuerto Internacional Viru Viru. El hotel cuenta con 216 habitaciones, incluyendo habitaciones estándar, superiores, ejecutivas y suites, todas diseñadas para ofrecer una experiencia confortable y práctica tanto para viajeros de negocios como de placer.', -17.760960616401000, -63.202155035140000, '4to Anillo Entre Radial 23 Y, Av. Las Ramblas S/N, Santa Cruz de la Sierra', '', '+591 3 342 4848', 'accommodation', 6, 'Hotel moderno de lujo', 'Habitaciones y suites', 95.00, NULL, NULL, 'other', NULL, 0, 'https://www.facebook.com/MarriottBonvoyLatAm/?brand_redir=314467271901260#', 'https://www.instagram.com/marriottbonvoy/', '+591 3 342 4848', NULL, '2025-10-06 23:35:59', '2025-11-04 05:39:33'),
(45, 1, 'Hotel Palacio de Sal', 'El Hotel Palacio de Sal ofrece una experiencia única a orillas del majestuoso Salar de Uyuni. Construido íntegramente con bloques de sal, desde las paredes hasta el mobiliario, combina arquitectura singular con comodidad moderna. Sus habitaciones cuentan con calefacción, baño privado y vistas al salar. Además, dispone de spa, restaurante panorámico, mirador 360° y un parque de diversiones que brinda entretenimiento para toda la familia en medio del altiplano boliviano.\n\nUbicado a unos 25 kilómetros de Uyuni, el Hotel Palacio de Sal invita a disfrutar de amaneceres, cielos estrellados y del encanto incomparable del desierto blanco, siendo una de las opciones más emblemáticas de hospedaje en Bolivia.', -20.305390297598000, -66.973896770000000, 'Colchani. Uyuni', '', '+591 71796404', 'accommodation', 5, 'Hotel elaborado con bloques de sal', 'Habitaciones y suites', 170.00, NULL, NULL, 'other', NULL, 0, 'https://www.facebook.com/HotelPalacioDeSalBolivia', 'https://www.instagram.com/palaciodesal/', '+591 71796404', 'http://palaciodesal.com.bo', '2025-10-06 23:35:59', '2025-11-04 05:58:39'),
(46, 1, 'HOTEL PARADOR SANTA MARIA LA REAL', 'El Parador Santa María La Real ocupa una casona señorial del siglo XVIII, situada en la calle Bolívar 625, en pleno centro histórico de Sucre. Esta residencia ha sido cuidadosamente restaurada para preservar su arquitectura colonial original y adaptarse a los estándares de un alojamiento de lujo. \n\nSus 39 habitaciones (entre individuales, dobles, matrimoniales y suites) combinan mobiliario clásico de época con comodidades contemporáneas como Wi-Fi gratuito y minibar. El hotel ofrece servicios de spa con sauna e hidromasaje, restaurante y bar en ambientes de estilo colonial, además de salones para eventos.', -19.049561315633000, -65.259162600000000, 'Calle Bolívar #625', '', '+591 71162191', 'accommodation', 1, 'Hotel de tipo colonial', 'Suites y habitaciones', 61.00, NULL, NULL, 'other', NULL, 0, 'https://www.facebook.com/HotelParadorSantaMariaLaReal/', 'https://www.instagram.com/paradorsantamarialareal/?hl=es', '+591 71162191', NULL, '2025-10-06 23:35:59', '2025-11-04 06:00:01'),
(47, 1, 'Hotel Camino Real', 'El Hotel Camino Real La Paz destaca por su elegancia contemporánea y su atención personalizada. Ofrece habitaciones amplias con vistas a la ciudad, wifi gratuito, climatización, minibar y un diseño que combina confort y estilo. Cuenta además con piscina climatizada, gimnasio, spa, restaurante gourmet y salones para eventos, brindando una experiencia completa tanto para viajeros de negocios como de descanso.\n\nUbicado en la zona Sur de La Paz, una de las áreas más exclusivas y tranquilas de la ciudad, el Hotel Camino Real La Paz se encuentra cerca de centros comerciales, restaurantes y cafés. Su ubicación, sumada a su servicio de alta calidad, lo convierte en una de las principales opciones de alojamiento en la ciudad de La Paz.', -16.540778396388000, -68.089358846810000, 'Calacoto Av. Ballivián #369 esquina Calle 10, La Paz', '', '+591 76765709', 'accommodation', 2, 'Hotel moderno de lujo', 'Suites', 116.00, NULL, NULL, 'other', NULL, 0, 'https://www.facebook.com/HotelCaminoRealLaPaz', 'https://www.instagram.com/suitescaminoreal.lpb/', '+591 76765709', 'https://www.caminoreal.com.bo/hotel-la-paz', '2025-10-06 23:35:59', '2025-11-04 05:49:17'),
(48, 1, 'VILLA ADELA', 'Ubicado en Tiquipaya, Villa Adela Eco Restaurant ofrece una alternativa gastronómica innovadora. Su propuesta combina sabores de la cocina boliviana y mexicana, creando fusiones únicas. Cada plato resalta ingredientes frescos y un ambiente acogedor en contacto con la naturaleza. Una experiencia culinaria pensada para deleitar a los comensales con autenticidad y creatividad.', -17.324228341229492, -66.208412804463340, 'Av Chilimarca', NULL, '+591 62735970', 'restaurant', 3, 'Espacio campestre.', NULL, NULL, NULL, NULL, 'other', NULL, 0, 'https://www.facebook.com/villadela.bo/', 'https://www.instagram.com/villadela.bo/?hl=es', '+591 62735970', NULL, '2025-10-06 23:37:46', '2025-12-01 13:45:51'),
(49, 1, 'Raffinè', 'El restaurante Raffiné – Experiencia Gastronómica, ofrece una propuesta de cocina fina dirigida por los chefs Alejandro De La Fuente y Saúl Pulino, quienes tras nueve años de experiencia en Francia, traen a Santa Cruz platos de alta cocina con raíces francesas y elaboraciones de temporada. \n\nUbicado en el barrio Sirari (Calle Las Dalias 37, Santa Cruz de la Sierra), el restaurante propone un menú degustación sorpresa, previo formulario de preferencias o alergias, así como opciones a la carta en almuerzo de fin de semana, en un ambiente elegante y contemporáneo.', -17.765259764830000, -63.170318642523000, 'Av Los Cusis 157', '', '+591 75572495', 'restaurant', 6, 'Restaurante enfocado en las experiencias gastronomicas', NULL, NULL, NULL, NULL, 'other', NULL, 0, 'https://www.facebook.com/raffinebolivia/', 'https://www.instagram.com/raffine.bo/?hl=es-la', '+591 75572495', NULL, '2025-10-06 23:37:46', '2025-11-04 05:52:39'),
(50, 1, 'TIKA PALACIO', 'El Tilka Palacio Restaurante propone una propuesta culinaria contemporánea en el centro de Potosí, ideal para quienes buscan disfrutar de sabores de alto nivel. Ofrece platos de cocina fusión boliviana‑internacional, ingredientes de proximidad (“km 0”), carta de vinos seleccionados y ambiente elegante.\nUbicado junto a una zona patrimonial de Potosí, Tilka Palacio Restaurante combina su servicio cuidado con una atmósfera que invita al disfrute tranquilo, convirtiéndose en una opción destacada para una comida o cena sofisticada en la ciudad.', -20.305146028322000, -66.973793544863000, 'Av. Potosí #113, Uyuni, Bolivia.', '', '+591 68420784', 'restaurant', 5, 'Cocina boliviana con enfoque sostenible', NULL, NULL, NULL, NULL, 'other', NULL, 0, 'https://www.facebook.com/tikaenbolivia/?locale=es_LA', 'https://www.instagram.com/tika.bolivia?utm_source=ig_web_button_share_sheet&igsh=ZDNlZDc0MzIxNw==', '+591 68420784', NULL, '2025-10-06 23:37:46', '2025-11-04 06:03:31'),
(51, 1, 'RESTAURANT EL SOLAR', 'Restaurante ubicado en el centro histórico de la ciudad de Sucre, se caracteriza por ofrecer una experiencia gastronómica en un ambiente colonial acogedor. Con una propuesta que combina la tradición culinaria local con ingredientes frescos y de calidad, creando platos que reflejan la riqueza cultural de la región.', -19.049561315633202, -65.259162599999980, 'Calle Bolívar #625', NULL, '+591 63354297', 'restaurant', 1, 'Cocina tradicional en ambiente colonial', NULL, NULL, NULL, NULL, 'other', NULL, 0, 'https://www.facebook.com/RestaurantElSolar/?locale=es_LA', 'https://www.instagram.com/elsolarrestaurant/?hl=es', '+591 63354297', NULL, '2025-10-06 23:37:46', '2025-10-06 23:37:46'),
(52, 1, 'GUSTU', 'Gustu es un restaurante–escuela pionero en Bolivia que trabaja exclusivamente con productos de la despensa natural del país. Combina innovación culinaria y sostenibilidad con el rescate de ingredientes nativos y sabores silvestres. Más que un restaurante, es un movimiento gastronómico que forma a jóvenes y apoya a comunidades productoras. Cada plato es un homenaje a Bolivia, su cultura y su patrimonio alimentario. Reconocido internacionalmente, Gustu se ha consolidado como un referente de la gastronomía latinoamericana.', -16.544532062744707, -68.086348628880340, 'Calacoto Av. Ballivián #369 esquina Calle 10, La Paz', NULL, '+591 69830327', 'restaurant', 2, 'Restaurante-escuela con productos nativos bolivianos', NULL, NULL, NULL, NULL, 'other', NULL, 0, 'https://www.facebook.com/RestaurantGUSTU/', 'https://www.instagram.com/gusturestaurant/?hl=es', '+591 69830327', NULL, '2025-10-06 23:37:46', '2025-10-06 23:37:46'),
(53, 1, 'De la vida tu copa ¡Brinda en la Vendimia de Tarija!', 'Entre viñedos que alcanzan los cielos, cada racimo de Tarija guarda el secreto de la altura. La magia de estas tierras eleva los sabores, creando vinos que celebran sol, viento y tradición. Pisa la cosecha, degusta la historia y brinda por la alegría de la Vendimia, donde cada copa es un encuentro con la esencia de los Andes.', -21.695560039777000, -64.652872029733000, 'Valle de la Concepción, Tarija', '', '', 'event', 9, '', NULL, 0.00, '2025-08-01 09:00:00', '2025-08-03 22:00:00', 'festival', NULL, 1, NULL, NULL, NULL, NULL, '2025-09-14 18:30:55', '2025-11-05 21:27:10');
INSERT INTO `locations` (`id`, `user_id`, `name`, `description`, `latitude`, `longitude`, `address`, `opening_hours`, `contact_info`, `type`, `department_id`, `badge`, `room_type`, `price_per_night`, `start_date`, `end_date`, `event_type`, `capacity`, `is_recurring`, `facebook`, `instagram`, `whatsapp`, `link`, `created_at`, `updated_at`) VALUES
(54, 1, 'Escucha siglos de música barroca en las Misiones de Chiquitos', 'Festival Internacional de Música Renacentista y Barroca Americana “Misiones de Chiquitos”\nEntre templos de piedra, las melodías barrocas resuenan como ecos de siglos pasados. Este festival revive la música que acompañó la vida espiritual de las Misiones Jesuíticas, invitando a escuchar, sentir y valorar la riqueza cultural de una tradición que sigue viva en cada nota', -17.834004467272000, -60.750861668816000, 'San José de Chiquitos, Santa Cruz', '', '', 'event', 6, '', NULL, 250.00, '2025-07-15 19:30:00', '2025-07-15 23:30:00', 'concert', NULL, 0, NULL, NULL, NULL, NULL, '2025-09-14 18:31:14', '2025-11-04 05:56:02'),
(55, 1, '¡Adéntrate en el Laberinto de Sal, un paseo entre mil pasillos!', 'Entre caminos blancos que se multiplican hasta el horizonte, cada pasillo del Laberinto de Sal ofrece descubrimiento y asombro. Un recorrido único que invita a perderse y explorar un mundo de sal interminable, lleno de misterio', -20.476084836887000, -67.609682655249000, 'Salar de Uyuni, Potosí', '', '', 'event', 5, '', NULL, 180.00, '2025-06-10 07:00:00', '2025-06-11 17:00:00', 'tour', NULL, 1, NULL, NULL, NULL, NULL, '2025-09-14 18:31:25', '2025-11-04 06:06:10'),
(56, 1, 'Alasitas, ¡sueña en miniatura!', 'Cada miniatura que encuentras en la Feria de la Alasita representa un deseo, un anhelo que, según la tradición, puede hacerse realidad. Entre coloridos puestos y figuras diminutas, esta feria invita a soñar, celebrar la cultura paceña y dejar que cada detalle en miniatura cuente una historia propia.', -16.503128442033000, -68.125553102852000, 'La Paz', '', '', 'event', 2, '', NULL, 50.00, '2026-02-14 08:00:00', '2026-02-15 23:59:00', 'festival', NULL, 1, NULL, NULL, NULL, NULL, '2025-09-14 18:31:56', '2025-11-04 05:55:04'),
(57, 1, 'Festival de la Vendimia y Degustación de Singani', 'Celebración de la cosecha de uvas, degustación de vinos y singanis artesanales, música en vivo y gastronomía regional.', -21.533300000000000, -64.733300000000000, 'Tarija', NULL, NULL, 'event', 9, NULL, NULL, 80.00, '2025-10-18 11:00:00', '2025-10-18 20:00:00', 'festival', NULL, 1, NULL, NULL, NULL, NULL, '2025-09-14 18:32:06', '2025-10-07 10:26:15'),
(60, NULL, 'Museo Nacional de Arte', 'El Museo Nacional de Arte de es un espacio emblemático que resguarda una valiosa colección de arte boliviano y latinoamericano. Sus salas exhiben obras que abarcan desde el período virreinal hasta la producción contemporánea, reflejando la evolución del arte en el país. Entre sus piezas destacan pinturas coloniales, esculturas, grabados y una importante colección de arte moderno.\n\nEl edificio, una joya arquitectónica del siglo XVIII conocido como el Palacio de los Condes de Arana, es en sí mismo una obra de arte, con su patio central, balcones de madera tallada y muros de piedra labrada. Situado en el corazón histórico de La Paz, el museo invita a recorrer sus galerías y descubrir la riqueza artística que guarda en cada rincón.\n\nSi te apasiona el arte y la historia, el Museo Nacional de Arte es una visita imprescindible.', -16.495866439640000, -68.134172417879000, 'Calle Comercio esquina Socabaya 485', 'Lunes a Viernes 08:30 - 16:30 | Sábado 09:00 - 17:00 | Domingo 09:00 - 13:00', '(+591) 2408542', 'museum', 2, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, 'https://www.facebook.com/museonacionaldeartebolivia/?locale=es_LA', NULL, NULL, 'https://www.museonacionaldearte.gob.bo/', '2025-11-06 00:57:22', '2025-11-06 00:57:22'),
(61, NULL, 'Museo Costumbrista Juan de Vargas', 'El Museo Costumbrista Juan de Vargas, ubicado en la histórica calle Jaén de la ciudad de La Paz, ofrece un recorrido por las tradiciones, personajes y costumbres paceñas a lo largo del tiempo. En sus salas se exhiben maquetas, fotografías, vestimentas y objetos que recrean escenas de la vida cotidiana, las celebraciones populares y los oficios tradicionales de la ciudad.\n\nEntre sus principales atractivos se encuentran las representaciones de la Ch’alla, el Carnaval paceño, la Alasita entre otros. Además, se pueden apreciar retratos y esculturas de personajes históricos y populares que marcaron la identidad de La Paz.\n\nSi te interesa conocer el alma de la ciudad a través de su historia y sus costumbres, el Museo Costumbrista Juan de Vargas es una parada que no puede faltar en tu visita.', -16.491794160405000, -68.135583916161000, '', 'Martes a Viernes 09:00 - 12:30 | Sábado 09:00 - 17:00', '', 'museum', 2, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, 'https://www.facebook.com/profile.php?id=100068572866105', NULL, NULL, NULL, '2025-11-06 01:16:48', '2025-11-06 01:16:48'),
(62, NULL, 'Casa-Museo \"Pedro Domingo Murillo\"', 'El Museo Casa de Murillo, situado en la tradicional calle Jaén de la ciudad de La Paz, es uno de los espacios más emblemáticos para conocer la historia de la independencia boliviana. En esta casona colonial vivió Pedro Domingo Murillo, prócer del levantamiento del 16 de julio de 1809, hecho que marcó el inicio del proceso libertario en el Alto Perú.\n\nEl museo conserva mobiliario, documentos, armas, retratos y objetos de la época, que permiten revivir el ambiente de finales del siglo XVIII y comienzos del XIX. Sus salas están ambientadas con detalles originales, mostrando la arquitectura y el estilo de vida de la sociedad paceña de aquel tiempo.\n\nVisitar la Casa de Murillo es adentrarse en un capítulo de la historia y el espíritu revolucionario de La Paz.', -16.492144824069000, -68.135666503432000, 'Calle Jaén Nro. 790', 'Martes a Viernes 09:00 - 17:00', '', 'museum', 2, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, NULL, NULL, NULL, '2025-11-06 01:18:27', '2025-11-06 01:19:02'),
(63, NULL, 'Museo de  Metales Preciosos Precolombinos', 'El Museo de Metales Preciosos Precolombinos, ubicado en la histórica calle Jaén de la ciudad de La Paz, resguarda una de las colecciones más valiosas del patrimonio arqueológico boliviano. En sus salas se exhiben piezas de oro, plata, cobre y cerámica pertenecientes a culturas  precolombinas como Tiwanaku, Mollo y otras civilizaciones andinas.\n\nEntre sus tesoros más destacados se encuentran finas joyas, utensilios rituales y objetos que revelan la maestría metalúrgica de los antiguos pueblos del altiplano. El museo funciona en una casona colonial restaurada, lo que brinda un ambiente íntimo y elegante para apreciar cada pieza.\n\nSi te apasiona la historia y el arte antiguo, el Museo de Metales Preciosos Precolombinos es una visita indispensable para descubrir la riqueza cultural que precedió a la época colonial.', -16.492031595991000, -68.135695546834000, 'Calle Jaen N° 777', 'Martes a Viernes 09:30 - 12:30 15:00 - 19:00 | Sábado y Domingo 09:00 - 13:00', '', 'museum', 2, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, 'https://www.facebook.com/MuseoMetalesPreciososBolivia/?locale=es_LA', NULL, NULL, NULL, '2025-11-06 01:21:21', '2025-11-06 01:21:21'),
(64, NULL, 'Museo Tambo Quirquincho', 'El Museo Tambo Quirquincho, ubicado en el corazón del casco histórico de La Paz, es un espacio dedicado a la preservación y difusión del arte y la cultura paceña. Instalado en una casona colonial del siglo XVI, que en su origen funcionó como tambo o albergue para comerciantes, combina historia, arquitectura y arte en un mismo lugar.\n\nSus salas albergan colecciones de arte contemporáneo, objetos ceremoniales, trajes folklóricos y piezas que reflejan la identidad cultural de La Paz. Además, el museo acoge exposiciones temporales, talleres y actividades que promueven el diálogo entre el arte tradicional y las expresiones modernas.\n\nVisitar el Museo Tambo Quirquincho es descubrir un punto de encuentro entre el pasado y el presente de la ciudad.', -16.493608142619000, -68.138059107787000, 'Calle Evaristo Valle, zona Centro', 'Martes a Viernes 09:00 - 12:30 | 15:00 - 19:00', '', 'museum', 2, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, 'https://www.facebook.com/pages/Museo%20Tambo%20Quirquincho/302969309880528/#', NULL, NULL, NULL, '2025-11-06 01:39:44', '2025-11-06 01:39:44'),
(65, NULL, 'Museo Nacional Paleontologico y Arqueologico de Tarija MUNAPARQ', 'El Museo Nacional Paleontológico y Arqueológico de Tarija (MUNAPARQ) es un espacio dedicado a la preservación, investigación y difusión del patrimonio paleontológico y arqueológico del sur de Bolivia. Sus salas exhiben fósiles, restos óseos, herramientas y cerámicas que permiten conocer la evolución de la vida y las culturas que habitaron la región a lo largo de los siglos.\n\nEntre sus principales atractivos se encuentran esqueletos de animales prehistóricos, piezas de culturas indígenas antiguas, y recreaciones de ambientes y prácticas de los primeros pobladores. El museo ofrece además actividades educativas y exposiciones temporales que buscan acercar al público al conocimiento científico y arqueológico.\n\nVisitar el MUNAPARQ es descubrir la riqueza paleontológica y arqueológica que ha marcado la región.', -21.534863845484000, -64.734993652977000, 'Virginio Lema esq, Gral. Trigo, Tarija', '', '', 'museum', 9, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, 'https://www.facebook.com/museo.tarija/?locale=es_LA', NULL, NULL, 'https://munaparq.uajms.edu.bo/?fbclid=IwY2xjawN3CkZleHRuA2FlbQIxMABicmlkETEzUEZjV1ZyNWRpNk9iVFREAR7Muz0imdmn_wXEkPF6J4Ls_CC3LL_nbjGa9gh1T7l-SFkS3C6C6CsdF78j9g_aem_EMDKySg4Ks0tv4rneIAtCQ', '2025-11-06 01:42:33', '2025-11-06 01:42:46'),
(66, NULL, 'Casa Dorada', 'La Casa Dorada, ubicada en el centro histórico de Tarija, es un edificio emblemático que refleja la arquitectura y el estilo de vida colonial de la región. Su fachada y sus detalles arquitectónicos, caracterizados por balcones y molduras ornamentales, evocan la riqueza de la época y la influencia española en el territorio.\n\nEl museo alberga colecciones de mobiliario antiguo, documentos históricos, fotografías y objetos que narran la historia de Tarija y de sus familias más influyentes. Sus salas permiten recorrer la vida cotidiana, las tradiciones y los acontecimientos que marcaron el desarrollo cultural y social de la ciudad.\n\nVisitar la Casa Dorada es apreciar el legado arquitectónico, cultural y social de Tarija.', -21.532681232925000, -64.734053030568000, 'Calle Ingavi N° 0370', 'Lunes a Viernes 09:00 - 11:00 15:00 - 19:00', '', 'museum', 9, 'Nacionales 10 Extranjeros 15', NULL, NULL, NULL, NULL, NULL, NULL, 0, 'https://www.facebook.com/CasaDeLaCulturaTarija/?locale=es_LA', NULL, NULL, NULL, '2025-11-06 01:44:15', '2025-11-06 01:49:32'),
(67, NULL, 'Centro Cultural Castillo Azul Moises Navajas', 'El Castillo Azul,  es un edificio histórico de gran valor arquitectónico y patrimonial. Con un retiro ocupado por áreas verdes, el Castillo Azul se eleva en tres niveles, dos de los cuales se destinan a actividades residenciales, mientras que el tercero alberga una terraza y torres con cubiertas en forma de cúpulas y pirámides.\n\nCon aproximadamente 150 años de historia, el Castillo Azul fue mandado a construir por el comerciante Moisés Navajas Ichazo como casa de campo familiar. En 1962, fue vendido a la familia Rengel, quienes realizaron trabajos de restauración debido a su deterioro.\n\nVisitar el Castillo Azul permite apreciar su arquitectura, sus detalles históricos y la riqueza patrimonial que conserva en pleno corazón de Tarija.', -21.534375392191000, -64.726915592487000, 'Calle Bolívar entre Junín y O’Connor', 'Lunes a Viernes 09:00 - 09:45, 10:00 - 10:45, 11:00 - 11:45', '', 'museum', 9, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, 'https://www.facebook.com/p/Centro-Cultural-Castillo-Azul-100054584883326/?locale=es_LA', NULL, NULL, NULL, '2025-11-06 01:52:02', '2025-11-06 01:52:02'),
(68, NULL, 'Museo San Roque', 'El Museo San Roque fue inaugurado en 2007 con el propósito de preservar y difundir el patrimonio religioso y cultural vinculado al culto de San Roque, santo patrono de la ciudad. Está instalado en la antigua casa parroquial, construida en 1908, contigua a la iglesia que lleva su mismo nombre.\n\nEn sus salas se exhiben reliquias religiosas, vestimentas donadas por los devotos, instrumentos musicales y las características indumentarias de los chunchos promesantes, protagonistas de la tradicional Fiesta Grande de San Roque. Cada objeto y fotografía expuesta refleja siglos de fe, identidad y tradición del pueblo tarijeño.\n\nVisitar el Museo San Roque es una oportunidad para conocer de cerca una de las manifestaciones culturales y devocionales más significativas de Tarija.', -21.529330828998000, -64.733554902538000, 'Calle Gral. Trigo entre Fray M. Mingo', '', '', 'museum', 9, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, 'https://www.facebook.com/Museos.SanRoque?locale=hi_IN', NULL, NULL, 'https://turismosanroque.es/cultura', '2025-11-06 01:53:03', '2025-11-06 01:53:03'),
(69, NULL, 'Museo Histórico Municipal \"Alberto Lavadenz Ribera\"', 'El Museo Histórico Municipal “Alberto Lavadenz Ribera”, en la ciudad de Cobija, es un espacio que documenta los hitos fundamentales de la historia del departamento de Pando.\n\nEn el edificio, que en su momento albergó el cuarto de motores del antiguo aeropuerto local, se restauraron las instalaciones para transformarlo en museo en 2002, a petición de la Sociedad Geográfica e Histórica de Pando. \n\nEl acervo del museo incluye piezas de gran valor histórico: fusiles Winchester usados durante la guerra del Acre, el primer teléfono magnético que operó en Cobija, un piano que llegó al departamento en su momento de auge, entre otros objetos que narran los periodos de esplendor de la goma y la castaña en la región.', -11.030095881847000, -68.762409623220000, 'Av. 9 de febrero', 'Lunes a Viernes 08:00 - 12:30, 15:00 - 18:30', '', 'museum', 8, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, NULL, NULL, NULL, '2025-11-06 01:54:41', '2025-11-06 01:54:41'),
(70, NULL, 'Museo Pedro Villalobos', 'El Museo Pedro Villalobos, ubicado en la ciudad de Cobija, está dedicado a la preservación y difusión de la biodiversidad de la Amazonía boliviana. En sus salas se exhiben ejemplares disecados de fauna regional, fósiles y muestras que ilustran la riqueza natural del norte del país.\n\nEl acervo del museo incluye esqueletos de grandes mamíferos, reptiles, aves, insectos y peces, entre ellos un fragmento fósil de un caimán gigante de aproximadamente catorce metros de largo. También cuenta con una destacada colección de serpientes conservadas en frascos, así como especies representativas del ecosistema amazónico.\n\nVisitar el Museo Pedro Villalobos permite conocer la extraordinaria diversidad biológica de Pando.', -11.018427496483000, -68.755222013074000, 'Av. 9 de febrero Esq. Tcnl. Cornejo Nro 140', 'Lunes a Viernes 08:00 - 15:00', '', 'museum', 8, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, 'https://www.facebook.com/p/Museo-de-Historia-Natural-Pedro-Villalobos-100091351308922/', NULL, NULL, NULL, '2025-11-06 01:56:05', '2025-11-06 01:56:05'),
(71, NULL, 'Casa de la cultura Hermanos Torrico', 'La Casa de la Cultura Hermanos Torrico, situada en la ciudad de Cobija, ocupa un edificio histórico que originalmente fue la maestranza de los motores generadores de energía de la población. \n\nEn su interior se albergan una biblioteca, salas de exposición, aulas para danza y teatro, y espacios donde jóvenes artistas locales desarrollan música, pintura, poesía y otras manifestaciones culturales. La institución funciona como un centro de encuentro para la comunidad, promoviendo la lectura, el ensayo artístico y la divulgación del patrimonio cultural amazónico de Pando. \n\nVisitar la Casa de la Cultura Hermanos Torrico es una oportunidad para adentrarse en la vida artística de Cobija.', -11.019572420513000, -68.758519481885000, 'Av. 16 de Julio, Cobija', 'Lunes a Viernes 08:00 - 12:00, 15:00 - 18:30', '', 'museum', 8, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, 'https://www.facebook.com/cobija.gob', NULL, NULL, NULL, '2025-11-06 01:57:09', '2025-11-06 01:57:09'),
(72, NULL, 'Museo de la Coca', 'El Museo de la Coca ofrece una mirada profunda a la historia, el significado cultural y los usos tradicionales de la hoja de coca en Bolivia y en los Andes. A través de sus salas, el visitante puede conocer el papel que esta planta ha desempeñado desde tiempos precolombinos hasta la actualidad.\n\nEl recorrido presenta exposiciones sobre su uso medicinal, ritual y social, además de explicar los procesos de cultivo, cosecha y los aspectos científicos relacionados con la hoja. También aborda la historia de la coca en la economía y su papel en la cosmovisión andina.\n\nSi deseas comprender la importancia de esta planta en la cultura boliviana, el Museo de la Coca es una visita imprescindible.', -16.497579380134000, -68.138301979469000, 'Calle Linares N° 906', 'Lunes a Sábado 10:00 - 12:30, 13:30 - 19:00', '', 'museum', 2, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, 'https://www.facebook.com/p/Museo-de-la-Coca-La-Paz-100063908536312/?locale=es_LA', NULL, NULL, NULL, '2025-11-06 01:58:52', '2025-11-06 01:58:52'),
(73, NULL, 'Museo Nacional de Etnografía y Folklore (MUSEF)', 'El Museo Nacional de Etnografía y Folklore (MUSEF), ubicado en el centro histórico de La Paz, es un espacio dedicado a la preservación, investigación y difusión de la diversidad cultural de Bolivia. Sus salas albergan colecciones de arte, textiles, instrumentos musicales, máscaras y objetos ceremoniales que representan las tradiciones de los distintos pueblos indígenas y comunidades del país.\n\nEntre sus principales atractivos se encuentran las exhibiciones sobre festividades como el Carnaval de Oruro, danzas tradicionales, rituales andinos y amazónicos, así como muestras de vestimenta, artesanía y arte popular. Además, el museo organiza exposiciones temporales y actividades educativas que acercan a los visitantes a la riqueza cultural de Bolivia.\n\nVisitar el MUSEF permite comprender y apreciar la diversidad cultural del país, convirtiéndose en una parada esencial para quienes desean adentrarse en las raíces y tradiciones de Bolivia.', -16.494510323433000, -68.134987714162000, 'Calle IngavI N° 906', '', '', 'museum', 2, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, 'https://www.facebook.com/musef.lapaz.bolivia', NULL, NULL, 'http://musef.gob.bo/?fbclid=IwY2xjawN3COVleHRuA2FlbQIxMABicmlkETEzUEZjV1ZyNWRpNk9iVFREAR61ay_ke_SAyZHFD0oUzIAhXe_vbEXflv9SWA-iXS_4J6xQHqU85laHsPX69A_aem_qWOl4uF485a4704-SVAKDA', '2025-11-06 02:00:04', '2025-11-06 02:00:04'),
(74, NULL, 'Catedral Metropolitana Nuestra Señora de La Paz', 'La Catedral Metropolitana Nuestra Señora de La Paz se alza en el corazón de la ciudad, frente a la Plaza Murillo. Su construcción comenzó en 1835 sobre los restos de antiguos templos coloniales, consolidándose como el principal símbolo religioso de la sede de gobierno.\n\nDe estilo neoclásico, combina una sobria fachada con una imponente cúpula central que domina el paisaje urbano. En su interior, alberga elementos destacados que merecen ser admirados: su altar mayor, decorado con detalles dorados y esculturas religiosas; las vidrieras de colores, que crean una atmósfera mística; y el órgano de la catedral, utilizado en celebraciones litúrgicas.', -16.496036818820000, -68.133973875385000, 'Plaza Murillo', 'Lunes a Domingo 05:30 - 21:00', '', 'attraction', 2, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, 'https://www.facebook.com/catedraldelapazbolivia/?locale=es_LA', NULL, NULL, NULL, '2025-11-06 02:02:25', '2025-11-06 02:02:25'),
(75, NULL, 'Basílica de San Francisco', 'La Basílica de San Francisco es uno de los íconos más representativos de La Paz. Su construcción comenzó en el siglo XVI, y a lo largo de los años ha combinado elementos de arquitectura colonial y barroca, convirtiéndose en un testimonio vivo de la historia paceña.\n\nSu imponente fachada, elaboradamente tallada en piedra, y su torre principal dominan el paisaje urbano, mientras que en el interior se pueden admirar altares ricamente decorados, esculturas religiosas y un altar mayor ornamentado, junto a importantes reliquias y objetos históricos que datan desde el siglo XVI hasta el XIX.\n\nEjemplo destacado de la arquitectura barroca colonial en Bolivia, la Basílica de San Francisco es un espacio que invita a descubrir la riqueza histórica de la ciudad.', -16.496422568835000, -68.137164243898000, 'Calle Sagárnaga Nº 68 casi esquina Murillo', 'Lunes a Viernes 08:30 - 12:00 | 14:00 - 17:00. Sábado 08:30 - 12:00', '', 'attraction', 8, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, 'https://www.facebook.com/p/Bas%C3%ADlica-Menor-Nuestra-Se%C3%B1ora-de-los-%C3%81ngeles-San-Francisco-La-Paz-Bolivia-100076094323197/?locale=es_LA', NULL, NULL, NULL, '2025-11-06 02:04:01', '2025-11-06 02:04:01'),
(76, NULL, 'Catedral de San Bernardo de Tarija', 'Ubicada en el corazón de Tarija, la Catedral San Bernardo es uno de los monumentos más emblemáticos de la ciudad. Designada Patrimonio Histórico y Cultural de la Nación en 2004, combina elementos neoclásicos y coloniales que reflejan su evolución a lo largo del tiempo.\n\nEn su interior destacan vitrales coloridos, un altar mayor ornamentado y valiosas obras de arte religioso. Sede del Obispado de Tarija, la catedral sigue siendo un punto de encuentro espiritual y cultural para la población y sus visitantes.', -21.533125476617000, -64.735582678895000, 'Calle la Madrid y Campero 505, Tarija', '', '', 'attraction', 9, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, 'https://www.facebook.com/LaCatedralTarija/?locale=es_LA', NULL, NULL, NULL, '2025-11-06 02:05:27', '2025-11-06 02:05:27'),
(77, NULL, 'Iglesia de San Roque', 'La Iglesia San Roque es una de las más antiguas y representativas de Tarija, reconocida como símbolo de devoción popular. Construida en el siglo XVII, está estrechamente ligada a la “Fiesta Grande de Tarija”, una de las celebraciones religiosas más importantes de la región.\n\nDe arquitectura sencilla y elegante, conserva la imagen del santo patrono, venerada por miles de fieles que cada agosto acompañan las procesiones y danzas de los promesantes \"chunchos\", llenando de fe y color las calles de la ciudad.', -21.529452563807000, -64.733079380654000, 'Esquina de la calle Gral. Trigo con Gran Manuel Mingo', 'Lunes a Viernes 08:30 - 12:00, 14:30 - 18:00 | Sábado 08:30 - 12:00', '', 'attraction', 9, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, 'https://www.facebook.com/p/Parroquia-San-Roque-Tarija-61557252735852/', NULL, NULL, NULL, '2025-11-06 02:07:07', '2025-11-06 02:07:07'),
(78, NULL, 'Iglesia Nuestra Señora del Pilar', 'La Iglesia Nuestra Señora del Pilar es un referente religioso y un ícono del centro de Cobija. Su arquitectura combina sencillez y armonía, con detalles modernos y tradicionales que reflejan la identidad de la región.\n\nEn su interior se conserva la imagen de la Virgen del Pilar, patrona de Cobija, junto a murales y cuadros del artista local Eloy Añez Marañón. Además, sus campanas históricamente han servido para alertar a la población durante las crecidas del río Acre, protegiendo a los habitantes bajo el amparo de la Virgen', -11.018046727161000, -68.753028788174000, 'Plaza Principal de Cobija', '', '', 'attraction', 8, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, 'https://www.facebook.com/iglesiadelpilar/?locale=es_LA', NULL, NULL, NULL, '2025-11-06 02:08:22', '2025-11-06 02:08:22'),
(79, NULL, 'Museo Casa Santivañez', 'El Museo Casona Santivañez es uno de los espacios patrimoniales más emblemáticos de Cochabamba. Ubicado en una antigua casona colonial–republicana restaurada, conserva patios, balcones y salones que reflejan la vida doméstica de la ciudad en los siglos XVIII y XIX. En su interior se encuentran salas dedicadas a la memoria histórica, la fotografía antigua, la literatura y la Pinacoteca Municipal, además de muebles y piezas de época. El museo también acoge exposiciones temporales y actividades culturales, manteniéndose como un punto de encuentro para el arte y la identidad local.', -17.394564364622000, -66.159138257504000, 'Calle Santivañez entre Ayacucho y Junín', '', '', 'museum', 3, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, NULL, NULL, NULL, '2025-11-06 02:37:51', '2025-11-06 02:37:51'),
(80, NULL, 'Mitru Sur Hotel La Paz', 'El Mitru Sur Hotel La Paz ofrece una estadía confortable en la zona sur de la ciudad, combinando modernidad y funcionalidad. Sus habitaciones cuentan con wifi gratuito, aire acondicionado, TV de pantalla plana y mobiliario diseñado para el confort del huésped. El hotel dispone de restaurante, cafetería, gimnasio y salas para reuniones y eventos.\n\nUbicado cerca de centros comerciales, restaurantes y principales vías de acceso, el Mitru Sur Hotel La Paz combina comodidad y ubicación estratégica. Es una opción ideal tanto para aquellos que viajan por negocios como para quienes visitan la ciudad por placer, permitiendo disfrutar de la ciudad con facilidad y confort.', -16.536479783807000, -68.076036516710000, 'Av. Fuerza Naval 948 esq. C.23 de Calacoto, La Paz, Bolivia', '', '69294553 | ventas@hotelmitrusur.com', 'accommodation', 2, '', 'Ejecutiva', 120.00, NULL, NULL, NULL, NULL, 0, 'https://www.facebook.com/hotelmitrusur/', 'https://www.instagram.com/hotelmitrusur/?hl=en', NULL, 'https://hotelmitrusur.com/?srsltid=AfmBOootwwPIlzwutReIljJZ6wgS-Bj5Kq_v_W1hTfmlvUlcDvEzUtz2', '2025-11-06 17:51:33', '2025-11-06 18:09:23'),
(81, NULL, 'Suites Camino Real', 'Suites Camino Real brinda una experiencia de hospedaje sofisticada en la zona sur de la ciudad. Sus habitaciones destacan por su amplitud, confort y equipamiento moderno, incluyendo wifi gratuito, aire acondicionado y TV de pantalla plana. Los huéspedes pueden disfrutar de su restaurante gourmet, bar, spa, piscina climatizada y gimnasio, así como de espacios para reuniones y eventos.\n\nUbicado en una de las áreas más exclusivas y tranquilas de La Paz, ofrece fácil acceso a centros comerciales, restaurantes y vías principales. Es la opción perfecta para quienes buscan combinar lujo, tranquilidad y cercanía a los principales puntos de interés de la ciudad.', -16.540956474964000, -68.089434505503000, 'Calacoto Av. Ballivián #369 esquina Calle 10, La Paz', '', '(+591) 76765709 | suites@caminoreal.com.bo', 'accommodation', 2, '', 'Suite Simple', 117.00, NULL, NULL, NULL, NULL, 0, 'https://www.facebook.com/HotelCaminoRealLaPaz', 'https://www.instagram.com/suitescaminoreal.lpb/?hl=es-la', NULL, 'https://www.caminoreal.com.bo/hotel-la-paz', '2025-11-06 17:56:31', '2025-11-06 18:10:03'),
(82, NULL, 'Hotel Calacoto', 'El Hotel Calacoto ofrece una estadía cómoda y tranquila en la zona sur de La Paz, ideal para quienes buscan descansar en un entorno residencial. Sus habitaciones cuentan con wifi gratuito, TV por cable y baño privado, algunas con hidromasaje o cocina, pensadas para brindar mayor confort a estancias cortas o prolongadas.\n\nUbicado cerca de restaurantes, comercios y accesos principales, el Hotel Calacoto combina espacios amplios, jardines y un ambiente relajado con servicios como restaurante, bar y áreas para eventos. Es una alternativa versátil tanto para viajeros de negocios como para quienes desean disfrutar de la ciudad desde un lugar apacible y accesible.', -16.540757015562000, -68.085936738928000, 'Calacoto Calle 13 esquina Sanchez Bustamante 8009 (Zona Sur) La Paz, Bolivia', '', '(+591) 69412010 | info@hotelcalacoto.com', 'accommodation', 2, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, 'https://www.instagram.com/hotelcalacoto/?hl=es-la', 'https://www.instagram.com/hotelcalacoto/?hl=es-la', NULL, 'https://www.hotelcalacoto.com/', '2025-11-06 18:03:12', '2025-11-06 18:03:12'),
(83, NULL, 'Palacio Portales', 'En la zona norte de Cochabamba se alza el Palacio Portales, una joya arquitectónica construida a inicios del siglo XX por Simón I. Patiño. Sus salones y jardines reflejan una mezcla de estilos europeos, trabajados con detalle y elegancia. Hoy, gestionado por la Fundación Simón I. Patiño, el palacio funciona como centro cultural abierto al público, con exposiciones, talleres y recorridos guiados. Es un espacio donde la historia se encuentra con la creación contemporánea, invitando a caminar, contemplar y descubrir la memoria viva de la ciudad.', -17.374609359435000, -66.153102760301000, 'Av. Potosí 1450', 'Martes a Viernes de 15:00 a 18:00 - Sabados y Domingos de 10:00 a 12:30', '', 'museum', 3, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, 'https://www.facebook.com/FundacionPatinoCochabamba?locale=es_LA', NULL, NULL, 'https://patino.org/es/lugares/palacio-portales/', '2025-11-06 18:06:42', '2025-11-06 18:06:42'),
(84, NULL, 'Casa Museo Villa Albina', 'En la Hacienda Pairumani, al pie del Tunari, Villa Albina nació como un gesto de amor de Simón I. Patiño hacia su esposa. Su arquitectura elegante, rodeada de jardines serenos y senderos que invitan al paseo, conserva el espíritu de una época marcada por encuentros, familia y visión de futuro. Hoy abierta al público como museo y espacio cultural, la villa permite recorrer habitaciones, objetos y recuerdos que dialogan con la historia boliviana. Es un lugar donde la belleza se siente en los detalles y donde pasado y comunidad se encuentran en calma y contemplación.', -17.364366777891000, -66.320632969168000, 'Av. Pairumani', 'Martes a Viernes:  9:00-16:00	-  Sabado: 10:00 – 15:00', '', 'museum', 3, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, 'https://www.facebook.com/CasaVillaAlbina', NULL, NULL, 'https://museovillaalbina.fundacionpatino.org/visitas_guiadas?active=entradas', '2025-11-06 18:13:02', '2025-11-06 18:13:02'),
(85, NULL, 'Los Parrales Hotel Resort', 'El Los Parrales Hotel Resort ofrece una estadía de lujo en un entorno soñado entre la ciudad y la naturaleza de Tarija. Sus habitaciones, decoradas con buen gusto, cuentan con wifi gratuito, aire acondicionado, minibar y balcones o terrazas con vistas al río Guadalquivir y a los jardines interiores. El hotel dispone de restaurante de cocina internacional y criolla, bar junto a la piscina, piscina exterior climatizada, spa “El Lagar” con saunas e hidromasaje, además de espacios amplios para reuniones, eventos y celebraciones.\n\nUbicado en la Urbanización El Carmen de Aranjuez Km 3,5, a solo minutos del centro de Tarija, el Los Parrales combina confort, ubicación estratégica y servicios de alta gama. Es una opción ideal para quienes buscan relajarse, disfrutar de la campiña tarijeña y acceder fácilmente a puntos de interés urbanos y turísticos.', -21.520347893440000, -64.760240993393000, 'Urbanización El Carmen de Aranjuez Km. 3,5 - Tarija - Bolivia', '', '(+591) 75111885 | reservas@losparraleshotel.com', 'accommodation', 9, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, 'https://www.facebook.com/p/Hotel-Los-Parrales-100070092252277/', 'https://www.instagram.com/losparraleshotel/', NULL, 'https://losparraleshotel.com/', '2025-11-06 18:13:58', '2025-11-06 18:16:09'),
(86, NULL, 'Hotel Mitru Tarija', 'El Hotel Mitru Tarija ofrece una estadía cómoda y moderna ideal para quienes visitan la ciudad por negocios o placer. Sus habitaciones cuentan con wifi gratuito, aire acondicionado, TV de pantalla plana y mobiliario funcional pensado para su confort. El hotel pone también a disposición restaurante, cafetería y espacios para reuniones y eventos.\n\nUbicado en Tarija, en una zona de fácil acceso desde el centro y puntos de interés, el Hotel Mitru Tarija combina ubicación estratégica y ambiente relajado. Es una opción recomendable para quienes buscan una estadía eficiente, bien localizada y con servicios adecuados para un viaje agradable.', -21.538271005889000, -64.730499630952000, 'Avenida Avaroa #450 entre Delgadillo e Isaac Attie (591-4) Tarija, Bolivia', '', '(+591) 70522513', 'accommodation', 9, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, 'https://www.facebook.com/hotelmitrutarija/?locale=es_LA', NULL, NULL, NULL, '2025-11-06 18:15:55', '2025-11-06 18:15:55'),
(87, NULL, 'Hotel Los Ceibos', 'El Hotel Los Ceibos ofrece una estadía amplia y versátil en Tarija, ideal tanto para relajarse como para organizar eventos. Las habitaciones cuentan con minibar, TV por cable y bañera de hidromasaje en muchos casos. Además, el hotel dispone de piscina al aire libre y piscina techada, sauna seco y de vapor, jacuzzi, gimnasio completo y salones para reuniones o celebraciones de hasta 1.500 personas. \n\nEl Hotel Los Ceibos combina servicios de alto nivel y ubicación accesible. Es una opción recomendable tanto para quienes buscan descansar en un entorno cómodo como para grupos y viajeros de negocios que requieren instalaciones amplias y equipadas.', -21.531323742628000, -64.739848771519000, 'Av. Panamericana 612, Tarija, Bolivia', '', '(+591) 75133800 | info@hotellosceibos.com', 'accommodation', 9, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, 'https://www.facebook.com/hotellosceibos/?locale=es_LA', NULL, NULL, 'https://www.hotellosceibos.com/', '2025-11-06 18:20:03', '2025-11-06 18:20:03'),
(88, NULL, 'Museo de Historia Natural \"Alcide d\'Orbigny\"', 'Ubicado dentro del Jardín Botánico Martín Cárdenas, el Museo Alcide d’Orbigny resguarda y difunde la riqueza natural de Bolivia. Sus salas exhiben minerales, fósiles y especies animales que revelan la diversidad y la historia de los ecosistemas del país, incluyendo ejemplares únicos como el pez fósil Sacabambaspis. Además de su exposición, el museo es un importante centro de investigación y conservación, colaborando en proyectos científicos y educativos a nivel nacional. Visitarlo es descubrir cómo la ciencia, la naturaleza y la memoria se encuentran para contar la historia viva de Bolivia.', -19.588082317937000, -65.757080203635000, 'Calle Santa Teresa s/n', 'LUNES A VIERNES: 9:00-12:00 - 15:00-18:00', '', 'museum', 3, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, NULL, NULL, NULL, '2025-11-06 18:21:44', '2025-11-06 18:21:44'),
(89, NULL, 'Real Amazonas Hotel Lodge', 'El Dorado Hotel, ofrece alojamiento confortable con una combinación de servicios para huéspedes tanto por negocios como de ocio. Sus habitaciones cuentan con aire acondicionado, TV por cable y WiFi gratis, y muchas disponen de balcón.\n\nEl hotel dispone de piscina al aire libre, bar y espacio de estacionamiento gratuito. Con recepción 24 horas, está idealmente situado para acceder a los centros de actividad de la ciudad, lo que lo convierte en una opción atractiva para quienes buscan una estadía bien localizada en la región fronteriza de Pando.', -11.026839205469000, -68.753427427059000, 'Final Avenida Internacional 583', '', '(+591) 73131618', 'accommodation', 8, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, 'https://www.facebook.com/hotelrealamazonas', NULL, NULL, NULL, '2025-11-06 18:22:30', '2025-11-06 18:22:45'),
(90, NULL, 'Dorado Hotel', 'El Dorado Hotel, ofrece alojamiento confortable con una combinación de servicios para huéspedes tanto por negocios como de ocio. Sus habitaciones cuentan con aire acondicionado, TV por cable y WiFi gratis, y muchas disponen de balcón.\n\nEl hotel dispone de piscina al aire libre, bar y espacio de estacionamiento gratuito. Con recepción 24 horas, está idealmente situado para acceder a los centros de actividad de la ciudad, lo que lo convierte en una opción atractiva para quienes buscan una estadía bien localizada en la región fronteriza de Pando.', -11.026839205469000, -68.753427427059000, 'Final Avenida Internacional 583', '', '(+591) 38422967', 'accommodation', 8, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, NULL, NULL, 'https://dorado-hotel.irelandhotel24.com/es/', '2025-11-06 18:24:16', '2025-11-06 18:24:16'),
(91, NULL, 'Hotel El Cristo', 'El Hotel El Cristo en Cobija ofrece una estadía cómoda y funcional en pleno corazón de la ciudad. Sus habitaciones cuentan con aire acondicionado, WiFi gratuito, TV de pantalla plana y baño privado, pensadas para brindar descanso tras las actividades del día.\nUbicado en la Avenida 9 de Febrero, frente a la rotonda principal, el Hotel El Cristo se sitúa en una zona de fácil acceso, cercana a aeropuertos, comercio y servicios. Ideal tanto para quienes viajan por negocios como para quienes exploran la región amazónica de Pando.', -11.027307413809000, -68.760222068683000, 'Av 9 de febrero, Cobija, Bolivia', '', '(+591) 74756249 | elcristohotel@gmail.com', 'accommodation', 8, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, 'https://www.facebook.com/HotelElCristo/?locale=es_LA', NULL, NULL, NULL, '2025-11-06 18:26:01', '2025-11-06 18:26:01'),
(92, NULL, 'Jardin Botanico Martin Cardenas', 'Creado en homenaje al botánico boliviano Martín Cárdenas, este jardín es un espacio dedicado a la conservación y estudio de la flora. Con más de 700 especies entre árboles nativos, cactus andinos, plantas medicinales y jardines ornamentales, el lugar invita a descubrir la riqueza vegetal de Bolivia. Sus senderos tranquilos, viveros y áreas de investigación lo convierten en un punto de encuentro entre ciencia, educación y naturaleza. Además, es refugio de aves urbanas y espacio para actividades ambientales y visitas educativas. Un rincón verde en la ciudad para aprender, respirar y reconectar con la vida natural.', -19.587805973976000, -65.751830742252000, 'C. R. Rivero Torrez 1630', '', '', 'attraction', 3, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, NULL, NULL, NULL, '2025-11-06 18:30:54', '2025-11-06 18:30:54'),
(93, NULL, 'La Rufina', 'La Rufina te invita a disfrutar de la auténtica gastronomía boliviana, reinterpretada con elegancia y sabor. Cada plato fusiona ingredientes 100 % bolivianos y técnicas tradicionales con un toque contemporáneo, generando sabores intensos, reconfortantes y memorables. Su ambiente cálido y refinado, junto con un servicio cuidadoso, convierten a La Rufina en el espacio ideal para una comida en familia, una cena de amigos, la celebración de un cumpleaños o una reunión ejecutiva.', -16.511327194764000, -68.128369325284000, 'Calle Belisario Salinas #572', '', '(+591) 68216777 | LaRufinabolivia@gmail.com', 'restaurant', 2, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, 'https://www.facebook.com/LaRufinaBolivia/?locale=es_LA', 'http://instagram.com/larufinaboliva', NULL, 'https://larufinabolivia.com/?fbclid=IwY2xjawN4W01leHRuA2FlbQIxMABicmlkETFIWEdsc1A3a2FiWDVHOGZCc3J0YwZhcHBfaWQQMjIyMDM5MTc4ODIwMDg5MgABHtfWFGeImiYeEaVn1JHFqRDkYjBv3JKPGZtM8eyZiNsqvATqt3AdJpHtOX0D_aem_1GXFC-FhfaSjaoju1Vz1gQ', '2025-11-06 18:34:15', '2025-11-06 18:34:15'),
(94, NULL, 'Popular Cocina Boliviana', 'Popular Cocina Boliviana te invita a saborear lo mejor de la cocina tradicional de Bolivia, reinterpretada con creatividad y dedicación. Cada plato rememora raíces auténticas y está elaborado con ingredientes locales frescos, destacando los sabores típicos de La Paz y sus alrededores. Su ambiente acogedor y familiar, junto con un servicio cordial, convierte a Popular en el sitio ideal para disfrutar de una comida casera, compartir un almuerzo con amigos, celebrar momentos especiales o vivir la esencia de la gastronomía boliviana.', -16.496027428758000, -68.138277003672000, 'Calle Murillo 826, La Paz, Bolivia', '', '', 'restaurant', 2, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, 'https://www.facebook.com/popularlapazbolivia/?locale=es_LA', 'https://www.instagram.com/popularbolivia?fbclid=IwY2xjawN4XLpleHRuA2FlbQIxMABicmlkETFIWEdsc1A3a2FiWDVHOGZCc3J0YwZhcHBfaWQQMjIyMDM5MTc4ODIwMDg5MgABHiaQW8J4zmhnsXV7bK4XAG1QU819YWoB2cI9weWnWb-Rxh7XFgmisPsrEnQP_aem_iq4_lht08uHdPEjLtnyQ9Q', NULL, NULL, '2025-11-06 18:36:55', '2025-11-06 18:36:55'),
(95, NULL, 'Catedral Metropolitana de San Sebastián', 'Ubicada en el corazón de la ciudad, la Catedral Metropolitana de San Sebastián es uno de los símbolos más representativos de Cochabamba. Su construcción se inició en el siglo XVI y fue ampliada durante el periodo colonial, combinando elementos barrocos y neoclásicos en una fachada de piedra que destaca por su detalle y armonía. En su interior conserva imágenes históricas como San Sebastián y la Virgen de la Merced, profundamente veneradas por la población. Además de ser un espacio de fe, la catedral forma parte esencial del patrimonio arquitectónico y cultural de la región, siendo escenario de celebraciones y encuentros que acompañan la vida de la ciudad.', -17.394350429531000, -66.156508151478000, 'Plaza 14 de septiembre', '', '', 'attraction', 3, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, NULL, NULL, NULL, '2025-11-06 18:40:19', '2025-11-06 18:40:19'),
(96, NULL, 'Typica', 'Típica te transporta al corazón del café boliviano, donde el aroma del grano recién tostado se mezcla con un ambiente moderno y acogedor. Cada taza refleja la pasión por el cultivo local y el tueste artesanal, mientras el menú acompaña con platos que reinterpretan ingredientes bolivianos con elegancia. Su espacio cuidado, servicio atento y atmósfera relajada lo convierten en el lugar ideal para un desayuno tranquilo, un almuerzo creativo o una pausa con amigos.\n\n¡Descubre el café de Bolivia elevado a otra categoría!', -16.511001072822000, -68.124562402940000, 'Av.6 de Agosto 2584', 'Lunes a Sábado 07:30 - 22:00', '(+591) 63263141 | contacto@typicabolivia.com', 'restaurant', 2, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, 'https://www.facebook.com/typica.cafe/', 'https://www.instagram.com/typica.cafe/', NULL, 'https://www.typica.com.bo/', '2025-11-06 18:52:11', '2025-11-06 21:14:51'),
(97, NULL, 'Convento Museo Santa Teresa', 'Fundado en el siglo XVIII, el Monasterio de Santa Teresa es uno de los conjuntos coloniales más emblemáticos de Cochabamba. Su arquitectura barroca, con muros gruesos y techos originales de teja, resguarda la historia y la vida contemplativa de las Carmelitas Descalzas que habitaron este espacio durante siglos. Hoy, convertido en museo, permite recorrer claustros silenciosos, celdas, salas y templos que revelan una espiritualidad profundamente ligada a la historia de la ciudad. Declarado Monumento Nacional, el monasterio es un lugar donde la memoria religiosa, el arte y la arquitectura se encuentran en un ambiente de quietud y recogimiento.', -17.389589606545000, -66.158080104462000, 'Calle Baptista', '', '', 'museum', 3, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, NULL, NULL, NULL, '2025-11-06 18:54:34', '2025-11-06 18:54:34'),
(98, NULL, 'Gattopardo', 'Gattopardo te da la bienvenida al centro de Tarija, en un espacio donde la comida criolla boliviana se mezcla con un ambiente urbano contemporáneo. Cada plato destaca por el uso de ingredientes locales frescos y recetas con raíces, mientras que su carta de vinos chapacos y cócteles bien preparados refleja el buen gusto de la región. Su terraza junto a la plaza, combinada con un servicio atento y un ambiente cómodo para compartir, convierte a Gattopardo en el lugar ideal para un almuerzo relajado, una cena con amigos o un evento casual de negocios.', -21.533591221439000, -64.733850078046000, 'La Madrid, Tarija', '', '', 'restaurant', 9, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, 'https://www.facebook.com/GattopardoTarija/?locale=es_LA', NULL, NULL, 'https://www.gattopardorestaurante.com/?fbclid=IwY2xjawN5iVxleHRuA2FlbQIxMABicmlkETFTano4TTN5d0ZKdEZYMVRic3J0YwZhcHBfaWQQMjIyMDM5MTc4ODIwMDg5MgABHt3V9RadxAEZWhubE10vRbE3wozGzCGCkPH1tfZgYsnvDnnxpDkH2m04WBg2_aem_N3PMbGXL8a-B-aO5abK_Xg', '2025-11-06 19:00:56', '2025-11-06 19:01:14'),
(99, NULL, 'Casona del Molino', 'La Casona del Molino te invita a vivir una experiencia gastronómica donde la tradición se encuentra con la elegancia. El edificio, declarado Patrimonio Cultural desde 1822, ofrece un ambiente sofisticado y acogedor mientras que la carta se especializa en cortes de carne de primera calidad, acompañados de una cuidada selección de vinos nacionales e internacionales, con más de 700 etiquetas disponibles para maridar cada plato a la perfección. Cada visita está diseñada para convertirse en una experiencia memorable, ya sea un almuerzo en familia, una cena con amigos, una celebración especial o una reunión de negocios.', -21.530455854621000, -64.739440541157000, 'Calle Bolivar Final Esq Ingavi (Loma de San Juan)', '', '(+591) 78701001', 'restaurant', 9, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, 'https://www.facebook.com/profile.php?id=100063722902292#', 'https://www.instagram.com/casona_del_molino/', NULL, 'https://casonadelmolino.com/delivery?fbclid=IwY2xjawN4c79leHRuA2FlbQIxMABicmlkETE5TDBCQUh5M1hCNUlqMVpZc3J0YwZhcHBfaWQQMjIyMDM5MTc4ODIwMDg5MgABHtkc9W8gspj46ctwO-xM0uzIKWquEajZIABi387xqaWprF92Qa91k0RaNb9S_aem_nnKAS2zdS9Vv-rH79NJaFw', '2025-11-06 19:04:34', '2025-11-06 19:04:34'),
(100, NULL, 'Belen Restaurante', 'Belén Restaurante es un espacio donde la elegancia, la calidez y el buen gusto se encuentran. Nuestra propuesta combina la tradición de la pastelería artesanal con una cocina contemporánea que resalta los sabores de Bolivia. Cada plato y postre es elaborado con ingredientes seleccionados, cuidando cada detalle desde la presentación hasta el sabor en un ambiente luminoso, acogedor y lleno de estilo.\n\nIdeal para compartir en familia, con amigos o en pareja, Belén es también el lugar perfecto para celebraciones especiales, encuentros de negocios o una pausa deliciosa durante el día.', -21.534788484987000, -64.732260165439000, 'Calle Colón entre calle 15 de Abril y calle La Madrid  Colon #536', '', '(+591) 75112000 - (4)6675838 | info.cafebelen@gmail.com', 'restaurant', 9, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, 'https://www.facebook.com/BelenRestauranteCafe', 'https://www.instagram.com/belen_restaurante?fbclid=IwY2xjawN4ddFleHRuA2FlbQIxMABicmlkETE5TDBCQUh5M1hCNUlqMVpZc3J0YwZhcHBfaWQQMjIyMDM5MTc4ODIwMDg5MgABHtkc9W8gspj46ctwO-xM0uzIKWquEajZIABi387xqaWprF92Qa91k0RaNb9S_aem_nnKAS2zdS9Vv-rH79NJaFw', NULL, 'https://www.belenrestaurante.com/?fbclid=IwY2xjawN4dAZleHRuA2FlbQIxMABicmlkETE5TDBCQUh5M1hCNUlqMVpZc3J0YwZhcHBfaWQQMjIyMDM5MTc4ODIwMDg5MgABHkoly0boL-p5x6FFsNBrVHeqwZSqXKAqOQUCm2KrLbiBDuvF9MFyKWlMNciO_aem_wmWnMIR15PRtN_GdzbunIQ', '2025-11-06 19:06:35', '2025-11-06 19:06:35'),
(101, NULL, 'Las Palmas Restaurant Karaoke', 'Las Palmas Restaurante combina la riqueza de la cocina amazónica y boliviana con un ambiente cálido y animado. Los cortes a la parrilla, pescados frescos de la región y platos tradicionales con yuca y plátano invitan a deleitarse en cada bocado. \n\nEl espacio está diseñado para compartir momentos: sea un almuerzo en familia, una cena con amigos o una salida especial. La atención personalizada y el entorno acogedor hacen de Las Palmas un destino ideal para disfrutar de lo mejor de Pando.', -11.019801789859000, -68.759921375631000, 'Av. Chelio Luna Pizarro Esq. Walter Fernandez Puerto Cobija, Bolivia', '', '(+591) 69204163', 'restaurant', 8, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, 'https://www.facebook.com/laspalmas.bo?locale=es_LA', NULL, NULL, NULL, '2025-11-06 19:08:09', '2025-11-06 19:08:09'),
(102, NULL, 'La casa del Asaí', 'La Casa del Asaí se presenta como un espacio dedicado al fruto amazónico del asaí, valorado por sus propiedades nutritivas y su sabor distintivo.\n\nCada visita ofrece la oportunidad de disfrutar de batidos, cremas y productos elaborados con asaí, preparados con esmero para realzar la riqueza natural de la Amazonía boliviana. El ambiente es cálido, moderno y pensado para que tanto locales como visitantes se sientan acogidos.\n\nIdeal para una pausa refrescante, ¡Déjate sorprender por el sabor del asaí amazónico!', -11.012358020323000, -68.753684634049000, 'Av. 9 de Febrero 240, Cobija', '', '(+591) 77462912 | ronal1766388vasquez@gmail.com', 'restaurant', 8, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, 'https://www.facebook.com/LaCasaDelAsai?locale=es_LA', NULL, NULL, NULL, '2025-11-06 19:11:40', '2025-11-06 19:11:40'),
(104, NULL, 'Tiwanaku', 'Se erige en el altiplano como uno de los destinos turísticos y culturales más emblemáticos de Bolivia, cuna de civilizaciones precolombinas que dejaron huella en la historia. \n \n Entre sus tesoros, la Puerta del Sol, el Templete Semisubterráneo, la majestuosa Pirámide de Akapana y el enigmático Puma Punku se presentan como guardianes del ingenio, el conocimiento astronómico y la cosmovisión de la cultura tiwanakota, dejando a cada visitante maravillado ante su monumentalidad. \n \n Así, cada paso se convierte en un viaje que une pasado y presente, invitando a vivir su verdadera esencia.', -16.557432814578000, -68.675265306253000, '', '', '', 'attraction', 2, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, NULL, NULL, NULL, '2025-11-25 00:37:59', '2025-11-25 20:52:39'),
(105, NULL, 'Copacabana', 'Copacabana se alza a orillas del mítico lago Titicaca, el lago navegable más alto del mundo y cuna de numerosas culturas andinas. Es la ciudad principal donde los visitantes descubren la magia del Titicaca, un centro turístico y de peregrinación que refleja su riqueza cultural. \n \n Miles de peregrinos llegan cada año a la Basílica de Copacabana para venerar a la Virgen, mientras otros recorren las aguas del lago. También se encuentra el Calvario, cuya ascensión es una tradición especial durante la Semana Santa. Cerca del pueblo reposan vestigios prehispánicos como la Horca, el Baño y el Asiento del Inca, testigos de un legado histórico que se extiende también a las islas del Sol y de la Luna, invitando al viajero a recorrer su territorio.', -16.165427310386000, -69.085396047309000, '', '', '', 'attraction', 2, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, NULL, NULL, NULL, '2025-11-25 00:39:30', '2025-11-25 20:53:14');
INSERT INTO `locations` (`id`, `user_id`, `name`, `description`, `latitude`, `longitude`, `address`, `opening_hours`, `contact_info`, `type`, `department_id`, `badge`, `room_type`, `price_per_night`, `start_date`, `end_date`, `event_type`, `capacity`, `is_recurring`, `facebook`, `instagram`, `whatsapp`, `link`, `created_at`, `updated_at`) VALUES
(106, NULL, 'Apolobamba, por la Ruta de los Kallawayas', 'La Ruta de los Kallawayas atraviesa la Cordillera de Apolobamba. Ofrece un viaje donde el turismo cultural y de naturaleza se entrelaza con la historia y el misterio de estas tierras de niebla. Este territorio es hogar de chamanes expertos en medicina herbal y en curación ritual, portadores de un conocimiento que se transmite de generación en generación. \n \n Kallawaya, que en quechua significa “el que lleva plantas a la espalda”, hace referencia a estos curanderos itinerantes que viajan con sus hierbas y remedios para sanar. Reconocidos históricamente como los médicos oficiales de la nobleza inca, recorrían todo el mundo andino y más allá, ofreciendo sus conocimientos, curando, intercambiando y compartiendo sus preparados.', -15.176359411216000, -68.995125034166000, '', '', '', 'attraction', 2, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, NULL, NULL, NULL, '2025-11-25 00:40:32', '2025-11-25 20:53:26'),
(107, NULL, 'Arani', 'Arani, tierra del pan y del viento, es mucho más que un destino: es un viaje a la tradición cochabambina. Al llegar, el aire cálido recibe al visitante con el aroma inconfundible del pan recién horneado, elaborado con manos expertas que han heredado este arte de generación en generación. \n Sus calles tranquilas y empedradas invitan a caminar sin prisa, mientras las fachadas coloniales y la calidez de su gente hacen sentir a quien llega como parte de su historia. La devoción a la Virgen La Bella se percibe en cada rincón, especialmente en agosto cuando Arani se llena de música, fe y color durante una de las fiestas más emblemáticas del valle.', -17.573260292562000, -65.768082869845000, '', '', '', 'attraction', 3, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, NULL, NULL, NULL, '2025-11-25 00:41:20', '2025-12-02 21:15:15'),
(108, NULL, 'Totora', '\"Cochabamba, Totora: Historia, Arte y Naturaleza\", reconocida por sus calles de trazo irregular, adaptadas a la topografía del valle, conservan un encanto singular que ha resistido al paso del tiempo. Viejas casonas señoriales y templos de estilo colonial revelan la importancia que tuvo esta población en épocas pasadas.\n \nEl ambiente artístico de Totora nace de sus callejuelas angostas y empinadas, donde pintores, fotógrafos y viajeros encuentran inspiración en cada rincón. Aquí, la arquitectura, la cultura y la naturaleza se entrelazan para dar vida a un destino que preserva con orgullo su identidad.', -17.735640952954000, -65.191259862886000, '', '', '', 'attraction', 3, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, NULL, NULL, NULL, '2025-11-25 00:41:55', '2025-12-02 21:15:51'),
(109, NULL, 'Corredor turístico del Valle hacia el Caine \"Donde la tradición y la aventura, se viven\"', 'El Corredor Turístico del Valle hacia El Caine, “Donde la tradición y la aventura se viven”, reúne una notable diversidad cultural, natural y gastronómica. Está conformado por los municipios de Anzaldo, Arbieto y Tarata, junto con la Mancomunidad de Municipios de la Cuenca del Caine, conectados a través de la ciudad de Cochabamba como centro de distribución. \n \nEste corredor conecta atractivos turísticos que permiten recorrer comunidades del valle, donde se preservan costumbres, arquitectura y celebraciones propias de la región. Combina sitios paleontológicos y espacios naturales con actividades de observación de flora y fauna, además de una destacada gastronomía local. Su enfoque se centra en el turismo comunitario, impulsando la conservación y el valor cultural del territorio a través de experiencias compartidas con sus habitantes.', -17.778966870977000, -65.932138928063000, '', '', '', 'attraction', 3, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, NULL, NULL, NULL, '2025-11-25 00:43:00', '2025-12-02 21:16:19'),
(110, NULL, 'Sorata', 'Sorata, conocida como Paraíso Terrenal, cautiva por la armonía de sus paisajes, donde convergen ecosistemas que combinan la fuerza de la montaña con la frescura de los bosques húmedos. Ubicada en el departamento de La Paz en las faldas del imponente Illampu y bañada por un clima templado, se despliega en un valle que descansa bajo la Cordillera Real, ofreciendo un refugio natural lleno de serenidad.\n \nEntre sus mayores encantos se encuentran la Gruta de San Pedro, el tradicional puente colgante, miradores con panorámicas inolvidables y lagunas glaciares como Chilata y Glaciar, rodeadas de paisajes que invitan a la aventura. Además, Sorata es punto de partida ideal para quienes buscan ascender a los nevados.', -15.773091513178000, -68.649928001475000, '', '', '', 'attraction', 2, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, NULL, NULL, NULL, '2025-11-25 00:43:28', '2025-12-02 21:17:26'),
(111, NULL, 'Trinidad', 'Trinidad, te va a enamorar. Es la capital del Beni y un destino donde naturaleza, historia y hospitalidad se entrelazan para brindar una experiencia auténtica en el corazón de la Amazonía boliviana. Rodeada por los ríos Ibare y Mamoré, invita a vivir aventuras como paseos fluviales, avistamiento de fauna y visitas a áreas protegidas, entre ellas el Parque Municipal Ibare–Mamoré, refugio de una biodiversidad excepcional con delfines rosados, aves exóticas y una vegetación que deslumbra en cada recorrido.', -14.835022834379000, -64.904139410929000, '', '', '', 'city', 7, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, NULL, NULL, NULL, '2025-11-25 00:44:33', '2025-12-02 21:17:46'),
(112, NULL, 'Roboré', 'Roboré(Santa Cruz) cuyo nombre en lengua chiquitano-guaraní significa “piedra redonda”, refleja la presencia de formaciones rocosas que caracterizan su paisaje. Este destino destaca por su entorno natural privilegiado: ríos de aguas cristalinas que forman cascadas y balnearios, aguas termales que invitan al descanso y senderos que conducen al corazón del Bosque Seco Chiquitano y a zonas con arte rupestre. \n \nEntre sus imperdibles se encuentran los balnearios naturales y las caídas de agua que atraviesan el territorio, mientras que en Chochís se puede admirar una vista imponente del monumento natural conocido como la Torre de David, un símbolo majestuoso dentro de este territorio', -18.330674950978000, -59.756231420764000, '', '', '', 'attraction', 6, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, NULL, NULL, NULL, '2025-11-25 00:45:46', '2025-12-02 21:18:13'),
(113, NULL, 'Parque Nacional y Área de Manejo Integrado Kaa Iya: Biodiversidad', 'Parque Nacional y Área de Manejo Integrado Kaa Iya: Biodiversidad. Entre sus principales atractivos destacan los Bañados del Izozog y el río Parapetí, que conforman el humedal más extenso y valioso del Chaco cruceño, reconocido como Sitio Ramsar desde 2001. A ellos se suman otros espacios de gran belleza natural como el Palmar de las Islas, Fortín Ravelo, Laguna Porvenir y Yandeyari, que ofrecen paisajes únicos para vivir experiencias de ecoturismo y conexión con la naturaleza chaqueña.', -19.105697922677000, -61.700564090173000, '', '', '', 'attraction', 6, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, NULL, NULL, NULL, '2025-11-25 00:46:32', '2025-12-02 21:18:48'),
(114, NULL, 'Cobija', 'Cobija, capital del departamento de Pando, ubicada en plena Amazonía boliviana y a orillas del río Acre, destaca por su posición fronteriza con Brasil, que la convierte en un punto de encuentro cultural y comercial. Es un destino ideal para quienes desean adentrarse en la Amazonía de manera tranquila, lejos de las multitudes.\n \nCon una historia marcada por el auge del caucho y la vida fronteriza, Cobija combina el encanto urbano con la riqueza natural que la rodea. Así, se presenta como un lugar perfecto para descubrir la esencia amazónica desde una perspectiva cercana, cálida y auténtica.', -11.018295133067000, -68.753679290616000, '', '', '', 'city', 8, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, NULL, NULL, NULL, '2025-11-25 00:47:13', '2025-12-02 21:19:05'),
(115, NULL, 'Reserva Nacional de Vida Silvestre Amazónica Manuripi', 'La Reserva Nacional de Vida Silvestre Amazónica Manuripi fue creada para resguardar el bosque tropical húmedo, sus ríos y la extraordinaria biodiversidad que allí se conserva. En este entorno, la vida silvestre prospera y las comunidades locales encuentran sustento en recursos como la castaña amazónica y el asaí, actividades que mantienen un equilibrio con la naturaleza.\n \nLos paisajes de la reserva cautivan con la inmensidad de sus selvas y cursos de agua. Los ríos Manuripi, Tahuamanu y Madre de Dios atraviesan este territorio preservado, mientras que el Lago Bay destaca como un refugio de aguas claras rodeadas de vegetación exuberante. Un destino donde la Amazonía se muestra en toda su riqueza y su encanto natural.', -11.616427780940000, -67.666221156936000, '', '', '', 'attraction', 8, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, NULL, NULL, NULL, '2025-11-25 00:48:04', '2025-12-02 21:19:25'),
(116, NULL, 'Cotoca', 'Cotoca, en el departamento de Santa Cruz, es un pueblo que conserva el encanto tradicional del oriente boliviano. Su identidad gira en torno al Santuario de la Virgen de Cotoca, patrona de la región, cuya devoción convoca a miles de peregrinos cada año, especialmente durante la festividad del 8 de diciembre. La arquitectura colonial de su templo y el ambiente de fe que se respira en sus calles hacen de este destino un referente espiritual de Bolivia.\n \nEl talento artesanal de su gente se refleja en las piezas de arcilla que se elaboran y exhiben cada fin de semana, transformando sus plazas en auténticas galerías al aire libre. A ello se suma su mercado local, donde los visitantes pueden degustar la gastronomía típica y una amplia variedad de masitas y dulces tradicionales.\n \nDeclarada Patrimonio Cultural y Religioso de Bolivia, Cotoca te invita a vivir su fe y sus tradiciones más arraigadas.', -17.754349767169000, -62.996002646034000, '', '', '', 'city', 6, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, NULL, NULL, NULL, '2025-11-25 00:48:44', '2025-12-02 21:20:16'),
(117, NULL, 'Ruta del Bufeo: Guardianes del Río Tesoro de Bolivia', 'La Ruta del Bufeo, en el departamento del Beni, invita a encontrarse con el bufeo boliviano (Inia boliviensis), el delfín rosado que habita únicamente en los ríos amazónicos de Bolivia. Sus apariciones en la superficie y sus saltos juguetones parecen regalar sonrisas, despertando asombro y ternura en quienes los contemplan.\n \nEl recorrido inicia en Puerto Ballivián y se adentra en el Área Protegida Ibare–Mamoré, un territorio donde podrás adentrarte en la naturaleza de cerca y donde cada avistamiento se convierte en un recordatorio del valor y la fragilidad de la vida amazónica.', -14.830307491809000, -65.008097689391000, '', '', '', 'attraction', 7, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, NULL, NULL, NULL, '2025-11-25 00:50:10', '2025-12-02 21:20:52'),
(118, NULL, 'Colomi Ecoturística', 'Colomi es un destino que cautiva por su naturaleza y su riqueza cultural. Entre sus principales atractivos se encuentra la Laguna Corani, un cuerpo de agua artificial rodeado de bosques de pinos y montañas, en el camino hacia el Trópico de Cochabamba. Navegar por sus aguas es una actividad imperdible para quienes visitan la zona. Otro atractivo destacado es Incachaca, un sitio arqueológico que conserva vestigios de la ingeniería incaica, como fuertes, puentes y escalones construidos en piedra.\n \n La experiencia se completa con su gastronomía local: la trucha, presente en abundancia en las lagunas, y el tradicional guindo, una bebida fermentada obtenida de la guinda, que se produce y promociona en la región desde hace más de 18 años', -17.338264626712000, -65.868298387037000, '', '', '', 'attraction', 3, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, NULL, NULL, NULL, '2025-11-25 00:50:48', '2025-12-02 21:21:40'),
(119, NULL, 'Parque Nacional y Área Natural de Manejo Integrado Cotapata', 'Donde las montañas se enlazan con los bosques yungueños, se encuentra el Parque Nacional y Área Natural de Manejo Integrado Cotapata. Los ríos que nacen en sus montañas recorren el parque llevando agua pura a las comunidades y abasteciendo a las ciudades de La Paz y El Alto, un recordatorio constante de la importancia de preservar este equilibrio. Por eso, Cotapata fue creado para proteger fauna endémica y asegurar que los recursos naturales se utilicen de manera sostenible.\n \nEn medio de todo este entorno surge la carretera mundialmente conocida: el antiguo camino hacia los Yungas, hoy el famoso “Camino de la Muerte”. Así, Cotapata no solo es escenario de adrenalina, sino también un refugio de vida.', -16.198632599969000, -67.899430521652000, '', '', '', 'attraction', 2, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, NULL, NULL, NULL, '2025-11-25 00:51:42', '2025-12-02 21:22:37'),
(120, NULL, 'Villa Montes', 'En el sur de Bolivia, Villa Montes, conocida por su papel durante la Guerra del Chaco, resguarda una memoria que aún se siente en sus calles y espacios emblemáticos.\n \nEl río Pilcomayo atraviesa la región y brinda escenarios ideales para la pesca, la navegación y el descanso a orillas de sus aguas. Hacia el Angosto, las formaciones rocosas se elevan imponentes, creando un paisaje desafiante para los amantes de la aventura. Muy cerca, el Parque Nacional Aguaragüe se convierte en un refugio de biodiversidad, donde los senderos permiten descubrir la riqueza de la flora y avistamiento de aves en un entorno natural privilegiado. Villa Montes, Tarija, es también un punto de encuentro cultural, donde las tradiciones de los pueblos Guaraní, Weenhayek y Tapiete aún se mantienen vivos.', -21.260916169499000, -63.476075623803000, '', '', '', 'city', 9, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, NULL, NULL, NULL, '2025-11-25 00:52:28', '2025-12-02 21:23:27'),
(121, NULL, 'Tahua', 'Tahua se encuentra a los pies del imponente volcán Tunupa, en el Departamento de Potosí. Considerado un estratovolcán cónico formado por capas de lava endurecida y actualmente inactivo. Desde sus faldas, el mirador y observatorio astronómico ofrece vistas panorámicas del vasto Salar de Uyuni, sus islas y las cimas del cerro, mientras que el ascenso al volcán permite contemplar el desierto de sal desde alturas impresionantes, revelando su magnitud. \n \nEl entorno de Tahua está dominado por cactus y queñuas, y su fauna es igualmente sorprendente. En sus llanos se observan avestruces, vizcachas ariscas y zorros astutos, mientras que las lagunas reciben bandadas de flamencos de plumaje rosado y blanco. Además, manadas de llamas y esbeltas vicuñas recorren este paisaje singular.', -19.890877683586000, -67.696087869838000, '', '', '', 'attraction', 5, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, NULL, NULL, NULL, '2025-11-25 00:53:31', '2025-12-02 21:24:08'),
(122, NULL, 'San Xavier: Corazón Vivo de las Misiones Jesuíticas', 'Tahua se encuentra a los pies del imponente volcán Tunupa, en el Departamento de Potosí. Considerado un estratovolcán cónico formado por capas de lava endurecida y actualmente inactivo. Desde sus faldas, el mirador y observatorio astronómico ofrece vistas panorámicas del vasto Salar de Uyuni, sus islas y las cimas del cerro, mientras que el ascenso al volcán permite contemplar el desierto de sal desde alturas impresionantes, revelando su magnitud. \n \nEl entorno de Tahua está dominado por cactus y queñuas, y su fauna es igualmente sorprendente. En sus llanos se observan avestruces, vizcachas ariscas y zorros astutos, mientras que las lagunas reciben bandadas de flamencos de plumaje rosado y blanco. Además, manadas de llamas y esbeltas vicuñas recorren este paisaje singular.', -16.274151450373000, -62.504457313659000, '', '', '', 'attraction', 6, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, NULL, NULL, NULL, '2025-11-25 00:54:49', '2025-12-02 21:25:06'),
(123, NULL, 'Mizque, Valle Mágico del Cono Sur', 'Mizque (Cochabamba), cuyo nombre proviene del quechua misk\'i, que significa \"dulce\", es conocida como la ciudad de los 500 quitasoles, en alusión a las sombrillas que las señoras de la nobleza utilizaban como símbolo de distinción. Esta pequeña y acogedora ciudad se encuentra en el valle alto del departamento, ofreciendo un clima privilegiado y la calidez propia de los valles bolivianos.\n \n Su encanto colonial se refleja en casas y edificaciones bien conservadas, mientras que el Puente de Los Libertadores, construido en la época colonial sobre el río Kuri, recuerda el paso del Libertador Simón Bolívar rumbo a la Ciudad de la Plata durante su recorrido por el Alto Perú.', -17.941000000000000, -65.340200000000000, '', '', '', 'city', 3, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, NULL, NULL, NULL, '2025-11-25 00:55:21', '2025-12-02 22:20:32'),
(124, NULL, 'Guayaramerín, la Joya de la Amazonía', 'Guayaramerín, su nombre en tupí-guaraní significa “cachuela chica” o “pequeña cascada”, evoca los rápidos del río Mamoré que, desde siempre, han marcado la identidad de esta región. La ciudad nació como parte de un esfuerzo por impulsar el desarrollo del norte boliviano, facilitando el comercio y la explotación del caucho durante los años de la “fiebre del caucho”, cuando la Amazonía boliviana se convirtió en escenario de historia y progreso.\n \n Ubicada en la cuenca amazónica en el departamento del Beni, Guayaramerín se despliega sobre selvas húmedas y terrenos planos, atravesada por los ríos Mamoré, el Beni y el Yata.', -10.826558203097000, -65.356571332245000, '', '', '', 'city', 7, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, NULL, NULL, NULL, '2025-11-25 00:57:30', '2025-12-02 22:21:21'),
(125, NULL, 'Territorio Indígena y Parque Nacional Isiboro Sécure (TIPNIS)', 'El Territorio Indígena y Parque Nacional Isiboro Sécure (TIPNIS) es considerado un universo verde que resguarda una de las mayores concentraciones de vida del planeta. Considerada una de las áreas protegidas con mayor biodiversidad después del Madidi, es un refugio natural que la ciencia aún conoce de manera limitada, lo que aumenta su valor ecológico y la necesidad de su protección.\n \nSu nombre proviene de los ríos Isiboro y Sécure, cursos de agua que delinean gran parte de este territorio y sostienen la vida de la selva. Estos bosques funcionan como un pulmón natural y una bomba de agua decisiva para la regulación climática del país, garantizando humedad, oxígeno y equilibrio ambiental a toda la región.\n \nEl TIPNIS se convierte así en un espacio donde la naturaleza se manifiesta en su estado más puro.', -16.406583923308000, -66.046338813391000, '', '', '', 'attraction', 7, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, NULL, NULL, NULL, '2025-11-25 00:58:46', '2025-12-02 22:22:05'),
(126, NULL, 'Caranavi', 'Caranavi, ubicado en los Yungas del departamento de La Paz, se presenta como un destino ideal para el ecoturismo, el agroturismo y la aventura. Su clima agradable y la abundancia de riqueza natural crean un entorno perfecto para desconectarse de la cotidianidad. \n \nEntre sus atractivos destacan las caídas de agua y los ríos que invitan a practicar actividades de turismo extremo, así como los recorridos por las Rutas del Café, donde los visitantes pueden conocer la producción de café de alta calidad, uno de los mayores orgullos de la región. Caranavi combina así naturaleza, cultura productiva y aventura.', -15.833773757288000, -67.565616026105000, '', '', '', 'city', 2, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, NULL, NULL, NULL, '2025-11-25 01:00:13', '2025-12-02 22:22:25'),
(127, NULL, 'Ruta Precolombina del Takesi', 'El antiguo camino precolombino del Takesi forma parte del gran Qhapaq Ñan, la red vial andina que conectó civilizaciones enteras. Sus piedras colocadas hace siglos, permanecen sorprendentemente intactas, guiando a los viajeros por paisajes donde la historia y la montaña se entrelazan.\n \nLa travesía inicia entre cumbres imponentes y desciende progresivamente hacia la calidez de los Yungas, revelando en cada tramo el contraste entre la puna andina y la vegetación exuberante del bosque nuboso. Caminar el Takesi es adentrarse en un sendero que invita a vivir la profundidad cultural y natural de los Andes bolivianos.', -16.476559748161000, -67.862999405122000, '', '', '', 'attraction', 2, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, NULL, NULL, NULL, '2025-11-25 01:01:39', '2025-12-02 22:22:54'),
(128, NULL, 'Ruta de Yunga Cruz', 'En la provincia Sud Yungas, el camino prehispánico Yunga Cruz se abre paso entre cumbres y abismos uno de los senderos precolombinos más exigentes de la región, conecta el altiplano y los valles templados del sur de La Paz con la zona subtropical de los Yungas, culminando en la localidad de Chulumani.\n \nPor sus recorridos se revelan vestigios que narran el paso de antiguos viajeros, apachetas, cabañas de piedra y sitios arqueológicos que guardan el misterio de culturas milenarias. Entre la piedra, la neblina y la vegetación que cubre las laderas, el camino se abre paso por alturas que regalan miradores naturales desde los cuales se puede apreciar la imponencia del Illimani, acompañando al viajero antes de internarse en los dominios verdes del bosque yungueño.', -16.580290000000000, -67.694080000000000, '', '', '', 'attraction', 2, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, NULL, NULL, NULL, '2025-11-25 01:02:45', '2025-12-02 22:23:18'),
(129, NULL, 'Coripata Vive la aventura, siente la cultura', 'Coripata (La Paz), cuyo nombre en aymara significa “Altura del Oro”, remite a su pasado como campamento minero, donde los pobladores extraían el oro del río Peri. \n \n Hoy su territorio conserva la fauna característica de los Yungas, y desde lo alto, el CORIPARAPENTE permite elevarse en un planeador flexible para contemplar el paisaje en toda su magnitud de laderas teñidas de verde que se funden con el horizonte y el cielo. Cada vuelo es una invitación a descubrir Coripata con todos los sentidos.', -16.314072646219000, -67.606691054713000, '', '', '', 'attraction', 2, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, NULL, NULL, NULL, '2025-11-25 01:04:05', '2025-12-02 22:24:05'),
(130, NULL, 'Irupana Ecológica Turística', 'Irupana en La Paz, es el escenario del Irupanapente, el espectáculo anual de vuelos en parapente que atrae a aventureros y visitantes de todo el país, elevando al viajero sobre laderas verdes y ríos cristalinos mientras contempla la inmensidad del paisaje yungueño.\n \nEl clima generoso de la región también da vida a cultivos de café, cacao y una gran variedad de frutas tropicales, cuyos sabores se descubren en los mercados locales o directamente en las fincas, conectando al visitante con la tierra y sus tradiciones. Irupana invita a recorrer sus senderos, a sentir la emoción del vuelo y a disfrutar de la riqueza natural y cultural que fluye en cada rincón del municipio.', -16.526879495786000, -67.404156334387000, '', '', '', 'attraction', 2, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, NULL, NULL, NULL, '2025-11-25 01:06:08', '2025-12-02 22:25:46'),
(131, NULL, 'Quillacollo: Urcupiña madre de la integración', 'Quillacollo, en el departamento de Cochabamba, es un destino que integra historia, cultura y espiritualidad en un entorno acogedor. Su mayor símbolo es la Festividad de la Virgen de Urkupiña, una de las celebraciones religiosas más representativas de Bolivia, que cada agosto convoca a miles de peregrinos y visitantes. En esos días, la ciudad se transforma en un escenario lleno de color, danzas, música y ferias artesanales, donde devotos de todo el país y del continente llegan para rendir homenaje a la patrona de la integración nacional.', -17.394837568723000, -66.281098602084000, '', '', '', 'event', 3, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, NULL, NULL, NULL, '2025-11-25 01:06:54', '2025-12-02 22:26:16'),
(132, NULL, 'Parque Nacional Área Natural de Manejo Integrado Amboró', 'El Amboró, situado en el llamado “Codo de los Andes” en Santa Cruz, es un territorio donde la biodiversidad se despliega en toda su riqueza. Sus bosques son hogar del jaguar, el oso de anteojos y de numerosos mamíferos nativos de la Amazonía, mientras que el cielo se llena de aves que lo convierten en uno de los lugares con mayor concentración de avifauna del mundo.\n \nRecorrer el Amboró es adentrarse en un paisaje que invita a la exploración y la aventura: caminar por senderos rodeados de vegetación exuberante, pedalear entre montañas, cabalgar al ritmo de la naturaleza, escalar rocas y farallones, nadar en sus ríos o deslizarse en canoas. Cada actividad permite descubrir la flora y fauna del parque, mientras se experimenta la sensación de formar parte de un territorio vivo y lleno de maravillas por descubrir.', -17.816260190553000, -63.632268989057000, '', '', '', 'attraction', 6, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, NULL, NULL, NULL, '2025-11-25 01:07:57', '2025-12-02 22:27:36'),
(133, NULL, 'San Ignacio de Moxos', '\"San Ignacio de Moxos, Tierra de Cultura Viva\" en el corazón del Beni, es un pueblo donde la historia sigue presente a cada paso. Fundado como el tercer asentamiento misional de Moxos, ha sabido conservar una identidad que se transmite de generación en generación. \n \nSus tradiciones se manifiestan con especial fuerza en La Fiesta Grande: Ichapekene Piesta Inasianuana, donde la música, la devoción y los personajes festivos llenan las calles, mostrando el valor de una cultura. \n \n San Ignacio de Moxos es un lugar donde la tradición no se observa desde lejos ¡Se vive!', -14.996300000000000, -65.641100000000000, '', '', '', 'attraction', 7, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, NULL, NULL, NULL, '2025-11-25 17:47:23', '2025-11-25 20:47:17'),
(134, NULL, 'Challapata', 'Challapata ofrece atractivos naturales y culturales a corta distancia del centro urbano. A solo 10 km se encuentra la Represa Tacagua, ideal para pesca y observación de aves, la Cordillera de Azanaque brinda rutas de trekking con vistas hacia el antiguo Lago Poopó y a 13 km se encuentra el Valle de la Luna de Macallu, con formaciones de barro y arcilla moldeadas por la erosión.\n\nEl municipio también conserva su patrimonio histórico y cultural, destacando la Iglesia Colonial San Juan Bautista, construida en el siglo XVII, y sitios ceremoniales ancestrales como La Suchuna y Pasacana Rumi, donde aún se celebran rituales en honor a la Pachamama.', -18.898735152946000, -66.772919575114000, '', '', '', 'attraction', 4, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, NULL, NULL, NULL, '2025-12-02 01:30:01', '2025-12-02 01:30:01'),
(135, NULL, 'Tiquipaya', 'Tiquipaya, conocida como la Ciudad de las Flores, destaca por sus extensos viveros y la producción de plantas ornamentales que llenan de color sus paisajes. El municipio impulsa un turismo de naturaleza con manejo comunitario, invitando a los visitantes a recorrer sus espacios verdes y disfrutar de la tranquilidad del entorno.\n\nEl destino también es reconocido por el fenómeno natural el “manto” o “colchón de nubes”, que envuelve las montañas y crea un ambiente mágico y cautivador. Este espectáculo se observa en casi todos los atractivos de Tiquipaya, convirtiéndolo en un lugar ideal para quienes buscan contacto con la naturaleza y momentos de calma.\n\nSin duda, Tiquipaya es un lugar ideal para quienes buscan belleza natural y calma', -17.338088114696000, -66.218790698361000, '', '', '', 'attraction', 3, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, NULL, NULL, NULL, '2025-12-02 01:35:25', '2025-12-02 01:35:25'),
(136, NULL, 'Escoma', 'La Península de Challapata, se extiende entre totorales, playas lacustres y colinas que regalan vistas panorámicas del Lago Titicaca. Este territorio, conocido como “La Magia del Lago”, es hogar de una gran diversidad de aves altoandinas, desde el zambullidor del Titicaca hasta flamencos, gaviotas andinas y patos silvestres.\n\nLa vida cotidiana de las comunidades refleja la riqueza cultural de la región: pesca artesanal, agricultura tradicional, medicina natural y gastronomía típica. Con su ubicación privilegiada a orillas del Lago Titicaca se convierte en un destino a explorar.\"', -15.661488682797000, -69.128885538481000, '', '', '', 'attraction', 2, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, NULL, NULL, NULL, '2025-12-02 01:38:59', '2025-12-02 01:38:59'),
(137, NULL, 'Ascensión de Guarayos', 'Ascensión de Guarayos lleva en su nombre la historia de su gente: “guara” significa guerrero y “yu” pálido (amarillo o blanco). Una identidad que refleja la historia y el carácter de quienes han habitado estas tierras de la llanura oriental.\nSu población, de origen guarayo y mojeño, mantiene vivas sus prácticas tradicionales como la agricultura, la pesca y la caza, acompañadas de la música. Las mujeres destacan por su habilidad en el tejido de algodón, y los hombres, cuando no trabajan la tierra, dedican su esfuerzo a los aserraderos y a las haciendas ganaderas de la región.\n\nRíos, lagunas y bosques acompañan el paisaje de este destino, ideal para el ecoturismo y la observación de flora y fauna. Ascensión de Guarayos invita a descubrir una cultura que se conserva firme en la vida cotidiana de sus comunidades.', -15.896928715454000, -63.187637274152000, '', '', '', 'attraction', 6, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, NULL, NULL, NULL, '2025-12-02 01:40:12', '2025-12-02 01:40:12'),
(138, NULL, 'Salinas', 'Salinas se revela como un tesoro natural y cultural para quienes buscan nuevas formas de vivir el turismo más allá de lo convencional. En su vasto territorio se entrelazan iglesias e ingenios mineros de época colonial, vestigios arqueológicos de gran valor histórico, las mayores reservas de sal del mundo y los extensos cultivos de quinua que caracterizan esta tierra. Aquí, la vida gira alrededor del preciado “grano de oro”, del cual Salinas de Garci Mendoza es líder departamental en producción y un reconocido exportador. \n\nA los pies del imponente Volcán Tunupa, el paisaje se abre hacia la inmensidad blanca del salar y guía a los viajeros hasta la ciudadela de Alcaya, donde una antigua y  civilización dejó huellas que aún resisten al tiempo.', -19.637587712877000, -67.675229506444000, '', '', '', 'attraction', 4, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, NULL, NULL, NULL, '2025-12-02 01:42:03', '2025-12-02 01:42:03'),
(139, NULL, 'Uriondo, Corazón del Turismo', 'Bajo el lema “Uriondo, Corazón del Turismo”, se distingue como la zona con mayor producción de vid en Bolivia, consolidándose como un referente vitivinícola nacional. Sus viñedos y bodegas, permiten a los visitantes recorrer plantaciones, conocer técnicas de elaboración de vinos y singanis, y participar en la tradicional vendimia, una celebración que combina cultura, música y gastronomía local.', -21.695550889479000, -64.652646817477000, '', '', '', 'attraction', 9, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, NULL, NULL, NULL, '2025-12-02 01:43:31', '2025-12-02 01:43:31'),
(140, NULL, 'Comarapa, paraíso escondido', 'Comarapa fue bautizada con un nombre quechua: “con-wara” (verde y campo), al que más tarde se añadió la sílaba “pa”, dando origen a “Campo Verde”, un nombre que resume la identidad de este valle fértil. Ese significado se hace visible en su entorno, donde la riqueza natural convive con un valioso patrimonio cultural y huellas arqueológicas que narran su historia.\n\nConocida hoy como la capital de la frutilla, Comarapa ha logrado duplicar e incluso triplicar su producción gracias a la tecnificación agrícola, fortaleciendo el vínculo entre su gente y el cultivo que identifica al valle. Esta misma conexión con la tierra se refleja en su gastronomía, donde “chamas”(pan), quesos y mermeladas conquistan el paladar de cada visitante.', -17.913616640608000, -64.529640149223000, '', '', '', 'attraction', 6, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, NULL, NULL, NULL, '2025-12-02 01:45:17', '2025-12-02 01:45:17'),
(141, NULL, 'Tariquía: Santuario del Bosque Vivo', 'La Reserva Nacional de Flora y Fauna Tariquía tiene una función ambiental esencial para Tarija, ya que resguarda fuentes de agua y ecosistemas que sostienen la vida en la región, mientras protege una notable diversidad de especies que la convierten en un importante refugio de biodiversidad.\n\nEn este destino, las zonas turísticas de Corazón de Tariquía, Salinas y El Cajón ofrecen trekking, cabalgatas y observación de aves y fauna silvestre, a la vez que sus piscinas naturales de aguas cristalinas, alimentadas por vertientes, se integran con la presencia de comunidades locales que reciben al visitante y comparten su identidad y relación con el entorno.', -22.104384746392000, -64.431873142557000, '', '', '', 'attraction', 2, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, NULL, NULL, NULL, '2025-12-02 01:46:48', '2025-12-02 01:46:48'),
(142, NULL, 'El Alto, Capital de Los Andes', 'El Alto, la ciudad más joven de Bolivia y la segunda más poblada del país, se ha consolidado como un territorio de rápido crecimiento y transformación. Su ubicación a 4.095 metros sobre el nivel del mar la posiciona entre las ciudades más altas del mundo, un rasgo que se suma a la riqueza cultural y social que la caracteriza.\n\nSu identidad urbana se manifiesta en la arquitectura neoandina, conocida popularmente como “cholets”, este rasgo convive con la modernidad que aporta el Teleférico, desde donde se aprecian panorámicas únicas de la ciudad y del imponente Huayna Potosí. Todo este conjunto convierte a El Alto en un destino  donde tradición y modernidad se entrelazan.', -16.504161561683000, -68.162327898367000, '', '', '', 'city', 2, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, NULL, NULL, NULL, '2025-12-02 01:47:53', '2025-12-02 01:47:53'),
(143, NULL, 'San Lorenzo, donde nace la Historia', 'San Lorenzo, ubicado a pocos minutos de la ciudad de Tarija resguarda un valioso legado histórico, en donde su mayor emblema es la Casa de Moto Méndez, hoy convertida en museo, donde se preserva la memoria del héroe tarijeño que tuvo un rol importante en la lucha por la independencia.\n\nSu identidad cultural cobra especial realce durante Semana Santa, cuando se celebra una de las fiestas pascuales más destacadas de Bolivia. En esas fechas, las calles del pueblo se transforman con arcos y guirnaldas elaborados con miles de flores amarillas, creando un escenario lleno de color.', -21.417953678197000, -64.749359068200000, '', '', '', 'attraction', 9, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, NULL, NULL, NULL, '2025-12-02 01:49:27', '2025-12-02 01:49:27'),
(144, NULL, 'Guaqui: Capital de la morenada y Patrimonio ferroviario del Titicaca', 'Guaqui, ubicada a orillas del majestuoso Lago Titicaca, es reconocida como la “Capital de la Morenada” . Este título se consolidó tras alcanzar un récord Guinness, cuando más de tres mil bailarines y músicos interpretaron la morenada durante más de dos horas, reafirmando la fuerza cultural y festiva. \n\nAdemás de su patrimonio festivo, Guaqui conserva una importante herencia ferroviaria vinculada a la época de auge minero del país. A principios del siglo XX, fue el primer puerto lacustre internacional de Bolivia y punto clave para la exportación minera, razón por la cual la estación de trenes tuvo un rol fundamental. Hoy, el Museo de Locomotoras resguarda esa historia con una colección de locomotoras a vapor que recorrieron la ruta Guaqui–La Paz, ofreciendo a los visitantes un viaje en el tiempo.', -16.597569487071000, -68.836855381969000, '', '', '', 'attraction', 2, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, NULL, NULL, NULL, '2025-12-02 01:50:30', '2025-12-02 01:50:30'),
(145, NULL, 'Ruta de sitios con grabados y pinturas rupestres- Moro Moro', 'Moro Moro guarda en su territorio un legado inscrito en la piedra. La Ruta del Arte Rupestre conduce a descubrir eL pasado en un recorrido que revela tesoros arqueológicos: la cueva de Paja Colorada, con sus pinturas rupestres de distintos periodos prehispánicos, y la quebrada La Kollpa, donde cerámicas, tumbas y tejidos preincaicos mantienen viva la memoria de quienes habitaron estas tierras.\n\nDado que se trata de un patrimonio protegido, la experiencia se realiza junto a un guía autorizado, encargado de interpretar cada huella del pasado.', -18.366563461731000, -64.323578659925000, '', '', '', 'attraction', 6, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, NULL, NULL, NULL, '2025-12-02 17:37:18', '2025-12-02 17:37:18'),
(146, NULL, 'Distrito 8', 'El Distrito 8 de Sucre destaca por la promoción de sus áreas rurales, donde comunidades como Potolo, Maragua y Chataquila resguardan una riqueza natural, gastronómica y cultural. A menos de dos horas de la ciudad, estos destinos permiten a los visitantes acercarse a lugares como la Garganta del Diablo. \n\nAsimismo, el Distrito 8 es el principal custodio de los vestigios culturales de la nación Jalq’a. Sus comunidades conservan técnicas textiles e iconografías, reconocidas internacionalmente por su complejidad y belleza.', -19.033300000000000, -65.262000000000000, '', '', '', 'attraction', 1, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, NULL, NULL, NULL, '2025-12-02 17:42:43', '2025-12-02 17:42:43'),
(147, NULL, 'Ruta de cascadas en Taipiplaya y Cruz Playa', 'La Ruta de Cascadas en Taipiplaya y Cruz Playa revela un paisaje de exuberante naturaleza. Taipiplaya, rodeada por cerros cubiertos de vegetación tropical y flanqueada por dos ríos de aguas cálidas, debe su nombre a esta particularidad, que significa “en medio de la playa”.\n\nRío arriba, a casi 20 kilómetros, se encuentra Cruz Playa, hogar de la Cascada Rincón del Tigre. En este espacio se encuentran especies endémicas como el majestuoso jaguar, del que recibe su nombre, y el mono amarillo, exclusivo de Bolivia, convirtiendo al destino en un lugar de alto valor ecológico.', -16.021411015577000, -67.463989477951000, '', '', '', 'attraction', 2, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, NULL, NULL, NULL, '2025-12-02 17:48:25', '2025-12-02 17:48:25'),
(148, NULL, 'Recorrido histórico por sitios de la Guerra del Chaco', 'El Chaco boliviano ofrece un recorrido por los escenarios donde se desarrolló uno de los conflictos más trascendentales de Sudamérica: la Guerra del Chaco. En esta ruta es posible conocer fortines, trincheras y antiguos campos de batalla que permiten comprender el contexto, el sacrificio y la huella que dejó la contienda en el país.\n\nHoy, museos, cementerios de guerra, monumentos y comunidades locales resguardan testimonios que conectan el pasado con el presente, mientras el entorno natural del Gran Chaco enriquece la experiencia. Estas rutas buscan preservar la historia, atraer visitantes y fortalecer la economía local a partir del valor patrimonial de este territorio marcado por la resistencia.', -22.013788475961000, -63.677942906569000, '', '', '', 'attraction', 9, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, NULL, NULL, NULL, '2025-12-02 17:51:45', '2025-12-02 17:51:45'),
(149, NULL, 'Camataqui- Villa Abecia: La Coqueta del Sur, es más de lo que te imaginas', '\"Camataqui- Villa Abecia: La Coqueta del Sur, es más de lo que te imaginas\", es un referente vitivinícola en los Valles de Cinti, donde la producción de vinos y singanis se ha consolidado como una tradición. Su clima favorece la calidad de la uva, y sus bodegas algunas centenarias invitan a recorrer viñedos, conocer técnicas y degustar sabores que distinguen a este territorio. \n\nEntre cerros rojizos y ríos de aguas cristalinas, el destino también resguarda un valioso legado prehispánico. Cuevas como La Salamanca y Las Ulupikas conservan pinturas y petroglifos que revelan la presencia de antiguas culturas en la región. Así, Camataquí – Villa Abecia ofrece una experiencia donde cada copa cuenta una historia.', -20.974479119488000, -65.230736987791000, '', '', '', 'attraction', 1, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, NULL, NULL, NULL, '2025-12-02 17:53:36', '2025-12-02 17:53:36'),
(150, NULL, 'Santiago de Cotagaita : Capital histórica de Bolivia', 'Mucha historia concentrada en un territorio reducido: eso es Cotagaita, un municipio donde conviven lugares tan simbólicos como Tumusla y sitios históricos menos conocidos, como Vichacla. La ciudad se caracteriza por sus casas bajas y calles tranquilas, mientras que sus alrededores albergan fincas de frutas y hortalizas que aprovechan las aguas de los ríos Tumusla y Cotagaita.\n\nReconocida como la Capital Frutícola y Folklórica del departamento de Potosí, Cotagaita celebra cada año la Feria Frutícola y el Festival Folklórico, eventos en los que se presentan grupos de bailes tradicionales, músicos destacados y una muestra de la gastronomía local, incluyendo vinos, singanis y productos típicos de la región.', -20.817931738049000, -65.658651671946000, '', '', '', 'attraction', 5, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, NULL, NULL, NULL, '2025-12-02 17:55:45', '2025-12-02 17:55:45'),
(151, NULL, 'Llica: Municipio agro-ecoturístico Salar de Thunupa', 'Llica, con acceso al majestuoso Salar de Uyuni e Isla Incahuasi, sorprende con un paisaje que combina el misterio del Cráter de Ulo, las aguas serenas de sus lagunas, las formaciones rocosas y los bosques de cactus que se alzan como centinelas, ofreciendo refugio a fauna silvestre como vizcachas y vicuñas.\n\nEl municipio preserva las estructuras sociales del ayllu, y su identidad se refleja en la vestimenta tradicional, las facilidades y sistemas de organización territorial, así como en la producción de quinua real de origen.', -19.850607248418000, -68.249759724845000, '', '', '', 'attraction', 5, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, NULL, NULL, NULL, '2025-12-02 19:08:07', '2025-12-02 19:08:07'),
(152, NULL, 'Cañón de Pilaya: Sexto más profundo del mundo', 'El Cañón del Pilaya, ubicado en la frontera entre Tarija y Chuquisaca, es una de las formaciones naturales más imponentes de Bolivia. Con más de 3.030 metros de profundidad, está considerado el sexto más profundo del mundo. Sus paredes casi verticales han sido esculpidas por el río Camblaya, que al internarse en el abismo adopta el nombre de Pilaya, creando un paisaje que impresiona por su magnitud y dramatismo.\n\nEste entorno alberga una biodiversidad singular, donde viven especies emblemáticas como el cóndor y el oso andino, lo que otorga al área un alto valor para la conservación. El ecoturismo se convierte en la mejor manera de explorar este destino: caminatas, cabalgatas y observación de flora y fauna permiten descubrir cada rincón con respeto y asombro. Quienes se atreven a llegar hasta el Pilaya regresan con una certeza: hay paisajes que te cambian la forma de mirar la naturaleza… y este es uno de ellos.', -21.110455237846000, -64.801179288539000, '', '', '', 'attraction', 9, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, NULL, NULL, NULL, '2025-12-02 19:10:14', '2025-12-02 19:10:14'),
(153, NULL, 'Ruta de la Chicha y el Maíz', 'La Ruta de la Chicha y el Maíz, en los Valles Interandinos del Valle Alto y el Cono Sur de Cochabamba, invita a recorrer paisajes agrícolas los Valles Interandinos donde los campos de maíz se extienden hasta el horizonte. Aquí se pueden apreciar algunas de las 77 variedades de este cultivo ancestral y descubrir el proceso de elaboración de la chicha, bebida tradicional considerada Patrimonio Cultural Gastronómico del departamento.\n\nEl recorrido atraviesa los municipios de Anzaldo, Arani, Arbieto, Punata y Tarata, permitiendo descubrir la riqueza cultural, agrícola y social que gira en torno a estos productos emblemáticos y tan arraigados en la cultura quechua.', -17.583570199918000, -66.014778415954000, '', '', '', 'attraction', 3, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, NULL, NULL, NULL, '2025-12-02 19:13:59', '2025-12-02 19:13:59'),
(154, NULL, 'Coroico, la Ciudad de la Eterna Naturaleza', 'Coroico, donde la geografía montañosa y la biodiversidad tropical se combinan en un solo destino. Entre los espacios más concurridos se encuentran las cascadas de San Félix, San Jacinto y Cochuna, que forman pozas naturales ideales para el descanso y la recreación. Desde el cerro Uchumachi, un punto de fácil acceso para caminatas, es posible contemplar vistas panorámicas del valle y de la Cordillera Real. \n\nEl turismo de aventura también tiene un papel fundamental, el descenso en bicicleta desde La Cumbre por la antigua carretera, reconocido mundialmente, se ha consolidado como una de las actividades más representativas del destino. A ello se suman senderos para caminatas, rafting, tirolesa y visitas temáticas vinculadas a la producción de café, miel, coca y frutas tropicales. Coroico también resguarda una herencia cultural invaluable. En comunidades afrobolivianas como Mururata, Tocaña y Chijchipa, los visitantes son recibidos con hospitalidad.', -16.188661912739000, -67.727595793589000, '', '', '', 'attraction', 2, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, NULL, NULL, NULL, '2025-12-02 19:16:06', '2025-12-02 19:16:06'),
(155, NULL, 'Porvenir: Capital Turística de Pando', 'Porvenir se posiciona como la capital turística de Pando, destacando por su riqueza natural, su gastronomía basada en frutos amazónicos y la hospitalidad de su gente. Su entorno se caracteriza por una notable diversidad de flora y fauna, así como una extensa red hidrográfica que fortalece su vocación turística.\n\nA solo 30 kilómetros de Cobija se encuentra el Área Natural de Manejo Integrado Bosque de Porvenir, un espacio que permite a visitantes nacionales y extranjeros adentrarse en la majestuosidad de los bosques amazónicos. Allí es posible navegar por el río Tahuamanu, observar la vida silvestre y conocer prácticas de manejo sostenible de productos del bosque impulsadas por las comunidades locales, que también desarrollan iniciativas turísticas que enriquecen la experiencia del viajero.', -11.237617546020000, -68.687162873947000, '', '', '', 'attraction', 8, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, NULL, NULL, NULL, '2025-12-02 19:17:56', '2025-12-02 19:17:56'),
(156, NULL, 'Ruta de la Quinua', 'La Ruta de la Quinua recorre los Andes para mostrar un territorio donde la herencia cultural, agrícola y natural se entrelaza con la vida cotidiana de las comunidades de Machacamarca, Santuario de Quillacas y los Gobiernos Autónomos Indigena Originario Campesinos Salina y Uru. En este circuito, el “grano de oro” se convierte en eje central, conectando paisajes áridos pero llenos de vida: vastas planicies salinas, lagunas altoandinas y formaciones rocosas que enmarcan la producción de la quinua real, una variedad orgánica cultivada durante miles de años por su alto valor nutricional.\n\nA más de 3.700 metros sobre el nivel del mar, la ruta permite descubrir cómo la agricultura tradicional impulsa la economía local y fortalece la identidad de la región.', -18.170561171883000, -67.022930293485000, '', '', '', 'attraction', 4, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, NULL, NULL, NULL, '2025-12-02 19:23:43', '2025-12-02 19:23:43'),
(157, NULL, 'El Angosto', 'El Angosto, ubicado a diez kilómetros de la ciudad de Villa Montes, es uno de los tramos más emblemáticos de la ruta que conecta Tarija con el Chaco boliviano. Construido en 1928 sobre un estrecho desfiladero a orillas del río Pilcomayo, impresiona por sus paredes rocosas. \nDurante la temporada de lluvias, su trayecto se vuelve un desafío debido a la caída de rocas, lo que lo ha catalogado como un tramo vial de alto riesgo. Sin embargo, esta misma geografía le otorga un atractivo singular, convirtiéndolo en un punto de interés para el turismo de aventura.\nEn el lugar se desarrolla la Ruta Turística Aguaragüe El Angosto, un recorrido señalizado que permite disfrutar de miradores naturales, caídas de agua, propuestas gastronómicas y actividades de deportes extremos.', -21.235452324803000, -63.557979543238000, '', '', '', 'attraction', 9, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, NULL, NULL, NULL, '2025-12-02 19:33:11', '2025-12-02 19:33:11'),
(158, NULL, 'San Pedro de Tiquina', 'San Pedro de Tiquina, con afluencia turística constante durante todo el año, se constituye como el paso obligado hacia los principales destinos lacustres del Lago Titicaca, donde conocer Tiquina es mucho más que cruzar el estrecho. En este punto, las embarcaciones transportan a viajeros y vehículos en una travesía breve, pero inolvidable, que permite apreciar la grandeza del inicio del lago. A orillas del lago, la vida cotidiana se entrelaza con la naturaleza, viviendas de adobe y piedra con techos de paja resaltan en el paisaje, invitando al visitante a detenerse en San Pedro de Tiquina.', -16.221721035771000, -68.852996085978000, '', '', '', 'attraction', 2, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, NULL, NULL, NULL, '2025-12-02 19:34:35', '2025-12-02 19:34:35');
INSERT INTO `locations` (`id`, `user_id`, `name`, `description`, `latitude`, `longitude`, `address`, `opening_hours`, `contact_info`, `type`, `department_id`, `badge`, `room_type`, `price_per_night`, `start_date`, `end_date`, `event_type`, `capacity`, `is_recurring`, `facebook`, `instagram`, `whatsapp`, `link`, `created_at`, `updated_at`) VALUES
(159, NULL, 'Colcha K: Magia, belleza y aventura', 'Colcha “K”, municipio de la provincia Nor Lípez, se ubica cerca del Salar de Uyuni, consolidándose como un territorio con gran potencial para diversificar la oferta turística más allá del salar.\n\nEntre sus atractivos sobresale la Gruta de las Galaxias, también conocida como las Maravillas de Zepita, cuyas estalactitas y estalagmitas únicas atraen a visitantes interesados en geología y fenómenos naturales. En San Juan de Rosario destacan los circuitos arqueológicos y la necrópolis de chullpares, testimonio del pasado prehispánico de la región. Colcha “K” permite al visitante vivir la experiencia de recorrer una verdadera maravilla de la naturaleza.', -20.740345371281000, -67.660530753528000, '', '', '', 'attraction', 5, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, NULL, NULL, NULL, '2025-12-02 19:36:51', '2025-12-02 19:36:51'),
(160, NULL, 'Vallegrande', 'Vallegrande se reconoce como un destino para adentrarse en la historia de Ernesto Che Guevara. La lavandería del Hospital de Vallegrande, donde se trasladó su cadáver tras su ejecución en La Higuera, permite comprender los últimos momentos de su vida, allí se realizó la identificación del cuerpo y se tomó la emblemática fotografía en la que Guevara aparece como Cristo yacente.\n\nA pocos pasos, la antigua pista de aterrizaje recuerda el lugar en donde fueron enterrados los restos de Che y seis de sus compañeros en una fosa común. Hoy, un mausoleo preserva la memoria de estos hechos, convirtiendo a Vallegrande en un espacio de homenaje para conocer de cerca el legado del revolucionario.', -18.489547083298000, -64.108192244762000, '', '', '', 'attraction', 6, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, NULL, NULL, NULL, '2025-12-02 19:38:07', '2025-12-02 19:38:07'),
(161, NULL, 'FESTICHACO', 'El Festival de la Tradición Chaqueña 2025 se consolida como uno de los eventos culturales más esperados del año en el Chaco boliviano, donde artistas locales, nacionales e internacionales se reúnen para llenar de música, danza y tradición cada espacio del festival. Con la inauguración oficial, esta nueva edición reafirma su papel como una celebración que une al Chaco a través de la cultura, la identidad y el orgullo de sus habitantes.', -16.487650260650000, -68.143284760376000, '', '', '', 'event', 9, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, NULL, NULL, NULL, '2025-12-02 19:41:12', '2025-12-02 19:41:12'),
(162, NULL, 'Tupiza: Déjate atrapar con su belleza', 'Tupiza, en el sur del departamento de Potosí, se encuentra rodeada por formaciones geológicas singulares y cañones de piedra que crean un paisaje ideal para el turismo de aventura. Sus cañones y quebradas permiten realizar actividades como el trekking, cabalgatas y las excursiones al aire libre.\n\nAdemás de su riqueza natural, su historia también se entrelaza con la leyenda de Butch Cassidy y Sundance Kid, dotando a la ciudad de un valor cultural que la integra en circuitos turísticos internacionales.', -21.444150264673000, -65.720684632120000, '', '', '', 'attraction', 5, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, NULL, NULL, NULL, '2025-12-02 19:42:34', '2025-12-02 19:42:34'),
(163, NULL, 'Yanacachi', 'La vida del municipio destaca por el cultivo de productos reconocidos como el café y la hoja de coca, que aportan identidad y esencia a la región, mientras un importante patrimonio cultural e histórico permanece presente en su territorio. El camino prehispánico Taquesi, junto a pueblos coloniales e iglesias que datan del siglo XI.', -16.399324254102000, -67.737062953407000, '', '', '', 'attraction', 2, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, NULL, NULL, NULL, '2025-12-02 19:44:14', '2025-12-02 19:44:14'),
(164, NULL, 'San Pablo de Lípez: Tesoros vivos del Altiplano', 'San Pablo de Lípez, municipio del departamento de Potosí, se encuentra ubicado en la cordillera de los Lípez, en un territorio de terrenos semidesérticos y paisajes volcánicos de gran belleza.\n\nDentro del área protegida de la Reserva Nacional de Fauna Andina Eduardo Avaroa, concentra la mayor afluencia turística de la provincia de Sud Lípez. En su zona suroeste destacan cuerpos de agua de colores intensos, como la famosa Laguna Colorada, y los géiseres de “Sol de la Mañana”, un área de intensa actividad volcánica que sorprende por su fuerza. San Pablo de Lípez invita a recorrer un paisaje donde la geología y la naturaleza se combinan.', -21.687845025628000, -66.621122241354000, '', '', '', 'attraction', 5, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, NULL, NULL, NULL, '2025-12-02 19:51:56', '2025-12-02 19:51:56'),
(165, NULL, 'Mojinete', 'Mojinete, en la región de Sud Lípez, es un territorio frío y desértico que sorprende por sus verdes praderas y su abundancia de agua, un verdadero oasis en medio del altiplano. El municipio se distingue por su diversidad natural y sus formaciones geológicas únicas, rodeadas de montañas y ríos desde los cuales es posible observar su fauna endémica.\n\nUbicado a orillas del río San Juan del Oro, que riega sus tierras de manera natural, Mojinete se ha convertido en productor agrícola de variedades de manzana y hortalizas. Entre sus atractivos sobresale el Laberinto, un recorrido por estrechas callejuelas de roca cuyas tonalidades rojizas invitan a los visitantes a descubrir la magia de este rincón del altiplano.', -21.764732470203000, -66.239300097239000, '', '', '', 'attraction', 5, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, NULL, NULL, NULL, '2025-12-02 19:57:17', '2025-12-02 19:57:17'),
(166, NULL, 'Salar de Coipasa', 'Su nombre proviene de la voz aymara \"Qollpa\", que significa sal, y se encuentra a 220 kilómetros al sudoeste de la ciudad de Oruro, en la provincia Sabaya. Es el segundo salar más grande de Bolivia, después del Salar de Uyuni, y rodea completamente al lago Coipasa, formando un paisaje donde el blanco del salar contrasta con el azul del horizonte.\n\nLas formaciones rocosas que lo enmarcan son de origen volcánico y, durante la visita, es posible apreciar la presencia de flora cactácea que resalta en medio de la vastedad salina.', -19.395429275468000, 68.157321704562000, '', '', '', 'attraction', 4, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, NULL, NULL, NULL, '2025-12-02 19:59:46', '2025-12-02 19:59:46'),
(167, NULL, 'San José de Chiquitos: Imposible de olvidar', 'San José de Chiquitos, en la Chiquitanía boliviana, es reconocido por la UNESCO como Patrimonio Cultural de la Humanidad gracias a su imponente Conjunto Misional Jesuítico, el único construido en piedra en toda la región. A su alrededor, el Espacio Cultural de Chiquitos, los murales restaurados y la riqueza artesanal reflejan la profundidad de sus raíces.\n\nEsta herencia se hace también presente en la música barroco-chiquitana que resuena en los coros locales, así como en La Ruta SaboreArte Chiquitos, la cual permite al visitante tener encuentros vivenciales con las familias locales, experiencias gastronómicas de cocina tradicional, talleres de artesanías y visita a sitios históricos y sitios naturales.', -17.845567833681000, -60.742238993098000, '', '', '', 'attraction', 6, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, NULL, NULL, NULL, '2025-12-02 20:01:46', '2025-12-02 20:01:46'),
(168, NULL, 'Apolo: Destino de Riqueza natural y Cultural', 'El municipio de Apolo destaca por la riqueza natural y cultural que concentra, con cerca del 78% de su territorio protegido por tres áreas de importancia nacional e internacional: el Parque Nacional y Área Natural de Manejo Integrado Madidi, reconocido por su biodiversidad única; la Reserva de la Biosfera y TCO Pilón Lajas, declarada por la UNESCO; y el Área Natural de Manejo Integrado Nacional Apolobamba, también reconocida como Reserva de la Biosfera.\n\nApolo es un espacio para la conservación de ecosistemas altoandinos y amazónicos, así como para la protección de su diversa fauna y flora. Además, su territorio posee una profunda riqueza cultural, habitado desde épocas prehispánicas por diversos grupos étnicos, entre ellos Lecos, Pamainos, Silamas y Aguachiles, cuyas tradiciones y saberes aún se mantienen vivos en la comunidad.', -14.715808054604000, -68.417776560100000, '', '', '', 'attraction', 2, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, NULL, NULL, NULL, '2025-12-02 20:03:31', '2025-12-02 20:03:31'),
(169, NULL, 'Reserva Biológica de la cordillera de Sama', 'La Reserva Biológica de la Cordillera de Sama, en el departamento de Tarija, sobresale por su diversidad de ecosistemas y la presencia de especies endémicas y amenazadas, como la taruca, el cóndor andino y la vicuña, que encuentran en sus montañas un hábitat protegido. En sus límites se extienden la laguna Grande y la laguna Tajzara, humedales incluidos en la Convención Ramsar que sostienen la vida de numerosas especies.\n\nAdemás, la observación de aves, especialmente migratorias, permite a los visitantes conectarse con la biodiversidad de la reserva.', -21.765817716688000, -65.202136724740000, '', '', '', 'attraction', 9, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, NULL, NULL, NULL, '2025-12-02 20:05:10', '2025-12-02 20:05:10'),
(170, NULL, 'Valle de la Concepción', 'El Valle de la Concepción se caracteriza por la producción de uvas de excelente calidad, las cuales dan identidad y prestigio a esta región vitivinícola. Entre sus atractivos destaca la bodega artesanal La Casa Vieja, donde los visitantes pueden degustar diferentes vinos y acompañarlos con platos típicos y dulces artesanales. Este espacio, además, ofrece una hermosa vista a los viñedos, creando un ambiente ideal para disfrutar del paisaje y el sabor propio del valle.', -21.689777524019000, -64.662108310288000, '', '', '', 'attraction', 9, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, NULL, NULL, NULL, '2025-12-02 20:10:17', '2025-12-02 20:10:17'),
(171, NULL, 'Ruta de la Goma y la Castaña', 'La Ruta de la Goma y la Castaña recorre las comunidades de San Buenaventura (La Paz), Riberalta y Guayaramerín (Beni), así como Porvenir y Cobija (Pando), un territorio cuya historia está  ligada a la explotación de la goma a finales del siglo XIX y a la recolección de la castaña o nuez amazónica, actividad que hasta hoy sigue siendo una de las principales fuentes de sustento para las comunidades de la región. \n\nEntre sus atractivos destacan los senderos utilizados durante el auge gomero, las antiguas barracas donde se desarrollaba la explotación del caucho y las actuales áreas de recolección de castaña, que permiten a los visitantes comprender la dinámica productiva. Además, los ríos Tahuamanu, Manuripi y Madre de Dios son ideales para la navegación y la observación de flora y fauna silvestre.', -11.237561283239000, -68.687218416085000, '', '', '', 'attraction', 8, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, NULL, NULL, NULL, '2025-12-02 20:17:58', '2025-12-02 20:17:58'),
(172, NULL, 'Santa Ana de Yacuma', 'Santa Ana de Yacuma, al norte del departamento del Beni, se encuentra en plena Amazonía boliviana y forma parte de la Reserva de Biosfera y Estación Biológica del Beni, un área que protege hábitats de especies emblemáticas como el delfín rosado (bufeo), el guacamayo barba azul, monos, caimanes y una gran variedad de aves. \n\nCada año, a finales de julio, Santa Ana de Yacuma celebra su fundación en honor a su patrona con la Mere’e Piesta, que en idioma movima significa “fiesta grande”. Durante esta celebración, el Cabildo Indígena lidera danzas tradicionales como la de los macheteros, mientras que juegos  como el jocheo de toros y el palo encebado, atraen a numerosos visitantes de todo el país. Reconocida por el Senado boliviano, la Mere’e Piesta destaca por su aporte a la cultura boliviana.', -13.745666639529000, -65.427916789441000, '', '', '', 'attraction', 7, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, NULL, NULL, NULL, '2025-12-02 20:20:56', '2025-12-02 20:20:56'),
(173, NULL, 'Camiri', 'El municipio de Camiri, conocido como la \"Capital Petrolera de Bolivia\", debe su desarrollo a la explotación petrolera durante el siglo XX, especialmente con la presencia de Yacimientos Petrolíferos Fiscales Bolivianos (YPFB), que impulsó su crecimiento económico y social.\n\nSu ubicación geográfica lo convierte en un punto de tránsito y encuentro cultural, donde convergen tradiciones guaraníes, mestizas y urbanas. Esta identidad guaraní se refleja en la música, las danzas, la gastronomía y las festividades tradicionales, entre las que destaca el Arete Guasu, una celebración que reúne a las comunidades guaraníes en torno a cantos y danzas que conmemora el ciclo de la vida.', -20.039353539989000, -63.520281551688000, '', '', '', 'attraction', 6, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, NULL, NULL, NULL, '2025-12-02 20:22:03', '2025-12-02 20:22:03'),
(174, NULL, 'San Miguel de Velasco', 'San Miguel de Velasco destaca como una de las misiones jesuíticas más atractivas del país. Declarado Patrimonio Cultural de la Humanidad, distingue por sus pinturas, vitrales y columnas torneadas, elaboradas en madera y decoradas con motivos propios del Barroco mestizo. Además de ser ampliamente reconocido en la región por el tallado de madera, refleja la fusión entre la tradición europea y las expresiones artísticas locales.', -16.697902129936000, -60.967828670649000, '', '', '', 'attraction', 6, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, NULL, NULL, NULL, '2025-12-02 20:23:11', '2025-12-02 20:23:11'),
(175, NULL, 'Yacuiba, la entrada a la diversidad del Sur', 'Yacuiba es un punto de partida ideal para explorar el turismo en la región de Tarija. La ciudad combina el encanto del paisaje agreste del campo con la sorpresa de su infraestructura urbana, que despierta admiración en los visitantes. Como zona productora de gas, sus recursos han permitido desarrollar espacios urbanos destacados, y además es posible visitar la antigua estación de tren Ferroviaria Oriental, que aún se encuentra en funcionamiento.', -22.013801130047000, -63.677819969309000, '', '', '', 'attraction', 9, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, NULL, NULL, NULL, '2025-12-02 20:27:06', '2025-12-02 20:27:06'),
(176, NULL, 'Sipe Sipe: Donde el sabor tradicional se une a la memoria de los pueblos', 'Sipe Sipe es una pequeña ciudad y municipio del Valle Bajo, en el departamento de Cochabamba, conocida como la “Tierra de la Uva y el Guarapo”. Este lugar conserva un importante legado histórico y cultural, descendiente de la cultura incaica, cuyos habitantes participaron activamente en las batallas de Viloma, Hamiraya y Aroma durante la independencia.\n\nLa mayoría de los visitantes llegan a Sipe Sipe para venerar al Señor de los Milagros, pero también se interesan por su patrimonio arqueológico. Entre los sitios más destacados se encuentra Inkarraqay, un conjunto de ruinas de una antigua fortaleza y centro administrativo inca.', -17.453684279646000, -66.357440013246000, '', '', '', 'attraction', 3, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, NULL, NULL, NULL, '2025-12-02 20:28:41', '2025-12-02 20:28:41'),
(177, NULL, 'Pazña Urmiri: Destino de Cultura y Termalismo', 'Pazña y Urmiri, ubicados en el sector sur del altiplano orureño, destacan por sus atractivos culturales, patrimoniales y naturales. Pazña resalta por su riqueza cultural, reflejada en fiestas locales y rutas que evocan la memoria minera de la región.\n\nUrmiri, por su parte, se distingue por el turismo de salud y naturaleza, donde sus aguas termales y la medicina natural ofrecen a los visitantes un espacio de descanso y bienestar.', -18.597815381851000, -66.920832969707000, '', '', '', 'attraction', 4, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, NULL, NULL, NULL, '2025-12-02 20:30:23', '2025-12-02 20:30:23'),
(178, NULL, 'Santa Rosa del Yacuma', 'Santa Rosa del Yacuma, ubicada en el departamento del Beni, destaca por su Área Protegida Municipal Pampas del Río Yacuma, que abarca 616.453 hectáreas de sabanas inundables, bosques ribereños y humedales, conformando un rincón natural de gran riqueza. Este entorno permite que la pesca, la observación de fauna y la fotografía se conjuguen, cautivando tanto a familias como a fotógrafos.\n\nSu ubicación favorece el desarrollo del turismo ecológico y de aventura, mientras que la diversidad de flora y fauna refuerza el valor único del lugar, reconocido por sus habitantes como un verdadero “Paraíso Terrenal\"', -14.079870547876000, -66.792375054289000, '', '', '', 'attraction', 7, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, NULL, NULL, NULL, '2025-12-02 20:31:34', '2025-12-02 20:31:34'),
(179, NULL, 'Riberalta: Puerta de la Amazonía Boliviana', 'Riberalta, en el departamento del Beni, donde la vida amazónica se expresa en sus ríos, su historia y su diversidad cultural. Conocida también como la Capital Amazónica de Bolivia, la ciudad se ubica en el punto de encuentro de los ríos Beni y Madre de Dios. \n\nSu denominación “Perla del Acre” recuerda el auge del caucho entre los siglos XIX y XX, periodo que marcó el crecimiento económico de la zona. Como puerto fluvial, Riberalta es punto de conexión con extensos territorios de selva y la puerta de ingreso a rutas navegables que permiten descubrir la Amazonía boliviana desde el agua.', -11.023358826526000, -66.047710963624000, '', '', '', 'attraction', 7, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, NULL, NULL, NULL, '2025-12-02 20:32:39', '2025-12-02 20:32:39'),
(180, NULL, 'Huatajata Te Espera', 'Ubicado a orillas del majestuoso Lago Titicaca, Huatajata es reconocido como cuna de los constructores de naves de totora, un saber que ha trascendido generaciones y que mantiene vivo el legado de navegación en la región del altiplano. \n\nAquí se encuentra la familia Limachi, célebre por la elaboración de balsas de totora. Ellos comparten con los visitantes la historia de las expediciones internacionales realizadas con embarcaciones construidas en el lago más alto del mundo. Durante tres generaciones, los Limachi han participado en al menos doce travesías globales, entre las que destacan los proyectos RA II, Tigris y Abora II, que demostraron al mundo la capacidad de estas naves para navegar los océanos.', -16.208891114648000, -68.700500363241000, '', '', '', 'attraction', 2, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, NULL, NULL, NULL, '2025-12-02 20:33:45', '2025-12-02 20:33:45'),
(181, NULL, 'Quime: Paraíso de Los Andes entre Glaciares y Manantiales', 'Quime comienza a destacar como un punto emergente para el ecoturismo, atrayendo a visitantes que buscan naturaleza, aventura y descanso. Desde la población, una caminata de 30 a 45 minutos conduce hacia lo alto de sus montañas.\n\nEl esfuerzo vale cada paso: allí aguardan dos pozas de aguas calientes, donde el viajero puede relajarse mientras contempla vistas sorprendentes del valle de Quime, entre el calor natural del agua y el paisaje que se abre a los ojos.', -16.980038783224000, -67.215675578664000, '', '', '', 'attraction', 2, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, NULL, NULL, NULL, '2025-12-02 20:35:25', '2025-12-02 20:35:25'),
(182, NULL, 'Pucarani: Corazón del Cóndor Andino', 'Pucarani, cuyo nombre proviene del aymara “Pukara” (fortaleza), conserva en su memoria hechos trascendentales como las batallas de la Revolución Federal de 1899, que marcó al altiplano paceño. Ese espíritu también se refleja en su entorno natural, dominado por la imponencia del macizo Condoriri.\n\nEste conjunto montañoso debe su nombre a su silueta, que desde la distancia adopta la forma de un cóndor con las alas extendidas. Su punto más elevado alcanza aproximadamente 5.700 m s. n. m., y en su interior se distribuyen treinta picos, de los cuales quince destacan por su relevancia y diez por su singular belleza y popularidad entre montañistas.', -16.399760920962000, -68.477657835436000, '', '', '', 'attraction', 2, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, NULL, NULL, NULL, '2025-12-02 20:36:29', '2025-12-02 20:36:29'),
(183, NULL, 'Palca \"Mística y Ancestral\"', 'Muy próximo al Valle de las Ánimas, se encuentra el singular Cañón de Palca, un corredor natural formado por estructuras rocosas que alcanzan hasta 200 metros de altura y 8 kilómetros de longitud, un atractivo turístico escondido en la ciudad de La Paz.\n\nDesde distintos puntos del municipio se aprecian vistas privilegiadas del Mururata y del imponente Illimani, cuyas cumbres se elevan como guardianas del valle paceño.', -16.561210702668000, -67.952993541770000, '', '', '', 'attraction', 2, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, NULL, NULL, NULL, '2025-12-02 20:37:45', '2025-12-02 20:37:45'),
(184, NULL, 'Entre Ríos Auténtico', 'Entre Ríos, en el departamento de Tarija, es un territorio donde la identidad guaraní mantiene plena vigencia. Aquí se encuentra la región de Itika Guasu, una de las poblaciones guaraníes más importantes del país, donde sus tradiciones y expresiones culturales aún se mantienen vivas. \n\nAdemás de su riqueza viva, Entre Ríos resguarda un valioso patrimonio paleontológico. En la comunidad de Naranjo se descubrieron alrededor de cien huellas de dinosaurios, principalmente de terópodos y saurópodos, que revelan el paso de gigantes prehistóricos por lo que hoy es parte del sur boliviano.', -21.525859712346000, -64.171873264078000, '', '', '', 'attraction', 9, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, NULL, NULL, NULL, '2025-12-02 20:38:57', '2025-12-02 20:38:57'),
(185, NULL, 'El Filo, Santuario de Cóndores', 'El Filo, ubicado entre Samaipata y Cabezas, destaca como un santuario natural para el cóndor andino, donde estas majestuosas aves sobrevuelan las serranías y pueden observarse en su hábitat con una tranquilidad absoluta. Su ubicación y clima lo convierten en un lugar para quienes buscan descanso y contacto con la naturaleza. \n\nAdemás, ofrece espacios acondicionados para el disfrute seguro del visitante, desde miradores naturales con vistas panorámicas hasta áreas destinadas al relax y la desconexión. Entre sus atractivos más representativos se encuentran el Mirador Cóndor, el Bosque de Helechos, el Cañón con su cueva y las enigmáticas Caras Incas. Asimismo, se avanza en la consolidación de un circuito histórico-cultural asociado al paso de Ernesto “Che” Guevara.', -18.401589469277000, -63.604918817791000, '', '', '', 'attraction', 6, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, NULL, NULL, NULL, '2025-12-02 20:40:45', '2025-12-02 20:40:45'),
(186, NULL, 'Aiquile', 'Aiquile, reconocida como la \"Capital Nacional del Charango\", preserva la tradición musical y artesanal de este instrumento emblemático. Cada noviembre, celebra el Festival Nacional e Internacional del Charango, un encuentro que reúne a músicos, constructores y visitantes de distintos países, dando vida a una fiesta donde la música se combina con sabores locales como el tradicional uchuku. Esta identidad cultural también se refleja en el Museo del Charango, un espacio que resguarda las técnicas de fabricación y la evolución de este instrumento. \n\nA su riqueza cultural se suma una oferta natural diversa que invita al descanso y la aventura. El Mirador de Aiquile regala vistas panorámicas del valle, mientras que las aguas termales de Katariri brindan bienestar en un entorno sereno. La represa El Salto, con su atractivo paisaje, es ideal para actividades recreativas como paseos en bote y pesca.', -18.200449707786000, -65.180694057878000, '', '', '', 'attraction', 3, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, NULL, NULL, NULL, '2025-12-02 20:44:59', '2025-12-02 20:44:59'),
(187, NULL, 'Chorros de Marquiri', 'Los Chorros de Marquiri, ubicados en el municipio de San Lorenzo, invitan a iniciar la visita con una caminata de aproximadamente 45 minutos por un sendero que bordea la falda del cerro oeste, permitiendo disfrutar de la naturaleza desde el primer tramo del recorrido.\n\nAl llegar al área principal, los visitantes encuentran una hermosa cascada y pozas naturales que invitan a relajarse y disfrutar del agua cristalina. Los alrededores cuentan con senderos de montaña, miradores panorámicos y espacios para picnic o camping, convirtiéndolos en un destino ideal para quienes buscan actividades al aire libre. Además, los más intrépidos pueden practicar descenso por la caída de agua, integrándose por completo al paisaje de ríos, quebradas y valles interandinos que hacen de Marquiri un rincón único de Tarija.', -21.400442181306000, -64.859109640768000, '', '', '', 'attraction', 9, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, NULL, NULL, NULL, '2025-12-02 20:45:59', '2025-12-02 20:45:59'),
(188, NULL, 'Ruta del Chicharrón', 'La Ruta del Chicharrón en Sacaba es uno de los destinos gastronómicos más representativos de Cochabamba, consolidado en torno a la preparación tradicional del chicharrón de cerdo, un plato considerado patrimonio cultural y culinario de la región valluna. A lo largo de este recorrido se encuentran numerosos restaurantes y familias dedicadas exclusivamente a mantener viva esta tradición, ofreciendo sabores que forman parte de la identidad sacabeña.\n\nGracias a su cercanía con la ciudad de Cochabamba, la ruta recibe un importante flujo de visitantes durante fines de semana, feriados y festividades locales, convirtiéndose en un punto de encuentro para quienes buscan disfrutar de la gastronomía regional.', -17.403919673255000, -66.040227204727000, '', '', '', 'attraction', 3, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, NULL, NULL, NULL, '2025-12-02 20:51:37', '2025-12-02 20:51:37'),
(189, NULL, 'Uru Chipayas', 'Uru Chipaya es una nación indígena del altiplano boliviano, situada en el departamento de Oruro. Se autodenominan “Hombres de Agua”, en referencia a su histórico vínculo con los ríos y lagos que han determinado su forma de vida y su relación con el entorno. \n\nLa preservación de sus tradiciones ha permitido consolidar un modelo de turismo comunitario que invita a los visitantes a sumergirse en la vida diaria de la comunidad. La observación de prácticas agrícolas, la elaboración artesanal de textiles y la participación en rituales constituyen experiencias que acercan al visitante a la cultura, fortaleciendo al mismo tiempo el desarrollo local y la revalorización de su patrimonio vivo.', -19.041912693240000, -68.089653681042000, '', '', '', 'attraction', 4, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, NULL, NULL, NULL, '2025-12-02 20:52:26', '2025-12-02 20:52:26'),
(190, NULL, 'Parque Nacional y Área de Manejo Integrado Otuquis', 'Con una superficie de 10.059 km², el Parque Nacional y Área Natural de Manejo Integrado  Otuquis es una importante fuente y reservorio de agua dulce, además de ser hábitat de numerosas especies de flora y fauna. Al formar parte del Pantanal boliviano, uno de los humedales de agua dulce más grandes del mundo, está reconocido como Sitio Ramsar por su relevancia ecológica.\n\nEste territorio resguarda sitios de gran riqueza biológica, entre ellos destaca la laguna Cáceres, punto ideal para observar concentraciones de fauna silvestre.', -19.276654254841000, -58.759108946600000, '', '', '', 'attraction', 6, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, NULL, NULL, NULL, '2025-12-02 20:53:39', '2025-12-02 20:53:39'),
(191, NULL, 'Ruta del Tío', 'La Ruta del Tío abarca los municipios mineros de Llallagua, Uncía, Catavi y Siglo XX, con Huanuni como punto central, y permite conocer de cerca el legado histórico y cultural de la minería boliviana. \n\nEn este contexto, la figura del Tío es considerado protector de las minas y mediador de la seguridad y la prosperidad en los socavones, su presencia se mantiene viva en ofrendas que forman parte de la cosmovisión minera. Participar en estas actividades permite comprender la profunda espiritualidad que vincula a los trabajadores con el subsuelo, y descubrir una tradición que sigue latente en la memoria de los mineros.', -18.285900450132000, -66.834807795100000, '', '', '', 'attraction', 4, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, NULL, NULL, NULL, '2025-12-02 20:57:22', '2025-12-02 20:57:22'),
(192, NULL, 'Ruta del Pescado', 'La “Ruta del Pescado” (Ancoraimes, Huatajata, Huarina y Humacha) recorre las comunidades de Ancoraimes, Huatajata, Huarina y Humacha, ofreciendo a los visitantes la oportunidad de conocer criaderos de trucha, participar en paseos en lancha y actividades náuticas, y degustar platos típicos de pescado fresco elaborados según las tradiciones locales. Al mismo tiempo, la ruta permite explorar la artesanía y la cultura de cada comunidad.', -16.190778648886000, -68.601085167706000, '', '', '', 'attraction', 2, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, NULL, NULL, NULL, '2025-12-02 20:59:08', '2025-12-02 20:59:08'),
(193, NULL, 'Tarabuco \"Esencia viva el latido del Pujllay\"', 'Tarabuco es una verdadera joya de la cultura y el folklore boliviano debido a la presencia de comunidades que mantienen vivas sus costumbres y tradiciones. Como epicentro del pueblo Yampara, Tarabuco recibe cada domingo a pobladores de la región que llegan para vender y exhibir sus textiles, expresión de su identidad. \n\nSu principal atractivo turístico es la festividad del Pujllay.  Su nombre, proveniente del quechua y que significa “jugar” o “danzar”, rememora la valiente victoria de los indígenas Yampara sobre las fuerzas españolas en la Batalla de Jumbate.', -19.182634760364000, -64.914950436847000, '', '', '', 'attraction', 1, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, NULL, NULL, NULL, '2025-12-02 21:00:23', '2025-12-02 21:00:23'),
(194, NULL, 'Hotel Museo de Cayara', 'La Ruta de las Haciendas recorre antiguas haciendas que, durante los periodos colonial y republicano, jugaron un papel clave en el abastecimiento agropecuario y en la articulación económica vinculada al auge minero de Potosí. \n\nSu ubicación en valles templados y fértiles no fue casual: los colonizadores españoles, atraídos por la explotación intensiva del Cerro Rico, eligieron territorios estratégicos de menor altitud que aseguraban agua, clima favorable y suelos fértiles para sostener la economía minera. Hoy, estas haciendas y su entorno rural permiten al visitante conocer de cerca esta historia.', -19.551157691966000, -65.881564335870000, '', '', '', 'attraction', 5, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, NULL, NULL, NULL, '2025-12-02 21:03:14', '2025-12-02 21:03:14'),
(195, NULL, 'Ruta Paleontológica: Donde la tierra cuenta su historia', 'La Ruta Paleontológica es un corredor científico y turístico que se extiende por más de 500 km atravesando los Valles de Cochabamba, Potosí, Chuquisaca y Tarija, con su puerta de ingreso en el municipio de Anzaldo. Este recorrido es considerado una verdadera joya paleontológica, donde los visitantes pueden observar icnitas de dinosaurios, huesos fósiles y rastros de fauna prehistórica.\n\nAdemás, la ruta combina estos hallazgos con paisajes naturales y culturales que narran la historia geológica de millones de años.', -17.779007076141000, -65.932152385384000, '', '', '', 'attraction', 3, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, NULL, NULL, NULL, '2025-12-02 21:07:26', '2025-12-02 21:07:26'),
(196, NULL, 'Ruta del Cacao (Alto Beni – El Ceibo)', 'La Ruta del Cacao, que incluye a Alto Beni y El Ceibo, destaca por la producción de cacao, tradicionalmente recolectado y consumido por los pueblos indígenas de la región. El cacao se adapta de manera natural a las condiciones climáticas y ecológicas del Alto Beni, convirtiéndose en un recurso valioso tanto para la alimentación como para la economía local.\n\nA través de esta ruta se busca mejorar la calidad de vida de las comunidades indígenas y campesinas, promoviendo su participación en el agroturismo y fomentando la producción ecológica de cacao.', -15.598893274877000, -67.398651004545000, '', '', '', 'attraction', 2, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, NULL, NULL, NULL, '2025-12-02 21:09:27', '2025-12-02 21:09:27'),
(197, NULL, 'Padilla, cuna de la Libertad y Sabor', 'Padilla, ubicada en la región de los Valles Chuquisaqueños, destaca por su valor histórico como cuna de héroes de la independencia y escenario de importantes acontecimientos de la gesta libertaria. \n\nPero Padilla no solo es historia: también es tierra de sabores. El ají, cultivado con dedicación y cuidado, es un producto emblemático de la región. Aquí no solo se siembra, sino que se cría y se conversa con él, reflejando la relación cercana y respetuosa que se mantiene con la cultura gastronómica.', -19.307937538716000, -64.302600146428000, '', '', '', 'attraction', 1, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, NULL, NULL, NULL, '2025-12-02 21:10:31', '2025-12-02 21:10:31'),
(198, NULL, 'Santuario de Quillacas', 'Ubicado en el departamento de Oruro, Quillacas alberga uno de los santuarios coloniales más reconocidos a nivel internacional. Miles de peregrinos visitan este lugar para solicitar favores al Señor de Quillacas y recorrer su templo, una edificación del siglo XVII cuya arquitectura destaca por la cúpula central y el perímetro adornado con elegantes arcos.\n\nLa devoción hacia esta imagen de la Iglesia Católica se remonta al periodo de la Colonia, consolidando al santuario como un espacio de fe que continúa atrayendo visitantes de toda la región y el país.', -19.232719091093000, -66.941530891401000, '', '', '', 'attraction', 4, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, NULL, NULL, NULL, '2025-12-02 21:12:23', '2025-12-02 21:12:23'),
(199, NULL, 'Tarija, la Joya del Sur', 'Tarija no solo se visita… se vive. Conocida como \"Tarija la Linda\", este destino es ideal para quienes buscan disfrutar de su clima templado, recorrer atractivos turísticos, degustar vinos locales y conocer a gente amable y acogedora.\n\nEl recorrido por Tarija invita a explorar bodegas artesanales e industriales, donde los visitantes pueden probar vinos y singani de altura, cultivadas a más de 1.800 metros sobre el nivel del mar. Tarija también se distingue por sus festividades llenas de música y baile, como la Vendimia Chapaca que rinde homenaje a la cosecha de la uva y refleja la alegría y la tradición de su gente.', -21.533910799773000, -64.734297964852000, '', '', '', 'attraction', 9, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, NULL, NULL, NULL, '2025-12-02 21:13:43', '2025-12-02 21:13:43'),
(200, NULL, 'Monteagudo: Tierra Sauceña', 'Monteagudo, tierra sauceña, se distingue por su clima templado a cálido y su rica biodiversidad que albergan una variada flora y fauna. Sus recursos hídricos, como el Río Sauces y el Cañón de Heredia, ofrecen escenarios ideales para actividades al aire libre: el cañón destaca por sus aguas cristalinas y cascadas, perfectas para balnearios naturales, mientras que el río permite disfrutar de canotaje y pesca deportiva.\n\nAdemás, la fusión de las culturas guaraní y chaqueña se refleja en sus tradiciones, música y festividades, haciendo de Monteagudo un lugar auténtico.', -19.802975944830000, -63.955111292274000, '', '', '', 'attraction', 1, '', NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, NULL, NULL, NULL, '2025-12-02 21:14:42', '2025-12-02 21:14:42');
