INSERT INTO `location_items` (`id`, `location_id`, `name`, `description`, `type`, `price`, `review`, `image_url`) VALUES
(1, 47, 'Habitación Doble Estándar', 'Habitación cómoda con cama doble, baño privado, TV y vista a la ciudad.', 'room', 85.00, '4.7', 'https://vilaguesthouses.com/wp-content/uploads/sites/461/2022/06/vila_garden_twin_std_thumb_03.jpg'),
(2, 47, 'Suite Junior', 'Espaciosa suite con sala de estar, cama king size y amenities de lujo.', 'room', 116.00, '4.8', 'https://rojasplazaboutique.com/wp-content/uploads/2020/03/doble-estandar_01.webp'),
(3, 47, 'Habitación Familiar', 'Ideal para familias: 2 camas dobles, baño amplio y espacio para 4 personas.', 'room', 130.00, '4.6', 'https://www.suitescaminoreal.lpb/wp-content/uploads/2023/05/habitacion-familiar.jpg'),
(4, 47, 'Desayuno Buffet Gourmet', 'Desayuno internacional con productos locales, jugos frescos y pan artesanal.', 'offer', 15.00, '4.9', 'https://www.suitescaminoreal.lpb/wp-content/uploads/2023/05/desayuno.jpg'),
(5, 47, 'Traslado Aeropuerto - Hotel', 'Servicio privado de ida y vuelta desde el aeropuerto de El Alto.', 'service', 25.00, '4.8', 'https://www.suitescaminoreal.lpb/wp-content/uploads/2023/05/traslado.jpg'),
(6, 47, 'Masaje Relajante de 60 minutos', 'Terapia con aceites esenciales en la comodidad de tu habitación.', 'service', 60.00, '4.9', 'https://www.suitescaminoreal.lpb/wp-content/uploads/2023/05/masaje.jpg'),
(7, 47, 'Tour Guiado: Centro Histórico de La Paz', 'Recorrido por Plaza Murillo, Calle Jaén y Mirador Killi Killi.', 'offer', 45.00, '4.7', 'https://www.cataloniahotels.com/es/blog/wp-content/uploads/2024/01/tipos-habitaciones-hotel.jpg'),
(8, 47, 'Habitación Superior con Vista', 'Habitación premium con balcón privado y vistas panorámicas al valle de La Paz.', 'room', 140.00, '4.9', 'https://www.suitescaminoreal.lpb/wp-content/uploads/2023/05/vista-valle.jpg'),
(9, 47, 'Cena Romántica en Habitación', 'Menú especial para dos, velas, vino y servicio privado.', 'offer', 90.00, '4.8', 'https://www.suitescaminoreal.lpb/wp-content/uploads/2023/05/cena-romantica.jpg'),
(10, 47, 'Acceso Diario: Gimnasio y Sauna', 'Instalaciones modernas para huéspedes y visitantes externos.', 'service', 20.00, '4.5', 'https://chuzefitness.com/wp-content/uploads/IMG_0235-1.jpg'),
(11, 49, 'Salteña Mex-Bol', 'Fusión única: masa de salteña rellena con tinga de pollo, aceitunas y un toque de ají amarillo.', 'dish', 28.00, '4.8', 'https://chipabythedozen.com/wp-content/uploads/2020/08/Saltenas-Bolivianas-de-Pollo19-700x467.png'),
(12, 49, 'Tacos de Charque con Salsa de Maní', 'Tortillas artesanales con charque desmenuzado, cebolla morada y salsa de maní tostado.', 'dish', 32.00, '4.9', 'https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcSMAidTF2wKN5BuLBSLvPeLAFhQuFPGHakRVw&s'),
(13, 49, 'Ceviche Andino', 'Pescado fresco marinado en limón, con ají, cebolla, aguacate y maíz tostado. Servido en concha de coco.', 'dish', 36.00, '4.7', 'https://perutepone.com/wp-content/uploads/2025/04/image-221-png.webp'),
(14, 49, 'Mole Paceño', 'Receta exclusiva: pollo en salsa de maní, ají, chocolate y especias andinas. Acompañado de arroz y papas.', 'dish', 38.00, '4.8', 'https://cdn.bolivia.com/gastronomia/2011/08/23/perniles-de-pollo-al-mole-3643-0.jpg'),
(15, 49, 'Quesillos con Miel de Caña', 'Queso fresco cremoso bañado en miel de caña artesanal, acompañado de frutos rojos de temporada.', 'dish', 22.00, '4.9', 'uploads/location-items/article_20251106_134807_5ba7c0f5ed24.webp'),
(17, 52, 'Sajta de pollos', 'Sajta de pollo cruce', 'dish', 10.00, '3', 'uploads/location-items/article_20251106_142341_2a5360530dee.webp'),
(18, 93, 'Anticucho', 'Corazón de res flambeado, tubérculos, salsa de maní\r\ny salsa de siete tipos de ajíes', 'dish', 35.00, '4', NULL),
