INSERT INTO `subcategories` (`id`, `category_id`, `name`, `description`, `image_url`, `created_at`, `updated_at`) VALUES
(1, 2, 'Los Andes bolivianos', 'En el vasto altiplano boliviano, el horizonte parece no tener fin, a más de 3.600 metros sobre el nivel del mar, la vida se teje entre montañas, lagunas y salares que reflejan la fuerza y la serenidad de los andes.', 'https://upload.wikimedia.org/wikipedia/commons/thumb/1/12/Llamas%2C_Laguna_Milluni_y_Nevado_Huayna_Potos%C3%AD_%28La_Paz_-_Bolivia%29.jpg/960px-Llamas%2C_Laguna_Milluni_y_Nevado_Huayna_Potos%C3%AD_%28La_Paz_-_Bolivia%29.jpg', '2025-10-14 22:07:07', '2025-10-14 19:19:13'),
(2, 2, 'Entre Valles y Yungas', 'Una región que demuestra que la diversidad no separa, sino que une. Es el punto de encuentro entre la altura y la humedad, entre lo templado y lo tropical.', 'https://boliviamia.net/Images/Attractionphotos/yungas-01.jpg', '2025-10-14 22:08:29', '2025-10-14 19:20:06'),
(53, 2, 'Oriente y la Amazonía', 'Los llanos son el pulmón del país, un espacio donde la aventura y la serenidad coexisten.', 'https://preview.redd.it/confluencia-de-los-r%C3%ADos-ichilo-y-chimor%C3%A9-para-formar-el-r%C3%ADo-v0-o8tf4m8syw4f1.jpeg?width=640&crop=smart&auto=webp&s=9511383381c735b7ef295c9c44dd589389dcd9c3', '2025-10-14 23:54:42', '2025-10-15 23:51:20'),
(54, 3, 'Chocolate y café boliviano ', 'El Cacao y el café boliviano son tesoros que llenan de aroma y sabor cada momentoreflejando nuestra tierra, nuestra cultura y nuestra identidad.', 'https://azafranbolivia.com/wp-content/uploads/2021/12/cacao-chocolate-bolivia-produccion-exportacion-1-1024x683.jpg', '2025-10-15 00:27:12', '2025-10-15 00:45:24'),
(56, 3, 'Quinua Real', 'Descubre el grano madre de los Andes bolivianos, un sabor que encierra vida y abundancia.', 'https://cdn.bolivia.com/sdi/2022/07/07/bolivia-supremacia-mundial-produccion-quinua-real-organica-1046143.jpg', '2025-10-16 00:14:51', '2025-10-16 00:14:51'),
(57, 3, 'Vinos y Singani de Altura', 'Saborea la altura con vinos provenientes de los viñedos más altos del mundo, cultivados entre 1.800 y 2.200 metros sobre el nivel del mar. ', 'https://sendaandina.com/wp-content/uploads/2025/01/tarija-03.webp', '2025-10-16 00:16:02', '2025-10-16 00:16:02'),
(58, 3, 'Cereales y Legumbres, el alma nutritiva de Bolivia', 'Descubre cómo cada grano y semilla transforma los platos bolivianos en un festín de sabor', 'https://elpotosi.net/img/contents/images_640/2022/09/30/bcd45ba2-5445-4ad8-b111-e75ffb10b323.jpg', '2025-10-16 00:17:27', '2025-10-16 00:17:27'),
(60, 3, 'Ajíes, la esencia picante de Bolivia', 'Déjate seducir por el sabor del ají, desde los más suaves y aromáticos hasta los intensamente picantes que harán todos sentidos.', 'https://assets.isu.pub/document-structure/221209050228-4ee5d43c8a5c653bf10cb987c9c2f5db/v1/07a007151f15d5162645a68c262b4b52.jpeg', '2025-10-16 00:18:54', '2025-10-16 00:18:54'),
(61, 3, 'Charque, herencia del sol ', 'Sabor que llega directamente desde los Andes a tu paladar: carne deshidratada al sol, perfeccionada frente al clima extremo del altiplano.', 'https://static.bainet.es/clip/3455beec-b4cf-4e58-8b93-1530b90718ac_facebook-aspect-ratio_default_0.jpg', '2025-10-16 00:20:11', '2025-10-16 00:20:11'),
(62, 3, 'Bebidas Naturales', 'Déjate conquistar por el sabor auténtico de nuestras bebidas naturales, en donde Bolivia se saborea en cada vaso.', 'https://upload.wikimedia.org/wikipedia/commons/thumb/0/03/Mocochinchi_boliviano.jpg/1200px-Mocochinchi_boliviano.jpg', '2025-10-16 00:20:57', '2025-10-16 00:20:57'),
(63, 4, 'Carnaval de Oruro', 'Patrimonio Oral e Intangible de la Humanidad – UNESCO (2001)', 'https://www.noticiasfides.com/images/news/2025/02/u-la-diablada-en-el-carnaval-de-oruro-foto-marcelo-m_1739320777.jpg', '2025-10-16 01:35:58', '2025-10-16 01:35:58'),
(64, 4, 'Gran Fiesta de San Roque', 'Patrimonio Cultural Inmaterial de la Humanidad – UNESCO (2021)', 'https://media-cdn.tripadvisor.com/media/photo-p/08/eb/8d/5c/photo3jpg.jpg', '2025-10-16 01:38:19', '2025-10-16 01:38:19'),
(65, 4, 'Festividad del Señor Jesús del Gran Poder', 'Patrimonio Cultural Inmaterial de la Humanidad - UNESCO (2019)', 'https://abi.bo/images/Noticias/Deportes/ago-22/48274ebe-5e96-4bbf-8cd0-d67593b35d63.jpg', '2025-10-16 01:40:03', '2025-10-16 01:40:03'),
(66, 4, 'Ichapekene Piesta', 'Patrimonio Cultural Inmaterial de la Humanidad - UNESCO (2011) ', 'https://ich.unesco.org/img/photo/thumb/06082-BIG.jpg', '2025-10-16 01:43:07', '2025-10-16 01:43:07'),
(67, 1, 'Danzas', 'La danza boliviana, los movimientos que cuentan la historia de un pueblo', 'https://somostarija.wordpress.com/wp-content/uploads/2020/01/carnaval-1.png', '2025-10-17 19:49:56', '2025-10-17 19:49:56'),
(68, 1, 'Sitios culturales emblemáticos\r\n', 'Testimonios vivos de su historia y diversidad, donde cada piedra, muro y camino guarda la memoria de antiguas civilizaciones que dieron forma a su identidad ', 'https://www.laregion.bo/wp-content/uploads/2015/12/11351089_10152876728313263_1642714537_o-1024x573.jpg', '2025-10-17 19:52:32', '2025-10-17 21:54:40'),
(69, 1, 'Música', 'La música boliviana nace del encuentro de raíces indígenas, españolas y africanas, dando vida a una diversidad de géneros que resuenan con el espíritu único de cada región. ', 'https://sucre.bo/wp-content/uploads/2024/01/SICURIS.jpg', '2025-10-17 19:54:55', '2025-10-21 20:55:47'),
(70, 1, 'Culturas Vivas', 'Bolivia es hogar de culturas vivas llenas de diversidad y color. Cada pueblo tiene su propia lengua, vestimenta y tradiciones, desde los imponentes Andes hasta la exuberante Amazonía mostrando la riqueza de la identidad cultural boliviana. ', 'https://i.ytimg.com/vi/_Up45ZqwX2M/maxresdefault.jpg', '2025-10-17 19:56:36', '2025-10-22 13:54:21'),
(71, 1, 'Textiles', 'La diversidad textil de Bolivia florece en la fusión de técnicas artesanales, en la suavidad de fibras naturales y en la riqueza de diseños que tejen la esencia misma de su identidad cultural.', 'https://www.shutterstock.com/image-photo/andes-textile-fabric-pile-on-600nw-2020842641.jpg', '2025-10-17 19:58:33', '2025-10-18 00:13:16'),
(72, 1, 'Artesanía', 'Cada pieza hecha a mano refleja la creatividad, la historia y la identidad de nuestros pueblos en donde las manos bolivianas dan vida a un arte manual   que refleja nuestra riqueza cultural. ', 'https://previews.123rf.com/images/jjspring/jjspring1411/jjspring141100074/34710751-souvenirs-made-from-salt-at-the-market-in-salar-de-uyuni-bolivia-south-america.jpg', '2025-10-17 19:59:50', '2025-10-17 19:59:50');
